-- Poems batch 328
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('b2b3fe38-97dc-4aa0-9b1a-b416b7c40a41','因來詩有題橋之句呈陸農師  其一','孔平仲','宋','宋诗','song-poetry','','[]','土壅沙培種海棠，木陰池徑要深藏。',64,'全唐诗/poet.song.53000.json','["土壅沙培種海棠，木陰池徑要深藏。", "臧文竊位人多笑，犬子題橋君未忘。", "心嗜黄柑聊小擘，手拈紅葉又成章。", "早鶑歸燕催時節，即泛金英醉菊堂。"]'),
('bee978e5-dd8d-42a9-99d2-c80f6462cd94','因來詩有題橋之句呈陸農師  其二','孔平仲','宋','宋诗','song-poetry','','[]','口吐絲綸一代英，央央旌旆發神京。',64,'全唐诗/poet.song.53000.json','["口吐絲綸一代英，央央旌旆發神京。", "小堂且作蕃宣守，寸晷昔聞弦誦聲。", "耳白于顔君有譽，言藏之默我無營。", "呂溪傅野何須出，山野嫌人問姓名。"]'),
('3283b536-d0ea-452f-b93f-0f5c86893266','因來詩有題橋之句呈陸農師  其三','孔平仲','宋','宋诗','song-poetry','','[]','千里謳謠威惠全，王庭斬柳勢騰騫。',64,'全唐诗/poet.song.53000.json','["千里謳謠威惠全，王庭斬柳勢騰騫。", "馬遷汗簡才無輩，車胤螢囊學自然。", "火急定聞中禁召，口傳仍有貴璫宣。", "亙天弦管須頻會，日暖花開草更芊。"]'),
('fde2debd-1ab2-47f0-b074-53dfd903ab40','呈陸農師  其一','孔平仲','宋','宋诗','song-poetry','','[]','比玉文章素出羣，羊公仁政載前言。',64,'全唐诗/poet.song.53000.json','["比玉文章素出羣，羊公仁政載前言。", "口談典冊開聾瞽，目想烟霄役夢魂。", "鬼谷縱橫非世寶，貝多浮蠹逐時昏。", "日期儒術恢明主，王業光華燕後昆。"]'),
('f26cc241-71d8-4e3e-ad52-2355f9a25802','呈陸農師  其二','孔平仲','宋','宋诗','song-poetry','','[]','同飲東洲俱醉容，谷鶑應笑臥花叢。',64,'全唐诗/poet.song.53000.json','["同飲東洲俱醉容，谷鶑應笑臥花叢。", "取交莫逆情相答，合宴多歡酒屢空。", "工欲代天君素志，心將浮海我家風。", "蟲魚草木吟何苦，古錦囊封寄逸筒。"]'),
('57c11685-ad8b-456c-ad3d-a3b3a24a9bd6','呈陸農師  其三','孔平仲','宋','宋诗','song-poetry','','[]','丁公松腹夢多靈，巫峽聞猿莫涕零。',64,'全唐诗/poet.song.53000.json','["丁公松腹夢多靈，巫峽聞猿莫涕零。", "令德豈宜居茇舍，吉人終見作台星。", "生嫌鷹隼虛張翼，共喜芝蘭暗有馨。", "香菊一尊歌數疊，且須頻醉竹間亭。"]'),
('ecdd69dd-b23c-47ce-9b96-54b92729d52f','呈陸農師  其四','孔平仲','宋','宋诗','song-poetry','','[]','用舍隨時未是窮，躬耕何必返耕農。',64,'全唐诗/poet.song.53000.json','["用舍隨時未是窮，躬耕何必返耕農。", "辰惟去速須行樂，木爲非材尚見容。", "口誦雅言披墜簡，閒聞新語繼華宗。", "小棠幽鳥依蕃府，付與花洲作附庸。"]'),
('dbdcff0b-e9db-4965-bce8-7bd57142bf97','呈陸農師  其五','孔平仲','宋','宋诗','song-poetry','','[]','果下名駒踏路莎，沙堤雖小未相多。',64,'全唐诗/poet.song.53000.json','["果下名駒踏路莎，沙堤雖小未相多。", "夕天返照摇珠璧，玉宇微風蕩綺羅。", "維棹水邊舟不正，止車門外轂相摩。", "手搴露蕊真清旦，一樣新翻蜀錦窠。"]'),
('a1f885e8-e3c4-4314-93a0-1e81a2984ad8','寄何君表','孔平仲','宋','宋诗','song-poetry','','[]','龍章寶篆閟天宮，呂釣伊耕甫降嵩。',64,'全唐诗/poet.song.53000.json','["龍章寶篆閟天宮，呂釣伊耕甫降嵩。", "高義當爲神所勞，力行寧顧命之窮。", "躬親庶政賢方急，心志斯民髮未童。", "里俗莫輕尼父厄，已聞名字在紗籠。"]'),
('bbd0a59b-e30f-4d12-9acc-7f301a672984','寄方逢原','孔平仲','宋','宋诗','song-poetry','','[]','我行求友要漸磨，石確金堅所得多。',64,'全唐诗/poet.song.53000.json','["我行求友要漸磨，石確金堅所得多。", "夕倦未眠排奕勢，力窮猶戰敵詩魔。", "鬼神福善安無窘，君相知名直靡佗。", "匕箸借前陳策畫，一朝登用即巍峨。"]'),
('7684a43e-992e-4a07-ac3f-758c16f4aa51','寄張天覺','孔平仲','宋','宋诗','song-poetry','','[]','手弄毛錐擲釣蓑，衰年遠使尚婆娑。',64,'全唐诗/poet.song.53000.json','["手弄毛錐擲釣蓑，衰年遠使尚婆娑。", "女緣被妬多閨怨，心欲安禪學鳥窠。", "果有壯圖希劍履，復何高論隠松蘿。", "維摩弟子張天覺，見說平生事揣摩。"]'),
('d4db23fd-3bb3-4605-a777-834504130d3c','寄黄仲光','孔平仲','宋','宋诗','song-poetry','','[]','早識江西黄仲光，兀然相對鬢毛蒼。',64,'全唐诗/poet.song.53000.json','["早識江西黄仲光，兀然相對鬢毛蒼。", "口陳仁義何明白，日欲經綸孰抵當。", "田老謳吟知盛德，心交隔闊想餘芳。", "方今天子求才藝，云有鋒車降寵章。"]'),
('81f28e82-266c-4f41-8620-df682d86a5f0','寄向公美使君','孔平仲','宋','宋诗','song-poetry','','[]','田竇當時亦后家，豕貪羊狠事空花。',64,'全唐诗/poet.song.53000.json','["田竇當時亦后家，豕貪羊狠事空花。", "化行今日皆謙願，心吉夫君少等差。", "工作隸書無小草，早分恩賜只團茶。", "木盤宴饌皆心廣，黄雀親來粟滿畬。"]'),
('e0ea9442-2fe6-46b2-ae33-b3bfd712dc9f','寄張江州','孔平仲','宋','宋诗','song-poetry','','[]','干盡公卿冷眼看，目懸霄漢望鴛鸞。',64,'全唐诗/poet.song.53000.json','["干盡公卿冷眼看，目懸霄漢望鴛鸞。", "鳥旟付治期當審，番玉求田計想完。", "元帥昔時幾跋扈，邑君何日得平安。", "女年已長榮親養，食祿翻思把釣竿。"]'),
('a3c61a44-d688-4a94-98e8-8051a9681fda','寄呂汝州','孔平仲','宋','宋诗','song-poetry','','[]','兀坐東齋讀老莊，壯夫今已厭雕章。',64,'全唐诗/poet.song.53000.json','["兀坐東齋讀老莊，壯夫今已厭雕章。", "早吞灝氣清無夢，夕倚薰爐暖有香。", "日射澄波縈暮島，山排紅葉照秋霜。", "相思時玩囊中墨，土室寒居幸借光。"]'),
('0b2007cb-c3f3-4afa-afea-8a02123a13b4','寄張解州','孔平仲','宋','宋诗','song-poetry','','[]','車輾輕雷會鄂君，口朱當在結慇懃。',64,'全唐诗/poet.song.53000.json','["車輾輕雷會鄂君，口朱當在結慇懃。", "心迷雲雨回歌扇，羽散鸞皇轉舞裙。", "巾墊香醪方取樂，木飄霜葉忽離群。", "羊毫寫字無魚寄，可問南歸有戍軍。"]'),
('e7dd4eec-04c4-4f6f-94ae-452cfafa38ed','寄王滑州','孔平仲','宋','宋诗','song-poetry','','[]','至意須同陳與雷，田家老瓦媿雲罍。',64,'全唐诗/poet.song.53000.json','["至意須同陳與雷，田家老瓦媿雲罍。", "缶非可擊參韶樂，木肯垂陰庇野苔。", "台輔雍容君有量，里閭寒賤我如灰。", "火龕對坐年華宴，安得西飛到滑臺。"]'),
('baff3361-6214-4459-a7af-5f05d833c616','寄賈宣州','孔平仲','宋','宋诗','song-poetry','','[]','高會當年喜得曹，日陪宴衎自忘勞。',64,'全唐诗/poet.song.53000.json','["高會當年喜得曹，日陪宴衎自忘勞。", "力回天地君應憊，心狹乾坤我尚豪。", "豕亥論書非素學，子孫干祿有東皋。", "十年求友相知寡，分付長松蔭短蒿。"]'),
('cef6118b-1683-46ba-864e-6ed4f0c077ee','詠高','孔平仲','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','先以下爲基，終當保不危。',264,'全唐诗/poet.song.53000.json','["先以下爲基，終當保不危。", "泰山雄地鎮，北斗正天維。", "敏手誇能賦，忠言願聽卑。", "百常登觀闕，九仞揭旌旗。", "木有遷鶑集，墉惟射隼宜。", "舉家何氏隠，雙下李愔搥。", "大比楊雄好，長同巽卦爲。", "巍然望堯帝，卓爾仰宣尼。", "羊肆猶陳義，皇墳或媲詞。", "變更驚岸谷，豐稔閱京坻。", "醉枕日三丈，詞場桂一枝。", "金城橫絕險，龍馬出權奇。", "已著名僧傳，仍先國手棋。", "張弓聊抑爾，封岱更增之。", "郢曲故難和，牙琴誰復知。", "楩柟凌遠壑，鴻鵠漾晴曦。", "漢祖興邦日，商宗享國時。", "設科求德劭，巡狩問年耆。", "容駟開門戶，摩霄展羽儀。", "形容上麟閣，勳閥照鰲碑。", "密勿雲臺議，揄揚崧嶽詩。", "巖巖具瞻峻，那復嘆隆墀。"]'),
('e5fa33dc-a04e-46e1-911a-9934f05e00f9','詠大','孔平仲','宋','宋诗','song-poetry','','[]','觀水宣尼志，歌風漢祖篇。',264,'全唐诗/poet.song.53000.json','["觀水宣尼志，歌風漢祖篇。", "鵬搏九萬里，椿壽八千年。", "老子能談道，唐堯亦法天。", "旅獒宜自戒，魏瓠不勝堅。", "西域瓜如斛，東山栗比拳。", "周蒿芟作柱，舜竹截爲船。", "魯語譏居蔡，邠詩詠獻豜。", "雷聲當擬聖，人跡謾疑仙。", "寶訓書傳百，真乘界說千。", "弓聞陽虎竊，鼎自郜城遷。", "馮異依喬木，劉公受一錢。", "小鮮無撓國，多稼最宜田。", "骨有專車異，珠求徑寸圓。", "癭垂驚罋盎，雹下駭杯棬。", "船泛銀山浪，琴操急雨弦。", "恐時心縵縵，臥處腹便便。", "公罷三名府，官防五在邊。", "從容隠朝市，指顧奠山川。", "已識古今體，且知天地全。", "介圭催入覲，夏屋示優賢。", "金印懸如斗，神毫運若椽。", "安榮可長享，儒效照青編。"]'),
('f979d1e2-e0e5-432d-b8f9-1d1222184d34','新作西庵將及春景戲成兩詩請李思中節推同賦  其一','孔平仲','宋','宋诗','song-poetry','','[]','鄙性常山野，尤甘草舍中。',48,'全唐诗/poet.song.53000.json','["鄙性常山野，尤甘草舍中。", "鉤簾陰卷柏，障壁坐防風。", "客土依雲實，流泉架木通。", "行當歸老去，已逼白頭翁。"]'),
('cca62fd4-bcef-4166-ab61-422bd3116d40','新作西庵將及春景戲成兩詩請李思中節推同賦  其二','孔平仲','宋','宋诗','song-poetry','','[]','昨葉何摇落，今逢淑景天。',48,'全唐诗/poet.song.53000.json','["昨葉何摇落，今逢淑景天。", "山椒紅杏火，岩石綠苔烟。", "爐火沉香燼，琴絲續斷弦。", "忍冬已徹骨，衰白及長年。"]'),
('1e350e92-d669-4f5c-b054-85bd5d338a2a','再賦  其一','孔平仲','宋','宋诗','song-poetry','','[]','楚澤蘭紉佩，廉泉水洗心。',48,'全唐诗/poet.song.53000.json','["楚澤蘭紉佩，廉泉水洗心。", "荷鋤通草徑，戴笠鉤藤陰。", "欲蚤休陳事，須甘遂陸沈。", "謾呈詩藁本，李杜若知音。"]'),
('2202823c-28ff-4a0e-b128-4577de430f45','再賦  其二','孔平仲','宋','宋诗','song-poetry','','[]','鬰鬰金舒柳，青青黛染槐。',48,'全唐诗/poet.song.53000.json','["鬰鬰金舒柳，青青黛染槐。", "繁陰庭側柏，碎綠井中苔。", "雨漏蘆簷破，風薰草意回。", "陟釐題短句，自洗筆頭灰。"]'),
('f7a45996-274e-40b6-ba61-a76716fdb8f7','再賦  其一','孔平仲','宋','宋诗','song-poetry','','[]','凍地榆抽笋，寒山藥長苗。',48,'全唐诗/poet.song.53000.json','["凍地榆抽笋，寒山藥長苗。", "老翁鬚自白，積雪草方夭。", "折桂心安在，屠龍膽已消。", "花前胡不醉，排悶合歡謠。"]'),
('31db2e20-9f80-4d9f-8e3c-310e2fef9da4','再賦  其二','孔平仲','宋','宋诗','song-poetry','','[]','此地龍舒國，池隍戰血餘。',48,'全唐诗/poet.song.53000.json','["此地龍舒國，池隍戰血餘。", "木香多是橘，石乳最宜魚。", "古瓦松杉冷，旱天麻麥疏。", "題詩雲母紙，牋膩粉難書。"]'),
('558221e0-f0da-4c93-9d6a-77fa946a038b','再賦  其一','孔平仲','宋','宋诗','song-poetry','','[]','百草霜雪死，半天河漢斜。',48,'全唐诗/poet.song.53000.json','["百草霜雪死，半天河漢斜。", "竹含輕紫粉，梅發淡紅花。", "蘸甲香醪釅，搔頭垢髮華。", "北亭歡宴罷，燈燭夜明沙。"]'),
('00a7b540-c4ab-420f-91d2-8109b4386b49','再賦  其二','孔平仲','宋','宋诗','song-poetry','','[]','起自然銅鼎，烹茶滴乳香。',48,'全唐诗/poet.song.53000.json','["起自然銅鼎，烹茶滴乳香。", "深冬灰正冷，新臘雪須當。", "我意空青眼，君才貫衆長。", "唱酬幾百合，衰白荷相忘。"]'),
('e99b99b0-bdde-4ae0-86fc-9a337d9b99e1','送李思中服闋入京','孔平仲','宋','宋诗','song-poetry','','[]','久客烏頭白，家無石斛儲。',48,'全唐诗/poet.song.53000.json','["久客烏頭白，家無石斛儲。", "諳尋小草木，心合大空虛。", "已耐冬寒過，新知母服除。", "銅青即金紫，無患子窮居。"]'),
('9318db65-3f70-411a-a834-94da3b5ae748','酬惠詩','孔平仲','宋','宋诗','song-poetry','','[]','屢得真珠玉，天葩蘭麝香。',48,'全唐诗/poet.song.53000.json','["屢得真珠玉，天葩蘭麝香。", "書燈心最苦，坐石膽應凉。", "松桂枝柯老，蛟龍骨骼長。", "急追無及已，請附子餘光。"]'),
('083da7a2-cbda-424c-a93d-41e22ef65a96','離合轉韵寄常父','孔平仲','宋','宋诗','song-poetry','','[]','舒州寄官舍，舍在潜峰下。',72,'全唐诗/poet.song.53000.json','["舒州寄官舍，舍在潜峰下。", "密邇豫章城，山川無十程。", "音書常絡繹，日日通消息。", "况復多唱酬，兄塤弟竽笛。", "秋風鳴竹林，火退避新金。", "悵望南來雁，長年空此心。"]'),
('74e01f1c-a177-41ad-80e6-53e60a0bb4e0','又一首寄孫虢州','孔平仲','宋','宋诗','song-poetry','','[]','鱖鯇飲石乳，魚中最溫補。',72,'全唐诗/poet.song.53000.json','["鱖鯇飲石乳，魚中最溫補。", "字畫尚茫然，何由食鮮□。", "漆林自小足，水繞庵前竹。", "君性本清高，伊人又閒熟。", "三堂秋際餘，一枕夢回初。", "斤斧却無事，新詩或起予。"]'),
('3f1fb115-31fb-4962-9e5a-8a28fb329c70','藥名離合四時四首  其一','孔平仲','宋','宋诗','song-poetry','','[]','草滿南園綠，青青復間紅。',24,'全唐诗/poet.song.53000.json','["草滿南園綠，青青復間紅。", "花開不擇地，錦繡徑相通。"]'),
('dd8912f0-2123-44c1-8418-3bf557ab736a','藥名離合四時四首  其二','孔平仲','宋','宋诗','song-poetry','','[]','漿寒飲一石，蜜液和巖桂。',24,'全唐诗/poet.song.53000.json','["漿寒飲一石，蜜液和巖桂。", "心渴望天南，星河燦垂地。"]'),
('df047a5d-7e55-4830-9ac3-72d8f94e0d88','藥名離合四時四首  其三','孔平仲','宋','宋诗','song-poetry','','[]','參旗挂疏木，通夕凉如水。',24,'全唐诗/poet.song.53000.json','["參旗挂疏木，通夕凉如水。", "銀漢耿半天，河橋暝烟紫。"]'),
('a1e5ffd2-2f2c-4388-ae27-4e955f62428e','藥名離合四時四首  其四','孔平仲','宋','宋诗','song-poetry','','[]','雪片擁頹垣，衣裘冷於甲。',24,'全唐诗/poet.song.53000.json','["雪片擁頹垣，衣裘冷於甲。", "香醪不滿榼，藤枕欹殘臘。"]'),
('7e685441-199b-462a-8f45-b0c670649781','藥名離合寄孫虢州  其一','孔平仲','宋','宋诗','song-poetry','','[]','孫八遠在虢，丹霞絢崔蒼。',48,'全唐诗/poet.song.53000.json','["孫八遠在虢，丹霞絢崔蒼。", "耳目雖清遠，志願多參商。", "陸沉衆人中，白首滯鉛黄。", "耆英紹前烈，當復佐興王。"]'),
('e8c9a309-ed2f-438d-afb9-40aac09bfd6c','藥名離合寄孫虢州  其二','孔平仲','宋','宋诗','song-poetry','','[]','朴也纔通貫，衆安無吠狗。',48,'全唐诗/poet.song.53000.json','["朴也纔通貫，衆安無吠狗。", "杞菊飯家常，山泉消晝漏。", "蘆雁來蔽空，青眼思朋舊。", "歷日驚晚景，天涯情更厚。"]'),
('62a0b364-17ee-4a15-b95c-58bd49db9ae0','十三日南湖之集賓主六人謹成詩十韵拜呈','孔平仲','宋','宋诗','song-poetry','','[]','律管秋灰動，銖衣暑服輕。',120,'全唐诗/poet.song.53000.json','["律管秋灰動，銖衣暑服輕。", "居官半舜牧，環坐列周卿。", "攬轡湖邊集，談經席上傾。", "逸交希李白，奇策擬陳平。", "博奕休言戲，韜鈐且議兵。", "續箋詩義白，重演卦爻成。", "午日停龍馭，西風駐鷁程。", "弓鈞寒力壯，天暮霽華明。", "綠野接鄉遂，良辰推甲庚。", "浴沂人已散，終日夢魂清。"]'),
('c77b081f-237f-4cca-818b-550d1bd96d5d','再吟六詩四首拜呈  其一','孔平仲','宋','宋诗','song-poetry','','[]','摩天皆勁翮，對壘盡雄詩。',120,'全唐诗/poet.song.53000.json','["摩天皆勁翮，對壘盡雄詩。", "漢士增三傑，唐儒益二夔。", "素修同德行，良會展尊彝。", "恥佩蘇秦印，閒吟谷永詩。", "郡條頒美政，邦典守新規。", "暗換陰陽氣，平分晝夜時。", "南朝餘草樹，戰國舊城池。", "弱跪霜前蟹，奇眸水底龜。", "風標觀畫鶴，禍福中靈棋。", "尼父談諸蔽，尤當謹禮儀。"]'),
('9330226a-3547-443f-a253-316c7d793f00','再吟六詩四首拜呈  其二','孔平仲','宋','宋诗','song-poetry','','[]','累日欲修禮，今茲清飲陪。',120,'全唐诗/poet.song.53000.json','["累日欲修禮，今茲清飲陪。", "位分乾卦畫，人比晉卿才。", "宗廟精禋近，侯邦舞羽來。", "光華連七璧，符采綴三台。", "儀鳳須論德，良弓自有材。", "雄鋩皆帝劍，直節倍公槐。", "吏計無先善，人情且去哀。", "箴思丹扆補，彩喜碧油回。", "穆若親朋會，欣然肺腑開。", "馳蛟參駿軌，朽馭愧駑駘。"]'),
('d33aa296-0f4d-442a-8556-890847d83136','再吟六詩四首拜呈  其三','孔平仲','宋','宋诗','song-poetry','','[]','侯服安無事，官曹靜不譁。',120,'全唐诗/poet.song.53000.json','["侯服安無事，官曹靜不譁。", "疇非信善友，俱是孝廉家。", "荀衮傳榮耀，溫龍競爪牙。", "尺輿思附鳳，角扇笑縈蛇。", "士習賢科論，人趨太守衙。", "莊衢當自騁，陳藥更誰誇。", "和露餐荷葉，臨流飲雪花。", "草萊依瑞穗，荆布綴明珈。", "且固官庭守，寧憂柄用賒。", "它時摇玉佩，鰲禁定聯華。"]'),
('9e0ab65d-6f93-4b59-b90b-f0ee6b0f8f7e','再吟六詩四首拜呈  其四','孔平仲','宋','宋诗','song-poetry','','[]','龍笛霜號竅，熊旗露綴斿。',120,'全唐诗/poet.song.53000.json','["龍笛霜號竅，熊旗露綴斿。", "追歡品加豆，偷暇日要囚。", "周冕英才集，商瑚瑞氣浮。", "金弢書屢講，蓬矢志須酬。", "草樹雙仙島，風烟半玉樓。", "畫圖觀隰駁，果實採沅榴。", "通貴人無恙，承平府孔修。", "官非劍外久，課比茂陵優。", "時變休成論，皇明已照幽。", "責躬無復事，嘉穀謁高秋。"]'),
('d008973a-f52d-4a07-9a46-9965eddaa846','十畫農謠一首','孔平仲','宋','宋诗','song-poetry','','[]','春雨津浹洽，秋苗香苾芬。',24,'全唐诗/poet.song.53000.json','["春雨津浹洽，秋苗香苾芬。", "京坻看便是，完固促修囷。"]'),
('ab26ad0b-d016-4243-8e32-300b6ecb33ef','惜別一首呈陸亨儒十畫','孔平仲','宋','宋诗','song-poetry','','[]','恬和效春律，芳茂若秋松。',24,'全唐诗/poet.song.53000.json','["恬和效春律，芳茂若秋松。", "盃畢花枝放，吳伻俳笑空。"]'),
('93b524e9-c6e4-43e1-8db6-8f788d0a28eb','九畫一首','孔平仲','宋','宋诗','song-poetry','','[]','坦直吾所知，良彥君長者。',36,'全唐诗/poet.song.53000.json','["坦直吾所知，良彥君長者。", "村邦柱材美，丞府依炉冶。", "弗忘念夙昔，吟奕同茇舍。"]'),
('6b6d999a-9552-486a-92ec-0b05ea6b35c8','八畫一首','孔平仲','宋','宋诗','song-poetry','','[]','牧守有民社，佳言多告余。',24,'全唐诗/poet.song.53000.json','["牧守有民社，佳言多告余。", "金芝先出谷，奔召戒征車。"]'),
('f9eb407f-1e67-4675-9dfd-5f81b10a226f','七畫一首','孔平仲','宋','宋诗','song-poetry','','[]','予兮仲尼后，老作外州行。',24,'全唐诗/poet.song.53000.json','["予兮仲尼后，老作外州行。", "丹穴屯戎伍，朱衣走吏兵。"]'),
('aa373312-f994-4635-9346-45a6ea5b59fb','十畫四言','孔平仲','宋','宋诗','song-poetry','','[]','亨倅沉俗，泥虬臥虹。',40,'全唐诗/poet.song.53000.json','["亨倅沉俗，泥虬臥虹。", "星君促面，省座班封。", "修治克茂，果有昌宗。", "恥於便倖，宜效孤忠。"]'),
('1ab7a84f-f402-4d96-b08d-ca077aea72e1','寄孫元忠  其一','孔平仲','宋','宋诗','song-poetry','','["\u8861\u5c71"]','君不見瀟湘之山衡山高，八月秋高風怒號。',69,'全唐诗/poet.song.53000.json','["君不見瀟湘之山衡山高，八月秋高風怒號。", "草木黄落龍正蟄，哀鴻獨叫求其曹。", "男兒生無所成頭皓白，漂零已是滄浪客。", "呼兒覓紙一題詩，此心炯炯君應識。"]'),
('bb92be64-6239-4486-b636-ae798f617960','寄孫元忠  其二','孔平仲','宋','宋诗','song-poetry','','[]','抱病江天白首郎，秋風此日曬衣裳。',64,'全唐诗/poet.song.53000.json','["抱病江天白首郎，秋風此日曬衣裳。", "看我形容已枯槁，此豈有意仍騰驤。", "一官羈絆實藏身，富貴於我如浮雲。", "致君堯舜付公等，幾時高義排金門。"]'),
('b0076e9e-1ea5-4593-a5be-d2941488f8cb','寄孫元忠  其三','孔平仲','宋','宋诗','song-poetry','','[]','嗚呼古人已糞土，紛紛輕薄何須數。',64,'全唐诗/poet.song.53000.json','["嗚呼古人已糞土，紛紛輕薄何須數。", "當面輸心背面笑，翻手作雲覆手雨。", "感君意氣無所惜，於我見子真顔色。", "人生會合不可常，昔者相遇今不得。"]'),
('0a66daf7-d819-4189-be02-b36a776f74e0','寄孫元忠  其四','孔平仲','宋','宋诗','song-poetry','','[]','不恨我衰子貴時，經濟實藉英雄姿。',64,'全唐诗/poet.song.53000.json','["不恨我衰子貴時，經濟實藉英雄姿。", "君有長材不貧賤，莫令斬斷青雲梯。", "驊騮作駒已汗血，坐看千里當霜蹄。", "省郎京尹必俯拾，軍符侯印取豈遲。"]'),
('3fc0a6cf-ac66-4463-810f-b10520fc33f8','寄孫元忠  其五','孔平仲','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','歲云暮矣多北風，瀟湘洞庭虛映空。',64,'全唐诗/poet.song.53000.json','["歲云暮矣多北風，瀟湘洞庭虛映空。", "中有雲氣隨飛龍，黄鵠高于五尺童。", "殊方日落玄猿哭，蕪沒瀟岸千株菊。", "少壯幾時奈老何，喧呼且覆杯中淥。"]'),
('ff20338a-3a5d-4985-89d5-acb96511066f','寄孫元忠  其六','孔平仲','宋','宋诗','song-poetry','','[]','老去悲秋强自寬，衰顔欲付紫金丹。',64,'全唐诗/poet.song.53000.json','["老去悲秋强自寬，衰顔欲付紫金丹。", "坐臥只多少行立，豈可久在王侯間。", "與君相逢未恨晚，他日更僕語不淺。", "瀟湘水國傍黿鼉，吏情更覺滄洲遠。"]'),
('f7e22871-9340-4408-8c74-1bacd3b4982f','寄孫元忠  其七','孔平仲','宋','宋诗','song-poetry','','[]','雄姿逸態何崷崒，自是君身有仙骨。',64,'全唐诗/poet.song.53000.json','["雄姿逸態何崷崒，自是君身有仙骨。", "彩服日向庭幃趨，百年未見歡娛畢。", "拖玉腰金致主身，起居八座太夫人。", "爾家最近魁三象，文采風流今尚存。"]'),
('881cab6e-dad0-4778-8769-1059083b5772','寄孫元忠  其八','孔平仲','宋','宋诗','song-poetry','','[]','思君須向古人求，夙昔一逢無此流。',64,'全唐诗/poet.song.53000.json','["思君須向古人求，夙昔一逢無此流。", "文章有神交有道，名位豈肯卑微休。", "倜儻權奇難具論，鷙鳥舉翮連青雲。", "無路從容陪笑語，使人歎恨傷精魂。"]'),
('33b00304-80d7-488a-a1b2-e531c1542879','寄孫元忠  其九','孔平仲','宋','宋诗','song-poetry','','[]','故人情誼晚難似，神傾意豁真佳士。',64,'全唐诗/poet.song.53000.json','["故人情誼晚難似，神傾意豁真佳士。", "可憐懷抱向人盡，再爲後會知何地。", "老大徒傷未拂衣，白頭吟望苦低垂。", "魚龍寂寞秋江冷，不見湘妃鼓瑟時。"]'),
('026c71e5-afb2-4f7a-b7c4-56ecf93e3c7c','寄孫元忠  其一○','孔平仲','宋','宋诗','song-poetry','','[]','獨立縹緲之飛樓，更有澄江銷客愁。',64,'全唐诗/poet.song.53000.json','["獨立縹緲之飛樓，更有澄江銷客愁。", "無邊落木蕭蕭下，萬里風烟接素秋。", "天青小城搗練急，漁翁暝踏孤舟立。", "嫩蕊濃花滿目斑，臨風三嗅馨香泣。"]'),
('1dad9a07-3779-4a8a-858a-e2cdb540cef7','寄孫元忠  其一一','孔平仲','宋','宋诗','song-poetry','','[]','玉几由來天北極，雲近蓬萊常五色。',64,'全唐诗/poet.song.53000.json','["玉几由來天北極，雲近蓬萊常五色。", "五更三點入鵷行，朝回君是同舍客。", "豈意出守江城居，此身已媿須人扶。", "青眼高歌望吾子，早據要路豈捐軀。"]'),
('65689009-3d19-46eb-91b2-9ba614637a61','寄孫元忠  其一二','孔平仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','秋風欻吸吹南國，天地黤慘忽異色。',64,'全唐诗/poet.song.53000.json','["秋風欻吸吹南國，天地黤慘忽異色。", "江石决裂青楓摧，波漂菰米沉雲黑。", "儒術於我何有哉，口雖吟咏心中哀。", "隠居欲就廬山遠，黄帽青鞋歸去來。"]'),
('64a71025-b375-4792-a466-13813e1c4c0d','寄孫元忠  其一三','孔平仲','宋','宋诗','song-poetry','','[]','秋水浮階溜决渠，啼猿僻在楚山隅。',66,'全唐诗/poet.song.53000.json','["秋水浮階溜决渠，啼猿僻在楚山隅。", "白沙翠竹江村暮，斗酒新詩終日疏。", "男兒生不成名身已老，但話夙昔傷懷抱。", "客至從嗔不出迎，逢迎少壯非吾道。"]'),
('5f47d0e1-4bc5-4914-9f41-05f0c1810878','寄孫元忠  其一四','孔平仲','宋','宋诗','song-poetry','','[]','自斷此生休問天，焉能終日心拳拳。',64,'全唐诗/poet.song.53000.json','["自斷此生休問天，焉能終日心拳拳。", "人生幾何春已夏，况我與子非壯年。", "東流江水西飛燕，可惜刻漏隨更箭。", "細推物理須行樂，只願無事長相見。"]'),
('86ea0527-c5c6-456a-a1c9-9309d74e3ae1','寄孫元忠  其一五','孔平仲','宋','宋诗','song-poetry','','[]','小臣魯鈍無所能，况乃疏頑臨事拙。',64,'全唐诗/poet.song.53000.json','["小臣魯鈍無所能，况乃疏頑臨事拙。", "今幸樂國養微軀，主恩前後三持節。", "未有涓埃答聖朝，却教江漢客魂銷。", "雲白山青千萬里，便應黄髮老漁樵。"]'),
('8d9f6a48-3c12-4f67-9a3b-fface7689ca6','寄孫元忠  其一六','孔平仲','宋','宋诗','song-poetry','','[]','秋風蕭蕭露泥泥，美人娟娟隔秋水。',64,'全唐诗/poet.song.53000.json','["秋風蕭蕭露泥泥，美人娟娟隔秋水。", "揚眉結義黄金臺，欲向何門趿朱履。", "案頭乾死讀書螢，遮莫鄰雞下五更。", "老夫臥穩朝慵起，肯信吾兼吏隠名。"]'),
('01947bf3-ac0b-47cc-8b79-1ccd9cedbf09','寄孫元忠  其一七','孔平仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','注目寒江倚山閣，碧瓦朱甍照城郭。',64,'全唐诗/poet.song.53000.json','["注目寒江倚山閣，碧瓦朱甍照城郭。", "雲物不殊鄉國異，形勝有餘風土惡。", "階面青苔老更生，况乃秋後轉多蠅。", "巫山不見廬山遠，悵望秋天虛翠屏。"]'),
('532d1581-72b5-488c-b3ae-75d8f77acdad','寄孫元忠  其一八','孔平仲','宋','宋诗','song-poetry','','[]','隠几蕭條戴鶡冠，强移栖息一枝安。',64,'全唐诗/poet.song.53000.json','["隠几蕭條戴鶡冠，强移栖息一枝安。", "重陽獨酌盃中酒，醉把茱萸子細看。", "羞見黄花無數新，當令美味入吾唇。", "久拚野鶴如霜鬢，何用浮名絆此身。"]'),
('1c8683c9-e875-4631-9e4b-c2425594a5ad','寄孫元忠  其一九','孔平仲','宋','宋诗','song-poetry','','[]','高棟層軒已自凉，青楓葉赤天雨霜。',64,'全唐诗/poet.song.53000.json','["高棟層軒已自凉，青楓葉赤天雨霜。", "自公多暇迎參伍，行酒賦詩殊未央。", "共指西日不相貸，萬事盡付形骸外。", "自笑狂夫老更狂，詩酒尚堪驅使在。"]'),
('c54b5f36-2a3d-446b-a38d-2590b077e589','寄孫元忠  其二○','孔平仲','宋','宋诗','song-poetry','','[]','摇落深知宋玉悲，東流之外西日微。',64,'全唐诗/poet.song.53000.json','["摇落深知宋玉悲，東流之外西日微。", "寒衣處處催刀尺，誰家搗練風凄凄。", "籬邊老却陶潜菊，前飛禿鶖後鴻鵠。", "安得送我置汝旁，悵望聊歌紫芝曲。"]'),
('8d06c957-8e8a-4176-bcd6-480748b57d76','寄孫元忠  其二一','孔平仲','宋','宋诗','song-poetry','','[]','秋風淅淅吹我衣，日日江樓坐翠微。',64,'全唐诗/poet.song.53000.json','["秋風淅淅吹我衣，日日江樓坐翠微。", "江光隠見黿鼉窟，水鳥啣魚來去飛。", "菱葉荷花凈如拭，清簟疏簾看奕棋。", "雷聲忽送千峰雨，波濤萬頃堆琉璃。"]'),
('fa32aa60-bcff-43af-a497-f740a1b16125','寄孫元忠  其二二','孔平仲','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','草閣柴扉星散居，遠開山岳散江湖。',64,'全唐诗/poet.song.53000.json','["草閣柴扉星散居，遠開山岳散江湖。", "蒼苔濁酒林中靜，丹橘黄柑此地無。", "洞庭揚波江漢回，願吹野水添金杯。", "巢燕養雛渾去盡，鄰雞還過短牆來。"]'),
('376328f4-65b6-4b20-9d90-60496549b482','寄孫元忠  其二三','孔平仲','宋','宋诗','song-poetry','','[]','秋來相顧尚飄蓬，兼泛滄浪學釣翁。',64,'全唐诗/poet.song.53000.json','["秋來相顧尚飄蓬，兼泛滄浪學釣翁。", "鐘鼎山林各天性，知君才是濟川功。", "萬里寒空只一日，會是排風有毛質。", "攀龍附鳳勢莫當，莫度清秋吟蟋蟀。"]'),
('b34290cf-d54c-42fc-82dc-3d0e9f5921ce','寄孫元忠  其二四','孔平仲','宋','宋诗','song-poetry','','[]','諸公衮衮登臺省，後來况接才華盛。',64,'全唐诗/poet.song.53000.json','["諸公衮衮登臺省，後來况接才華盛。", "天涯風俗自相親，歲暮陰陽催短景。", "江風颯颯亂帆秋，天入滄浪一釣舟。", "愁極本憑詩遣興，朔雲寒菊倍離憂。"]'),
('1a6d68c5-c74c-40a5-bcc4-8c4b1983ae75','寄孫元忠  其二五','孔平仲','宋','宋诗','song-poetry','','[]','秋水才深四五尺，風燈照夜欲三更。',64,'全唐诗/poet.song.53000.json','["秋水才深四五尺，風燈照夜欲三更。", "千崖無人萬壑靜，新月猶懸雙杵鳴。", "衰顔動覓藜床坐，仰看明星當空大。", "請君一來開我愁，南浮早鼓蕭湘柂。"]'),
('faf4a911-4676-4e79-b4b1-456c0ca9675f','寄孫元忠  其二六','孔平仲','宋','宋诗','song-poetry','','[]','可憐爲人好心事，今我能書數字至。',64,'全唐诗/poet.song.53000.json','["可憐爲人好心事，今我能書數字至。", "人生會面難再得，安得如鳥有羽翅。", "日暮聊爲梁父吟，非子誰復見幽心。", "入懷本倚崑山玉，許身媿比雙南金。"]'),
('a71ba93a-6bb0-41f2-9441-ff846aeb38d2','寄孫元忠  其二七','孔平仲','宋','宋诗','song-poetry','','[]','腐儒衰晚謬通籍，齒牙欲落真可惜。',64,'全唐诗/poet.song.53000.json','["腐儒衰晚謬通籍，齒牙欲落真可惜。", "滄浪水深青冥闊，山鬼幽憂雪霜逼。", "老去新知見面稀，被褐短窄鬢如絲。", "秋天漠漠向昏黑，獨立蒼茫自詠詩。"]'),
('3209ea7c-642e-45e3-9f75-5280eaab2ab2','寄孫元忠  其二八','孔平仲','宋','宋诗','song-poetry','','[]','江上形容吾獨老，百壺且試開懷抱。',64,'全唐诗/poet.song.53000.json','["江上形容吾獨老，百壺且試開懷抱。", "妙舞逶迤夜未休，多情依舊能潦倒。", "雨裛紅蕖冉冉香，玉樽錦席高雲凉。", "酒酣耳熱忘頭白，老儒不用尚書郎。"]'),
('1ba3d42b-f813-4fab-a0d2-96838ce59b33','寄孫元忠  其二九','孔平仲','宋','宋诗','song-poetry','','[]','江上今朝寒雨歇，翛然欲下陰山雪。',64,'全唐诗/poet.song.53000.json','["江上今朝寒雨歇，翛然欲下陰山雪。", "山巔朱鳳聲嗷嗷，白鵠翅垂眼流血。", "老夫清晨梳白頭，杖藜徐步立芳洲。", "使我殘年但飽喫，微軀此外更何求。"]'),
('c9788420-f366-4ecf-b23b-8600ad91ddd0','寄孫元忠  其三○','孔平仲','宋','宋诗','song-poetry','','[]','神仙中人不易得，京中舊見君顔色。',64,'全唐诗/poet.song.53000.json','["神仙中人不易得，京中舊見君顔色。", "同心不減骨肉親，我居巷南子巷北。", "佳人屢出董嬌嬈，秋水爲神玉爲骨。", "孤城此日堪斷腸，既飽歡娛亦蕭瑟。"]'),
('83376149-d34b-41f4-997a-5dca09ec111a','寄孫元忠  其三一','孔平仲','宋','宋诗','song-poetry','','[]','封書寄與淚潺湲，童稚情親四十年。',64,'全唐诗/poet.song.53000.json','["封書寄與淚潺湲，童稚情親四十年。", "離別不堪無限意，斷腸分首各風烟。", "反鎖衡門守環堵，聞道三年未曾語。", "數篇今見古人詩，更覺良工心獨苦。"]'),
('cb5037e8-f566-4484-97c7-83c4174b7933','孫元忠寄示種竹詩戲以二十篇答  其一','孔平仲','宋','宋诗','song-poetry','','[]','青錢買野竹，持答翠琅玕。',48,'全唐诗/poet.song.53000.json','["青錢買野竹，持答翠琅玕。", "深栽小齋後，幽事頗相關。", "自有烟霞質，能令朱夏寒。", "引溜加灌溉，毋令雪霜殘。"]'),
('7a1a2153-a6d9-4696-9473-aac20a245b65','孫元忠寄示種竹詩戲以二十篇答  其二','孔平仲','宋','宋诗','song-poetry','','[]','冠蓋滿京華，藩籬带松菊。',48,'全唐诗/poet.song.53000.json','["冠蓋滿京華，藩籬带松菊。", "看君用幽意，必種數竿竹。", "嬋娟碧鮮靜，窈窕一林麓。", "排悶强裁詩，清文動哀玉。"]'),
('55da0528-d520-47a2-bd90-6c03a923fae8','孫元忠寄示種竹詩戲以二十篇答  其三','孔平仲','宋','宋诗','song-poetry','','[]','秋風楚竹冷，倚杖更徘徊。',48,'全唐诗/poet.song.53000.json','["秋風楚竹冷，倚杖更徘徊。", "想見陰山雪，朱炎安在哉。", "自今幽興熟，携手臥蒼苔。", "客居暫封殖，臘月更須栽。"]'),
('09e7d36b-f335-4b89-aa97-9dda17938f63','孫元忠寄示種竹詩戲以二十篇答  其四','孔平仲','宋','宋诗','song-poetry','','[]','賞靜連雲竹，移因風雨秋。',48,'全唐诗/poet.song.53000.json','["賞靜連雲竹，移因風雨秋。", "我圃日蒼翠，會心直罕儔。", "若人才思闊，文彩珊瑚鈎。", "新詩錦不如，札翰時相投。"]'),
('18f02ff0-d52c-4cba-b4eb-46bff894fb51','孫元忠寄示種竹詩戲以二十篇答  其五','孔平仲','宋','宋诗','song-poetry','','[]','幽偏得自怡，種竹交加翠。',48,'全唐诗/poet.song.53000.json','["幽偏得自怡，種竹交加翠。", "雨露之所濡，成長容何易。", "葉密鳴蟬稠，啅雀爭枝墜。", "客思回林坰，蕭疏外聲利。"]'),
('7c4d6feb-4c97-4041-b52a-8686ff3171c4','孫元忠寄示種竹詩戲以二十篇答  其六','孔平仲','宋','宋诗','song-poetry','','[]','解榻秋露懸，竹凉侵臥內。',48,'全唐诗/poet.song.53000.json','["解榻秋露懸，竹凉侵臥內。", "幽姿可時睹，密幹疊蒼翠。", "况乃回風吹，低昂各有意。", "長嘯一含情，洒落富清製。"]'),
('0f9c18cc-2aaf-4b78-a9fd-b3f57769ce33','孫元忠寄示種竹詩戲以二十篇答  其七','孔平仲','宋','宋诗','song-poetry','','[]','朱夏雲鬰陶，種此何草草。',48,'全唐诗/poet.song.53000.json','["朱夏雲鬰陶，種此何草草。", "兒童汲井華，頗亦恨枯槁。", "寒雨下霏霏，滿眼顔色好。", "臨眺獨躊躇，山林跡如掃。"]'),
('64694b46-ebd6-4ecc-8a58-5c96ae0257d4','孫元忠寄示種竹詩戲以二十篇答  其八','孔平仲','宋','宋诗','song-poetry','','[]','古牆猶竹色，真作野人居。',48,'全唐诗/poet.song.53000.json','["古牆猶竹色，真作野人居。", "青雲羞葉密，空翠撲肌膚。", "寒日外慘淡，泠泠風有餘。", "高齋坐林杪，興遠一蕭疏。"]'),
('483ff140-739b-4115-b04c-17d88be016c6','孫元忠寄示種竹詩戲以二十篇答  其九','孔平仲','宋','宋诗','song-poetry','','[]','竹光團野草，秀氣豁煩襟。',48,'全唐诗/poet.song.53000.json','["竹光團野草，秀氣豁煩襟。", "贈此遣愁寂，蕭然靜客心。", "枕簟入林僻，鳥雀聚枝深。", "興趣江湖迥，松筠起碧潯。"]'),
('990bed5f-70f5-407d-aef9-deb32bb81345','孫元忠寄示種竹詩戲以二十篇答  其一○','孔平仲','宋','宋诗','song-poetry','','[]','琳琅愈青熒，綠竹半含籜。',48,'全唐诗/poet.song.53000.json','["琳琅愈青熒，綠竹半含籜。", "霜露一沾凝，秋風動哀壑。", "才名四十年，晚就芸香閣。", "江上憶君時，風林纖月落。"]'),
('2ffd2e1d-36bb-4d4b-bf87-6d0683effed2','孫元忠寄示種竹詩戲以二十篇答  其一一','孔平仲','宋','宋诗','song-poetry','','[]','竹深留客處，僻近城南樓。',48,'全唐诗/poet.song.53000.json','["竹深留客處，僻近城南樓。", "眼邊無俗物，淅淅野風秋。", "主人不世才，老氣橫九州。", "哀弦繞白雲，清絕聽者愁。"]'),
('f1f408f1-28b3-4478-9d63-49f7390f45b4','孫元忠寄示種竹詩戲以二十篇答  其一二','孔平仲','宋','宋诗','song-poetry','','[]','入門高興發，而無人世喧。',48,'全唐诗/poet.song.53000.json','["入門高興發，而無人世喧。", "叢篁低地碧，疏林聽晚蟬。", "衰年旅炎方，只想竹林眠。", "安得騎鴻鵠，飛去墜爾前。"]'),
('3592a6ca-25c6-48f9-a6d8-16458db65709','孫元忠寄示種竹詩戲以二十篇答  其一三','孔平仲','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','苔竹吾所好，開軒納微凉。',48,'全唐诗/poet.song.53000.json','["苔竹吾所好，開軒納微凉。", "望中疑在野，景物洞庭旁。", "秋風亦已起，洒面若微霜。", "南客瀟湘外，與君永相望。"]'),
('f3b6d3e6-f0ae-4f86-bf32-dae8e479d59f','孫元忠寄示種竹詩戲以二十篇答  其一四','孔平仲','宋','宋诗','song-poetry','','[]','有竹一頃餘，舍下筍穿壁。',48,'全唐诗/poet.song.53000.json','["有竹一頃餘，舍下筍穿壁。", "新茁才出牆，滿歲如松碧。", "蒼蒼衆色晚，歸鳥盡斂翼。", "宇宙此生浮，仰慚林間翮。"]'),
('90bed3be-976e-46f3-a954-c5859520fdc0','孫元忠寄示種竹詩戲以二十篇答  其一五','孔平仲','宋','宋诗','song-poetry','','[]','竹皮含舊翠，鳥雀滿樛枝。',48,'全唐诗/poet.song.53000.json','["竹皮含舊翠，鳥雀滿樛枝。", "冰壺動摇碧，故作傍人低。", "細雨荷鋤立，秋風獨杖藜。", "老來性情靜，不是傲當時。"]'),
('eed371f4-586b-4061-b53c-2478c921a94b','孫元忠寄示種竹詩戲以二十篇答  其一六','孔平仲','宋','宋诗','song-poetry','','[]','執熱何曾有，亭午減汗流。',48,'全唐诗/poet.song.53000.json','["執熱何曾有，亭午減汗流。", "風飄連野色，客意已驚秋。", "應接非本性，閉關人事休。", "瀟洒送日月，茲焉心所求。"]'),
('dcfc1cbf-9bb8-4875-ba5c-a56b1555371c','孫元忠寄示種竹詩戲以二十篇答  其一七','孔平仲','宋','宋诗','song-poetry','','[]','寒城朝烟淡，竹日靜暉暉。',48,'全唐诗/poet.song.53000.json','["寒城朝烟淡，竹日靜暉暉。", "芊芊烟翠羽，羅列萧洒姿。", "清風左右至，秋色有餘凄。", "日暮歸幾翼，鷦鷯在一枝。"]'),
('beb381e0-f679-4c06-9248-f5b4b895a23e','孫元忠寄示種竹詩戲以二十篇答  其一八','孔平仲','宋','宋诗','song-poetry','','[]','欻翕炎蒸景，汗踰水漿翻。',48,'全唐诗/poet.song.53000.json','["欻翕炎蒸景，汗踰水漿翻。", "凄凄自生凉，風竹在華軒。", "蕭摵寒籜聚，比公頭上冠。", "獨在天一隅，可望不可攀。"]'),
('aa7da2ee-289c-4101-a125-6888559d5eea','孫元忠寄示種竹詩戲以二十篇答  其一九','孔平仲','宋','宋诗','song-poetry','','[]','密竹復冬笋，抽梢合過牆。',48,'全唐诗/poet.song.53000.json','["密竹復冬笋，抽梢合過牆。", "明涵客衣靜，陰過酒樽凉。", "初月出不高，茂林延疏光。", "欣然淡情素，丘壑道難忘。"]'),
('2223e0ba-8cc8-45d6-8a88-9812884bf560','孫元忠寄示種竹詩戲以二十篇答  其二○','孔平仲','宋','宋诗','song-poetry','','[]','碧色忽惆悵，霜埋翠竹根。',48,'全唐诗/poet.song.53000.json','["碧色忽惆悵，霜埋翠竹根。", "啾啾黄雀啅，宅舍如荒村。", "侍婢艷傾城，煥若靈芝繁。", "天寒翠袖薄，染淚在叢筠。"]'),
('35fbd1c2-8e86-404b-8a13-f39d27caefdf','兩頭纖纖  其一','孔平仲','宋','宋诗','song-poetry','','[]','兩頭纖纖新月眉，半白半黑對客棋。',32,'全唐诗/poet.song.53000.json','["兩頭纖纖新月眉，半白半黑對客棋。", "腷腷膊膊拊翼雞，磊磊落落飣坐梨。"]'),
('09d2b0c6-bf61-43e3-80f3-d31058e3d7ff','兩頭纖纖  其二','孔平仲','宋','宋诗','song-poetry','','[]','兩頭纖纖織婦梭，半白半黑雪沒靴。',32,'全唐诗/poet.song.53000.json','["兩頭纖纖織婦梭，半白半黑雪沒靴。", "腷腷膊膊鼓腹歌，磊磊落落金印多。"]'),
('2b9cf92d-3ccf-4825-a24a-96c9512aed0c','兩頭纖纖  其三','孔平仲','宋','宋诗','song-poetry','','[]','兩頭纖纖棗子核，半白半黑紙上墨。',32,'全唐诗/poet.song.53000.json','["兩頭纖纖棗子核，半白半黑紙上墨。", "腷腷膊膊手趁拍，磊磊落落山頭石。"]'),
('09c52e57-33d2-45c1-9508-702c89a2fb39','兩頭纖纖  其四','孔平仲','宋','宋诗','song-poetry','','[]','兩頭纖纖柳葉書，半白半黑鷺間烏。',32,'全唐诗/poet.song.53000.json','["兩頭纖纖柳葉書，半白半黑鷺間烏。", "腷腷膊膊失水魚，磊磊落落大丈夫。"]'),
('e81e3c5f-9890-44dc-860e-ba26c1fc7ac8','兩頭纖纖  其五','孔平仲','宋','宋诗','song-poetry','','[]','兩頭纖纖新採菱，半白半黑玉汙蠅。',32,'全唐诗/poet.song.53000.json','["兩頭纖纖新採菱，半白半黑玉汙蠅。", "腷腷膊膊馬踏冰，磊磊落落枝壓橙。"]'),
('3335c07a-3e9e-4183-998d-9faff2135a57','五雜組  其一','孔平仲','宋','宋诗','song-poetry','','[]','五雜組，垂衣裳。',24,'全唐诗/poet.song.53000.json','["五雜組，垂衣裳。", "往復來，就桀湯。", "不獲已，剪夏商。"]'),
('2e7b8ac1-eb37-4dd5-aaa0-3debe4af123a','五雜組  其二','孔平仲','宋','宋诗','song-poetry','','[]','五雜組，封社土。',24,'全唐诗/poet.song.53000.json','["五雜組，封社土。", "往復來，使遼虜。", "不獲已，拜陽虎。"]'),
('a14717c1-2fd7-4651-8b44-6f17c08ad94f','五雜組  其三','孔平仲','宋','宋诗','song-poetry','','[]','五雜組，慶雲聚。',24,'全唐诗/poet.song.53000.json','["五雜組，慶雲聚。", "往復來，東西渡。", "不獲已，再娶婦。"]'),
('449959a3-b248-4d46-9244-c63fdc5ce623','五雜組  其四','孔平仲','宋','宋诗','song-poetry','','[]','五雜組，花木春。',24,'全唐诗/poet.song.53000.json','["五雜組，花木春。", "往復來，江湖人。", "不獲已，議和親。"]'),
('e3dcb1cc-47a2-418c-9289-0f508520f8b3','五雜組  其五','孔平仲','宋','宋诗','song-poetry','','[]','五雜組，錦繡段。',24,'全唐诗/poet.song.53000.json','["五雜組，錦繡段。", "往復來，隨陽雁。", "不獲已，猶仕宦。"]'),
('2f917f8a-80bb-4112-a671-7bdb282fa8fb','五雜組  其六','孔平仲','宋','宋诗','song-poetry','','[]','五雜組，朝霞明。',24,'全唐诗/poet.song.53000.json','["五雜組，朝霞明。", "往復來，車馬行。", "不獲已，方用兵。"]'),
('5e9b9269-4c08-4f90-93d6-9506081a95ed','寄芸叟  其一','孔平仲','宋','宋诗','song-poetry','','[]','未老已前胡不歸，何須斑白及衰羸。',32,'全唐诗/poet.song.53000.json','["未老已前胡不歸，何須斑白及衰羸。", "婆娑石上弄明月，臥看春風生桂枝。"]'),
('3d0626f3-4003-4b7e-bba3-c56e8bf70485','寄芸叟  其二','孔平仲','宋','宋诗','song-poetry','','[]','愁雲垂地黄映日，疊嶂插空青照樓。',32,'全唐诗/poet.song.53000.json','["愁雲垂地黄映日，疊嶂插空青照樓。", "野菊花開秋又晚，便當歸去老滄洲。"]'),
('d9141d9f-8b28-4492-9e0a-3abfae2ef99b','寄芸叟  其三','孔平仲','宋','宋诗','song-poetry','','[]','年過半百合歸去，謹杜衡門深退藏。',32,'全唐诗/poet.song.53000.json','["年過半百合歸去，謹杜衡門深退藏。", "衰白前途有多少，使君子細更商量。"]'),
('f131e4e7-321c-44a8-82cd-645c69d62bc3','承芸叟寄示新詞一篇以此寄謝揚子云書亦有色乎此亦書之色也','孔平仲','宋','宋诗','song-poetry','','[]','綺羅敷色新出機，嵩洛神秀鍾妙詞。',128,'全唐诗/poet.song.53000.json','["綺羅敷色新出機，嵩洛神秀鍾妙詞。", "關西子弟多習武，博學能文君最奇。", "目中無雙成器早，少小玉立誰瑕疵。", "天王母后親選擢，抱道韞德將發施。", "朝中議論太真樸，湖南威鳳翅小垂。", "屈申后先皆有數，此理昭昭君自知。", "芰荷堆綠珠露冷，蘭杜秋香風正吹。", "征鴻南飛燕北去，晚去瀟湘君未歸。"]'),
('0423db7d-746b-4870-a5c2-db9fa80ea357','夜宴曲','孔平仲','宋','宋诗','song-poetry','','[]','湘江紺碧玉照秋，丹楓紅蓼君莫愁。',80,'全唐诗/poet.song.53000.json','["湘江紺碧玉照秋，丹楓紅蓼君莫愁。", "江上女兒花見羞，吾曹大家行樂休。", "促席相虞美人出，羽觴昨許飛瓊液。", "天明君醉苦相挽，肯念奴家隔江遠。", "流蘇小帳曲屈屏，留連爲子都忘返。"]'),
('db530ef6-a261-4597-a315-617ce846b334','七夕一首呈席上','孔平仲','宋','宋诗','song-poetry','','[]','琥珀杯濃酒味醇，鬰金裙轉舞腰新。',64,'全唐诗/poet.song.53000.json','["琥珀杯濃酒味醇，鬰金裙轉舞腰新。", "鉛華第一人中白，歌響幾多梁上塵。", "玉漏將沉香未斷，銀潢雖遠志相親。", "合歡促席留君醉，最苦參斜夜向晨。"]'),
('b8e74ef9-fe9f-4d54-a805-9dec49890a85','寄芸叟年兄','孔平仲','宋','宋诗','song-poetry','','[]','垂天雄翮摶海風，窮高極遠志不同。',320,'全唐诗/poet.song.53000.json','["垂天雄翮摶海風，窮高極遠志不同。", "盛年折桂心未歉，磨刀水際思平戎。", "西羌活擒偶失手，天南星墮郴山中。", "未甘遂葬江魚腹，當歸入覲明光宮。", "何嘗僕射干薦舉，芸臺烏府選擇公。", "蛟龍齒角老愈硬，楩楠材格寒更濃。", "恥爲葳蕤要節目，預知子不見從容。", "川峽揭節建大戟，服紫腰金薄賞功。", "暮年車轄徙荆楚，江離摇碧水蓼紅。", "橘洲橋口皆莽草，賈傅井中苔已空。", "我已衰白斂一郡，附子餘光聊養蒙。", "嘗言早休乃良策，倚空親想蓮花峰。", "請君先去采芝朮，我續隨子棲蒿蓬。", "水甘松香真勝境，雲滑石險多行蹤。", "半天河漢傾瀑布，自然銅吼聞霜鐘。", "董仙種杏人競取，淵明石床蒼蘚封。", "怡神麯糵有妙理，禾收石斛歲屢豐。", "林迥岩屋尤可徧，溪間小橋橫木通。", "手捫松蘿攀紫葛，清凉半夏如秋冬。", "黄精久餌助冰雪，與君同作白頭翁。"]'),
('ab1355f4-fc18-4480-b6fb-207e924f9f9f','郡名詩呈呂元鈞五首  其一','孔平仲','宋','宋诗','song-poetry','','[]','元鈞家成都，洪秀稟天質。',168,'全唐诗/poet.song.53000.json','["元鈞家成都，洪秀稟天質。", "紫微耀文采，青鎖聯近密。", "德全無所累，道在固不屈。", "暮年徙江湖，寓舍安蓬蓽。", "種花憐衛足，養烏愛均一。", "南軒幽興發，北牖高臥佚。", "福慶有諸郎，壽康踰七帙。", "循環視天理，一馬齊萬物。", "我進亦隨隨，衰白紆郡紱。", "屢聞曠達論，頓覺蒙陋失。", "秋風吹楚澤，黄葉弄蕭瑟。", "潭水凝練光，衡門刻霜骨。", "登樓足嘉景，分務饒暇日。", "且復相從游，新醅侑梨栗。"]'),
('2a8c7b11-d254-4fe5-b6b8-f7c526245982','郡名詩呈呂元鈞五首  其二','孔平仲','宋','宋诗','song-poetry','','[]','相人觀久遠，要且視資質。',168,'全唐诗/poet.song.53000.json','["相人觀久遠，要且視資質。", "酒酸本多甘，絹敗爲少密。", "公家渭川後，端亮氣不屈。", "播移雖裔土，寧妥如舊蓽。", "優游歸孔聖，坎壈笑趙壹。", "儻來等榮辱，所遇順勞佚。", "道閣接談賓，文房散書帙。", "當其泰定時，海宇更無物。", "耳目并已忘，何心蘄冕紱。", "忽聞韶曲奏，更覺巴音失。", "溫純比金玉，清越勝琴瑟。", "似追少陵步，真得建安骨。", "從今益淬厲，及此舒長日。", "唱酬安敢同，心欽但齋栗。"]'),
('40084288-33b7-4adf-85e9-d85754f2667b','郡名詩呈呂元鈞五首  其三','孔平仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','二帝本仁愛，三王首忠質。',168,'全唐诗/poet.song.53000.json','["二帝本仁愛，三王首忠質。", "頗知周德厚，不似秦網密。", "平生勇自信，戈戟未易屈。", "何嘗戀儋耳，但欲返衡蓽。", "詔條甚明白，宣布要齊一。", "御衆莫若寬，使民宜以佚。", "古人貴守義，昭晰在緗帙。", "公言屢見廣，我惠慚及物。", "河檀負廩梢，梁鵜議印紱。", "廬山須决去，雲臥未爲失。", "瓊章屢起予，鳳吹雜瑶瑟。", "芝蘭暗有香，嵩華清見骨。", "君開筆頭花，我耀牖中日。", "九牛登巨鰲，視我真蠻栗。"]'),
('824497fc-fdea-40f6-a2bf-0d6f60f50d9d','郡名詩呈呂元鈞五首  其四','孔平仲','宋','宋诗','song-poetry','','[]','南軒何靚深，觸處皆野質。',168,'全唐诗/poet.song.53000.json','["南軒何靚深，觸處皆野質。", "簷間畫眉語，砌下霜筠密。", "小窗任明晦，一榻隨伸屈。", "宿鳥聚樛枝，凉蟬噪𡴴蓽。", "端居得頤養，誠意更精一。", "夏闌體長健，春至轉安佚。", "鉛鼎熟黄牙，仙經橫縹帙。", "和言不忤俗，定力何轉物。", "嗟我已龍鍾，江潭戀章紱。", "塵中素袍化，鏡裏韶顔失。", "愛君詩思茂，雅奏合竽瑟。", "愛君道氣成，金石叢壽骨。", "及瓜期尚遠，發藥容有日。", "德爵齒俱尊，登門但祗栗。"]'),
('e545aa33-28a7-476d-a035-d26a360d874c','郡名詩呈呂元鈞五首  其五','孔平仲','宋','宋诗','song-poetry','','[]','呂公杞梓材，自是棟梁質。',168,'全唐诗/poet.song.53000.json','["呂公杞梓材，自是棟梁質。", "岷山岩谷邃，蜀錦機杼密。", "含章同豹隠，榮進異蠖屈。", "興起自艱微，敗席代門蓽。", "揚庭挺科兩，許國操心一。", "理財務廉約，持憲從寬佚。", "言動肅以舒，絲綸蔚成帙。", "瑣圍使遼土，政府論儀物。", "陳郡剖侯封，潞郊紓守紱。", "今棲重湖外，久矣齊得失。", "高吟貽華莞，靜鼓雲和瑟。", "知音曠寰宇，自養融心骨。", "冥鴻難遂去，塞馬有歸日。", "會見促召還，忻歡投棗栗。"]'),
('60ea3bcf-d7a0-47e1-92ba-5cb31416f347','偶作','孔平仲','宋','宋诗','song-poetry','','[]','日影秋漸薄，月華寒更清。',120,'全唐诗/poet.song.53000.json','["日影秋漸薄，月華寒更清。", "光生含江水，天色晚來晴。", "德微慚郡紱，山野拙將迎。", "河流彌淺峻，壯木亦凋零。", "帝子閟瑶瑟，居聞鶚鵬聲。", "太剛每忤俗，平進誰提衡。", "何爲尚錄錄，以此思歸耕。", "報使掃舊蓽，願言嘿餘齡。", "上樓想羌廬，一望烟冥冥。", "封壤邈千里，書之寄餘情。"]'),
('aaa009f0-0569-4dfb-8945-1d0a1928546b','芸叟寄新詞作八陣圖一首','孔平仲','宋','宋诗','song-poetry','','[]','功業不復議，蓋載無所容。',120,'全唐诗/poet.song.53000.json','["功業不復議，蓋載無所容。", "三湘逶迤水，分與清河公。", "國士大手筆，名聲蔚摩空。", "成材兼衆製，八面任見攻。", "陣馬勢遒勇，圖繪出纖穠。", "江神敷妙詞，流入韶濩中。", "石心鐵爲腸，不意於此工。", "轉調協擊拊，遺音扣玲瓏。", "恨我狂既和，失之太匆匆。", "吞咀知雋永，吳越安可同。"]'),
('d7806202-af8a-4f02-8222-d97c16fd3a98','二十八宿寄芸叟','孔平仲','宋','宋诗','song-poetry','','[]','張公角立孰敢先，亢宗自許英妙年。',224,'全唐诗/poet.song.53000.json','["張公角立孰敢先，亢宗自許英妙年。", "捕逐氐羌先著鞭，文房餘思如涌泉。", "題詩寫心蟠遠烟，黑蛟矯尾明秋淵。", "南箕吐舌風墮鳶，弱羽斗落郴江邊。", "蝸牛客舍弔影眠，寒女晚嫁私自憐。", "誰知虛實久粲然，安危之理如循環。", "歸來藏室閱青編，東壁步武追神仙。", "綉衣白簡猶奎躔，體健不復婁金丸。", "腸胃充實頰骨堅，昴宿老人飛上天。", "志願未畢西餽邊，野鸛礪觜不啄羶。", "曾參殺人知謬傳，賞花墜井皆妄言。", "載鬼一車疑已捐，人欲折柳送公船。", "去同衆星環紫垣，張公張公人最賢。", "丹鳳奮翼蔚高鶱，更調玉軫續薰弦。"]'),
('f2fa0d12-5de3-4d51-820f-691ec68df584','卦名寄芸叟','孔平仲','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','小豐猶可喜，况此大有年。',264,'全唐诗/poet.song.53000.json','["小豐猶可喜，况此大有年。", "流庸已歸妹，獄訟久蕭然。", "明聖臨六合，吁俞萃羣賢。", "乾坤協氣滿，井邑歡聲連。", "張公性謙靜，玉節鎮湘壖。", "茇舍富暇豫，鈴齋恒晝眠。", "萬家人喜悅，鄰壤蒙安全。", "譬如泰山雲，益此涸轍泉。", "我鄙無所解，昔隨公得仙。", "超升已連帥，羈旅今華顛。", "屬郡損末理，郵筒賁新篇。", "坎坎我鼓腹，咸韶媿朱弦。", "暌乖每自念，姤遇兩何緣。", "野色小過雨，秋聲漸號蟬。", "園林凄剝落，樓觀蔚騰騫。", "曳履烟景外，支頤嵐翠前。", "嘗聞東晉士，多聞遠師禪。", "盛世非否塞，微生自屯邅。", "廬岳决遯去，老夫無妄言。", "迹同人間世，心鍊鼎中鉛。", "流俗若飛蠱，困途多墮鳶。", "相需緱嶺上，一比洪崖肩。"]'),
('06a1a19c-35a0-4386-afd8-b8ea9c1b8a2f','本是一首寄芸叟','孔平仲','宋','宋诗','song-poetry','','[]','本末已倒置，是非當告誰。',60,'全唐诗/poet.song.53000.json','["本末已倒置，是非當告誰。", "同爲天涯客，根冷聊相依。", "生平尚氣節，相約老不衰。", "煎烹雖炎炎，何損百鍊姿。", "太過空自反，急鞭尤恐遲。"]'),
('738300e8-9e2b-4a10-82aa-e87cb230fde8','相看一首寄芸叟','孔平仲','宋','宋诗','song-poetry','','[]','相與同少壯，看看俱老人。',60,'全唐诗/poet.song.53000.json','["相與同少壯，看看俱老人。", "過日如脫兔，半生若浮雲。", "百事多齟齬，不如收此身。", "寄心青霞杪，一笑輕千鈞。", "行行秋雁去，書此贈情親。"]'),
('bf5dc33c-6435-4501-9b8c-1e453d8d8fb2','朋友一首寄芸叟','孔平仲','宋','宋诗','song-poetry','','[]','面朋隨俯仰，心友存終始。',36,'全唐诗/poet.song.53000.json','["面朋隨俯仰，心友存終始。", "頻數寄詩書，因斯作瘡痏。", "此疏彼何密，已矣難湔洗。"]'),
('0b520b4c-6ce7-4e9e-84a7-d7b20109c3f2','題織錦璇璣圖  其一','孔平仲','宋','宋诗','song-poetry','','[]','紅窗小泣低聲怨，永夕春寒斗帳空。',32,'全唐诗/poet.song.53000.json','["紅窗小泣低聲怨，永夕春寒斗帳空。", "中酒落花飛絮亂，曉鶑啼破夢匆匆。"]'),
('dd54dcb8-e566-4bad-a3dd-23ea4a18a6ab','題織錦璇璣圖  其二','孔平仲','宋','宋诗','song-poetry','','[]','晞草露如郎行薄，亂花風似客情多。',32,'全唐诗/poet.song.53000.json','["晞草露如郎行薄，亂花風似客情多。", "歸鴻見處彈珠淚，語燕聞時斂翠蛾。"]'),
('374691d3-77d3-4ea1-a307-67d58b720b28','題織錦璇璣圖  其三','孔平仲','宋','宋诗','song-poetry','','[]','同誰更倚閒窗繡，落日紅扉小院深。',32,'全唐诗/poet.song.53000.json','["同誰更倚閒窗繡，落日紅扉小院深。", "東復西流分水嶺，恨兼愁續斷弦琴。"]'),
('71cabd83-e37c-4451-8da8-c8e2fe61c95c','題織錦璇璣圖  其四','孔平仲','宋','宋诗','song-poetry','','[]','腸斷寫愁縈字字，錦紋傳意寄君看。',32,'全唐诗/poet.song.53000.json','["腸斷寫愁縈字字，錦紋傳意寄君看。", "床空照月殘燈冷，黄葉霜前秋信寒。"]'),
('d04d02c3-d2b2-4629-a569-49d3db170ce6','題織錦璇璣圖  其五','孔平仲','宋','宋诗','song-poetry','','[]','前堂畫燭殘凝淚，半夜清香舊惹衾。',32,'全唐诗/poet.song.53000.json','["前堂畫燭殘凝淚，半夜清香舊惹衾。", "烟鎖竹枝寒宿鳥，水沉天色霽橫參。"]'),
('e0873dea-b710-4bbe-a521-6996e70906d3','星名詩呈提刑曾朝散','孔平仲','宋','宋诗','song-poetry','','[]','華胄參元後，高門輔弼臣。',120,'全唐诗/poet.song.53000.json','["華胄參元後，高門輔弼臣。", "莊池初奮翼，舜旦早逢辰。", "雲木千尋秀，鑪金百煉純。", "日邊虛位著，楚尾望車塵。", "尚德真膚使，存心信吉人。", "包含譽尤美，平格澤惟均。", "短髮憐衰老，黄金媿拊循。", "禮容長不責，恩義極相親。", "最要箕張口，深憐井有人。", "孤危荷全度，謀報畢餘身。"]'),
('33d7afb6-ff7c-48a2-a296-ad122af47d10','和徐道腴波字','孔平仲','宋','宋诗','song-poetry','','[]','人橫玉管寧無意，風入春江總是波。',32,'全唐诗/poet.song.53000.json','["人橫玉管寧無意，風入春江總是波。", "把袂相牽招飲去，岳陽城外酒徒多。"]'),
('6f1d35b5-7442-4bcd-8577-ee97e9cf9b52','席上口授杜仲觀','孔平仲','宋','宋诗','song-poetry','','[]','暮雨蕭蕭何不止，東風弄白起江波。',32,'全唐诗/poet.song.53000.json','["暮雨蕭蕭何不止，東風弄白起江波。", "綠楊綰作同心結，杜子春來狂興多。"]'),
('603b29fa-e77a-4d06-baef-b0d44d1e3988','累約慎思視事今已入境盤桓不進欲以十四日交承又云六甲窮日戲作藏頭一首','孔平仲','宋','宋诗','song-poetry','','[]','工巧新詩寄遞筒，同聲稍稍變他宮。',64,'全唐诗/poet.song.53000.json','["工巧新詩寄遞筒，同聲稍稍變他宮。", "口傳知受諸君指，日好何論六甲窮。", "躬自省愆方久仄，人多助虐更磨礱。", "石渠舊友年家契，大笑今朝已落空。"]'),
('0b3d3a2f-fa0c-487c-bf30-0f9f7e6837a3','慎思移日至月望交割口占奉呈','孔平仲','宋','宋诗','song-poetry','','[]','日日高樓倚望君，口吟心想跂清塵。',64,'全唐诗/poet.song.53000.json','["日日高樓倚望君，口吟心想跂清塵。", "土膏著雨蒼葭出，山色凝雲翠黛顰。", "卑冗一官誰羽翼，異同千狀極艱辛。", "十分明月迎新守，寸步江村老盡春。"]'),
('2bac9f0e-a5ae-484c-b0dd-84520ec6709a','建茶一首','孔平仲','宋','宋诗','song-poetry','','[]','建茶一杯午睡起，除渴蠲煩無此比。',96,'全唐诗/poet.song.53000.json','["建茶一杯午睡起，除渴蠲煩無此比。", "滿庭葉暗啼野鶑，平地雨足生春水。", "定心寧息守丹竈，執固養和歸赤子。", "破須速補勉旃修，危可求安灼然理。", "成事何論軒冕貴，收身早占雲泉美。", "開門納盜誤人多，閉關掃軌從今始。"]'),
('c4a93762-7268-4385-9528-50f7eef56c85','周亨叔推官見示詩軸','孔平仲','宋','宋诗','song-poetry','','[]','黄金鍊語玉琢詞，絹素中度無輕紕。',64,'全唐诗/poet.song.53000.json','["黄金鍊語玉琢詞，絹素中度無輕紕。", "幼時文采已奇絕，婦老兒長今可知。", "外窺驕虜亦有作，孫吳暗合知兵略。", "虀鹽氣味異膏粱，臼中丹砂非俗藥。"]'),
('2421940d-8abc-42d9-b095-448b9311445e','集文選句贈別','孔平仲','宋','宋诗','song-poetry','','[]','離別在須臾，置酒宴所歡。',96,'全唐诗/poet.song.53000.json','["離別在須臾，置酒宴所歡。", "借問此何時，萋萋春草繁。", "江蘺生幽渚，山櫻發欲然。", "游絲映空轉，紅藥當階翻。", "飛鳥繞樹翔，哀猿響南蠻。", "相與數子游，行邁越長川。", "相去日已遠，光景不可攀。", "舉目增永慕，敘意於濡翰。"]'),
('04eb989a-0ef3-46c3-a511-b9f2a3f8adbf','文選集句寄慎思交代學士慎思遊岳老夫守舍敘述遊舊慎問交承與夫舍舟登陸之策俱在此矣','孔平仲','宋','宋诗','song-poetry','','["\u8861\u5c71"]','鄧生何感激，志尚好書詩。',288,'全唐诗/poet.song.53000.json','["鄧生何感激，志尚好書詩。", "清機發妙理，言論準宣尼。", "翰墨時間作，文雅縱橫飛。", "彌年缺相從，夢想見容輝。", "自昔同寮寀，恩愛兩不疑。", "潔身躋秘閣，携手游郊畿。", "一麾乃出守，桑梓有餘輝。", "濡迹涉江湘，將就衡陽棲。", "渺渺孤舟游，洲渚既淹時。", "鳳凰集南嶽，平生遂幽期。", "岩峭嶺稠疊，高高入雲霓。", "企石挹飛泉，陵岡掇丹荑。", "即事既多美，游子澹忘歸。", "春仲尚未發，悠悠隔山陂。", "今我惟困蒙，處身孤且危。", "顧影悽自憐，悄悄令人悲。", "一心抱區區，知音世所希。", "塊然守空堂，高窗時動扉。", "仰視浮雲翔，密雨如散絲。", "中夜撫枕歎，軒車來何遲。", "傾想遲嘉音，會合何時諧。", "借問下車日，臨路猶遲迴。", "春江壯風濤，漁潭霧未開。", "肅此塵外軫，以副饑渴懷。"]'),
('0e197c36-a30c-4400-b093-bb6e2471ab77','一勝篇','孔平仲','宋','宋诗','song-poetry','','[]','我與承君棋，結局贏一路。',48,'全唐诗/poet.song.53000.json','["我與承君棋，結局贏一路。", "太多亦何用，停則無勝負。", "天清與地寧，妙絕占此數。", "正如賈堅射，不中乃奇處。"]'),
('8816cfcc-e8e2-4a0b-a1a3-d8371714788e','再勝篇','孔平仲','宋','宋诗','song-poetry','','[]','再勝路幾許，非一亦非三。',48,'全唐诗/poet.song.53000.json','["再勝路幾許，非一亦非三。", "小雅連大雅，周南兼召南。", "舜目處其半，臨爻與之參。", "在我猶不足，自笑無乃貪。"]'),
('3a2842c3-97b5-4b33-8c75-04dccfd6e91e','嘲承君','孔平仲','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','已填實局餘五黑，天數相符豈人力。',64,'全唐诗/poet.song.53000.json','["已填實局餘五黑，天數相符豈人力。", "雖於洪範少四疇，若比武成多二策。", "我詩雜組今幾首，鼯鼠技窮那復有。", "泰山風拔大夫松，彭澤霜隕先生柳。"]'),
('096c85d3-1e03-4563-ae3e-38f39ebb8ea0','承君棋輸包子詩以促之  其一','孔平仲','宋','宋诗','song-poetry','','[]','君看射夫指，柔軟作皮室。',48,'全唐诗/poet.song.53000.json','["君看射夫指，柔軟作皮室。", "君看艷婦手，縫帛恐不密。", "草木漸叢生，正渴柚與橘。", "亟遣中丞來，莫令章句出。"]'),
('7aff4e55-94b9-44f1-b9e6-ef40b8fde426','承君棋輸包子詩以促之  其二','孔平仲','宋','宋诗','song-poetry','','[]','承君非耄荒，意似羞棋敗。',48,'全唐诗/poet.song.53000.json','["承君非耄荒，意似羞棋敗。", "未應倒干戈，當且解粉黛。", "如何畫虎手，乃作死麕態。", "貢茅緩不誅，含覆吾已大。"]'),
('715e532e-a2dd-499d-8941-3f3519ca2e9b','承君輸十三籌','孔平仲','宋','宋诗','song-poetry','','[]','欲知輸籌數，計月乃閏年。',48,'全唐诗/poet.song.53000.json','["欲知輸籌數，計月乃閏年。", "秦箏有幾弦，汴上樓幾間。", "寶從真如獻，人逐耿恭還。", "老氏死之徒，孫子著書篇。"]'),
('c8a64825-0b04-4bbe-a2a0-211cfb1f077f','走筆呈承君','孔平仲','宋','宋诗','song-poetry','','[]','圍棋屢北當復戰，乘興能來不待邀。',32,'全唐诗/poet.song.53000.json','["圍棋屢北當復戰，乘興能來不待邀。", "杜牧詩如道今日，最宜簷雨竹蕭蕭。"]'),
('95fb1096-c5ba-4056-b74c-a80517e60f37','風人一絕','孔平仲','宋','宋诗','song-poetry','','[]','須煩玉手自操刀，便趁槐芽作冷淘。',32,'全唐诗/poet.song.53000.json','["須煩玉手自操刀，便趁槐芽作冷淘。", "剩潑葱油抹羊肉，不嫌瀟洒愛蕭騷。"]'),
('d2539635-cd31-43be-bcea-5b6b76fec019','戲承君  其一','孔平仲','宋','宋诗','song-poetry','','[]','一自棋輸日望之，至今肅肅草生時。',64,'全唐诗/poet.song.53000.json','["一自棋輸日望之，至今肅肅草生時。", "知君苦愛刀筆吏，使我長吟風雨詩。", "已共苞稂泉浸濕，更聽甫草馬鳴悲。", "子雲寂寞方無頼，想見馨香雜祭脂。"]'),
('12f8d6bc-2907-4f65-bcea-7cba7d3402e0','戲承君  其二','孔平仲','宋','宋诗','song-poetry','','[]','越上荒山浪得名，如何開邑在彭城。',64,'全唐诗/poet.song.53000.json','["越上荒山浪得名，如何開邑在彭城。", "飄蕭雲意迷秋日，索寞人心戀玉京。", "花倚宮牆無限好，泉流古寺有餘清。", "盡芟野艾栽修竹，更聽虞弦奏九成。"]'),
('28ac976e-7eab-4fc5-a69f-074c5719f81f','戲承君  其三','孔平仲','宋','宋诗','song-poetry','','[]','至忠至朴少人知，思話胸中聽者誰。',64,'全唐诗/poet.song.53000.json','["至忠至朴少人知，思話胸中聽者誰。", "長史移家真暫住，相君爲冠定他時。", "道齋不廢持三寶，資斧何須措一辭。", "更有閒堂奉清宴，客來簷雨看圍棋。"]'),
('865c1e38-7761-445a-b65e-799bb1972353','戲承君  其四','孔平仲','宋','宋诗','song-poetry','','[]','次君門戶想風標，千載齊梁已寂寥。',64,'全唐诗/poet.song.53000.json','["次君門戶想風標，千載齊梁已寂寥。", "隋后如何依異域，秋晨定不怨凉飈。", "半揎紅袖能調瑟，滿把真珠看結條。", "它日蘭陵若歸去，臨江灘上略相邀。"]'),
('6b4d796b-4b5b-4753-af00-1d09f31484ad','承君輸棋八路','孔平仲','宋','宋诗','song-poetry','','[]','君希元凱才，我異厨顧黨。',48,'全唐诗/poet.song.53000.json','["君希元凱才，我異厨顧黨。", "誅蠻幾首級，十指屈其兩。", "疾風摧桂林，異夢吞卦象。", "疲極曳杖歸，顰眉有餘怏。"]'),
('f326da94-66ea-42a1-b9fd-e05ca3c9e3e8','蕭器之小飲誦王舒公藥名詩因效其體','孔平仲','宋','宋诗','song-poetry','','[]','蕭郎嘉客近遠志，把酒勸賓郎半醉。',160,'全唐诗/poet.song.53000.json','["蕭郎嘉客近遠志，把酒勸賓郎半醉。", "自然同類易相投，官守從容况無事。", "清晨麴糵寒有力，倒洒金鍾乳花滴。", "十分蘸甲香且醇，不覺昏黄連夜色。", "雀噪烏栖奈晚何，匆匆白日若飛梭。", "青青百草霜已歇，牆陰淺白微輕雪。", "庭梅香膩粉苞解，歲律將旋復花發。", "銅壺泣水銀箭短，漏聲斷續隨風遠。", "起視天南星斗稀，蟾蜍已黑牽牛低。", "知子多情惜分散，山公酩酊自當歸。"]'),
('09d6872c-4350-45f5-a5f0-7136d68f7394','再作藥名詩一篇呈器之','孔平仲','宋','宋诗','song-poetry','','[]','肥羊作臛香出厨，膏粱姜桂品味俱。',224,'全唐诗/poet.song.53000.json','["肥羊作臛香出厨，膏粱姜桂品味俱。", "夙開東閣戒諸客，千金騰踊沽酒壺。", "飛觥倒杓約不退，一卷百盞皆無餘。", "不須呼盧會六博，笙簧琴筑非真樂。", "蕭郎獨以酒娛賓，憐子心勤憎子虐。", "眼前覆花不容起，面赤復令須滿酌。", "更深閃閃燈焰消，照天燭黄蠟洒膏。", "欲逃人覺安敢去，飲水只欲吞波濤。", "青烟鬰鬰金鴨細，花上紅酥合香蒂。", "四垂銀箔不知寒，却勸金罌子同醉。", "久不見子眼空青，見子宛然猶舊情。", "敗船如簁寄江水，天陰夜半防風起。", "告歸急走城西角，如粉霜花衣上落。", "屢蒙大幅掃長篇，才薄何由繼高作。"]'),
('29f07b9a-bdd3-45df-9f6a-2a01738b634e','與董承君棋輒勝四籌作藥名五言詩奉戲','孔平仲','宋','宋诗','song-poetry','','[]','董子獷且狂，孔公孽更毒。',192,'全唐诗/poet.song.53000.json','["董子獷且狂，孔公孽更毒。", "文楸石棋子，白及黑對局。", "預知子輕敵，銳膽坐看覆。", "一時羅列徧，先與推大腹。", "欻如飛廉驅，窘若防風戮。", "餘兵尚百合，續斷聊忽忽。", "猛虎仗爪牙，中塗佯躑躅。", "嗟嗟草草甚，驅豬令迫逐。", "直前無夷險，觱撥下子速。", "而我頗從容，莽草先設伏。", "常山肆縱橫，大戟挾長轂。", "威靈先震盪，巨勝侔破竹。", "蕭蕭馬鳴退，戰血餘川谷。", "百步笑奔崩，獨活嗟窮蹙。", "萎蕤不復騁，銷蝕神采縮。", "作詩誚伊棋，我壯知子曲。"]'),
('77b3525d-7bcb-4115-8d07-b4afbe9ac67a','亶父寄示與譙沖元唱和藥名詩因作一篇奉寄','孔平仲','宋','宋诗','song-poetry','','[]','天南星斗垂晶熒，麻姑山色排空青。',240,'全唐诗/poet.song.53000.json','["天南星斗垂晶熒，麻姑山色排空青。", "人中白眉誰第一，周郎獨以文章名。", "少年折桂心已壯，大學弱冠衆所驚。", "嚴徐長卿詞格老，合上芸臺預讎討。", "赤車素者已爲淹，復令倅郡淮南道。", "蘄春何幸人熙熙，有賢使君子副之。", "鈴閣深沉香一炷，綵牋舒卷百篇詩。", "藏鱗伏翼聊展轉，有才無患子不顯。", "楚澤蘭芳莫謾悲，秦烏頭白終當返。", "我栖江上松蘿深，自甘草莽長陸沉。", "忽忽光景又半夏，書房風月澄人心。", "昏黄禽噪悄不樂，架木通渠清河濯。", "雨餘凉風襲衣襟，半天河漢垂簷角。", "惟恨與子未從容，紫芝眉宇何時逢。", "頻以青琅玕寄我，不須怊悵白頭翁。"]'),
('5da6ca6f-a168-4516-8079-76a15bc3bec5','再作藥名詩一首寄亶父並用本字更不假借此諸名布在本草中雖或隠晦然以爲不當但取世俗之所知而遺其所不知亦君子之用心也至於搜索牽合亦可以發人意思而消磨光景請亶父同作','孔平仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','憶昔見子龍沙邊，冰臺玉壺氣凜然。',304,'全唐诗/poet.song.53000.json','["憶昔見子龍沙邊，冰臺玉壺氣凜然。", "才薄人微辱取友，青蒿媿倚崑崙顛。", "詩鋒利如立刀劍，談經辨博森戈鋋。", "賢愚校我幾百倍，預知子必轉青天。", "別來喧卑共誰語，神遊閬苑長思仙。", "京師再見空草草，瑣細辛勤官事牽。", "如今相去水南北，一別羈旅還隔年。", "每思益友在咫尺，九江地與蘄黄連。", "作詩寄我解離恨，紫貝珊瑚堆目前。", "靈蛇含珠久不吐，駿馬銜脫誰能先。", "彌天雄句駭俗耳，入木香煤濡綵牋。", "嗟余鄙訥會强敵，蜀雞格鬭非所便。", "未甘遂服强一戰，光焰消縮何由然。", "我居此土頗大適，門對廬山飛玉泉。", "火雲燒赤赫日熾，委蛇退食甘晝眠。", "環池老木自却暑，清波白石明相鮮。", "木香漠漠初過雨，水英燦燦新開蓮。", "區區余心最念子，空對黄昏江月圓。", "重樓遠望君不見，淮南細草迷蒼烟。"]'),
('fba35ecd-e78a-41ea-9f1d-195241145406','亶甫寄示廬山高藥名詩亦作一首奉酬不犯唱首兼用本字更不假借','孔平仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','噫戲廬山乎高哉，山連大江勢橫絕。',258,'全唐诗/poet.song.53000.json','["噫戲廬山乎高哉，山連大江勢橫絕。", "虎卷龍拏起霜雪，五湖七澤瀉波來。", "百穿千孔吞吐成雲雷，其上自有飛瀑水。", "白如一疋練，半天河漢傾崔嵬。", "蒼蒼石壁插空翠，漠漠雲華自開閉。", "水甘松香澗谷深，黄精枸杞生成林。", "地無虎狼毒草木，但聞仙童玉女語笑之清音。", "君不見當時匡續斷世故，結廬莽草無尋處。", "又不見淵明無心五斗米，石床醉臥呼不起。", "真君種杏人獲生，遠公白蓮開玉英。", "松肪柏實皆可飽，何必皓露棲金莖。", "我欲攀崖採紫芝，道中逢仙一問之。", "接余之手生虹蜺，崑崙太室相追隨。", "玄臺絳闕恣遠遊，旁通三島逮十洲。", "柯消石爛未肯休，千秋萬歲一瞑目，下視塵世如蝸牛。"]'),
('8ffda573-ee35-4646-8e46-446a0f0d1ef7','八音詩  其一','孔平仲','宋','宋诗','song-poetry','','[]','金風盪炎暑，六合氣已清。',96,'全唐诗/poet.song.53000.json','["金風盪炎暑，六合氣已清。", "石崇南山高，晨起見崢嶸。", "絲垂蟲就繭，彼各有所營。", "竹實不足飽，鳳凰尚饑鳴。", "匏瓜固賤草，引蔓上高城。", "土地之所宜，結子如瓶罌。", "革带守空文，歲月逝可驚。", "木落行且秀，欣欣候春榮。"]'),
('bbb222da-b056-46f7-8fd8-a7575e36712e','八音詩  其二','孔平仲','宋','宋诗','song-poetry','','[]','金杯十分酒，酌子消百憂。',96,'全唐诗/poet.song.53000.json','["金杯十分酒，酌子消百憂。", "石可補青天，棄與瓦礫侔。", "絲可弦南風，織成絹素柔。", "竹帛未書功，光景忽以遒。", "匏繫久不食，栖栖江上洲。", "土鼓與蕢桴，爲用先鳴球。", "革带人所賤，猶列下邳侯。", "木有棟梁材，終當回萬牛。"]'),
('ac770ac3-1fe4-437b-b372-26c28afc3764','八音詩  其三','孔平仲','宋','宋诗','song-poetry','','[]','金谷草離離，綠珠魂已蟄。',96,'全唐诗/poet.song.53000.json','["金谷草離離，綠珠魂已蟄。", "石崇雖富貴，一散不可集。", "絲亦不須悲，岐亦不須泣。", "竹林諸逸士，以醉名自立。", "匏弦且爲樂，惜此光景急。", "土人勸我勤，朱紫當早拾。", "革性以從容，矯揉未易入。", "木散姑自全，寧求斧斤及。"]'),
('f2dad5ec-c2e7-44af-8c14-e08d7d652cc4','八音詩  其四','孔平仲','宋','宋诗','song-poetry','','[]','金色晦塵垢，人疑以爲鍮。',96,'全唐诗/poet.song.53000.json','["金色晦塵垢，人疑以爲鍮。", "石有潔白姿，昧者比琳璆。", "絲繰不盡緒，誰與結綢繆。", "竹可裁笙竽，奈何困薪槱。", "匏黄已落蔕，歲序颯驚秋。", "土壤厭卑濕，山川嗟阻修。", "革車召武士，折敵當與謀。", "木鐸一奮劍，爲君斬倡優。"]'),
('505f0b67-6ae3-4151-80de-b50e4c690a81','八音詩  其五','孔平仲','宋','宋诗','song-poetry','','[]','金弦調陰陽，諸公盡梁棟。',96,'全唐诗/poet.song.53000.json','["金弦調陰陽，諸公盡梁棟。", "石室校圖書，英才皆屈宋。", "絲侵鬢邊髮，瀕老知無用。", "竹徑理舊居，蔬畦閱新種。", "匏刳以酌酒，自唱出歌送。", "土燥葉可收，水清魚益衆。", "革屨隨藜杖，徜徉步方縱。", "木末見栖鴉，暝歸街鼓動。"]'),
('7b6a69a7-5909-472a-9720-fa809af6fc38','八音詩  其六','孔平仲','宋','宋诗','song-poetry','','[]','金烏卷海水，東欲上扶桑。',96,'全唐诗/poet.song.53000.json','["金烏卷海水，東欲上扶桑。", "石性本沉滯，不能隨波揚。", "絲縈自作繭，漸老甘退藏。", "竹會有青色，牽人幽興長。", "匏羹若可飽，何必羨牛羊。", "土室若可安，不須高棟梁。", "革以脂自柔，鐵遇火則烊。", "木可揉而直，惟士心有常。"]'),
('ba51ea51-fbaf-4530-aabf-accc6e2d8285','又謝諸君酬和','孔平仲','宋','宋诗','song-poetry','','[]','金蘭諸益友，一一皆詩家。',96,'全唐诗/poet.song.53000.json','["金蘭諸益友，一一皆詩家。", "石音盡清越，使我慚淫哇。", "絲棼强抽緒，語句多疵瑕。", "竹牋屢塗竄，誰謂點不加。", "匏實雖百枚，不如一甘瓜。", "土朱重千鈞，不如一丹砂。", "革去齊梁體，羨君吐天葩。", "木强未肯休，餘辭綴車斜。"]'),
('332cefcb-7ef6-40a3-a318-148114e352c9','又奉項元師','孔平仲','宋','宋诗','song-poetry','','[]','金剛有遺偈，難以聲音求。',96,'全唐诗/poet.song.53000.json','["金剛有遺偈，難以聲音求。", "石擊乃有光，是名爲火不。", "絲從何處來，認著從繭抽。", "竹本由根生，根外又何由。", "匏開即爲勺，針屈即爲鉤。", "土地水火風，合爲一浮漚。", "革易固不常，溈山水牯牛。", "木性無榮謝，古今春復秋。"]'),
('3369718d-4f77-41a3-afa1-4f073cf80ea8','又奉朱明叟','孔平仲','宋','宋诗','song-poetry','','[]','金榜閱名姓，於今二十秋。',96,'全唐诗/poet.song.53000.json','["金榜閱名姓，於今二十秋。", "石隕鷁退飛，才命不相謀。", "絲繩可比直，應笑曲如鈎。", "竹未遇蔡邕，有聲誰見求。", "匏瓜豈無蔓，奈何枝不樛。", "土俗相慢侮，有如東家丘。", "革囊貯珠玉，至寶勿暗投。", "木若假先容，爲君效綢繆。"]'),
('8c92a4e4-09f9-462e-b19a-450fb3de7a34','又奉周文之','孔平仲','宋','宋诗','song-poetry','','[]','金臺招俊乂，之子值明時。',96,'全唐诗/poet.song.53000.json','["金臺招俊乂，之子值明時。", "石藴荆山璞，當爲璧與珪。", "絲隨物所染，在涅要不緇。", "竹箭中有筠，歲寒尚猗猗。", "匏葉異甘苦，采掇須自知。", "土性殊美惡，栽培擇所宜。", "革急而韋緩，古人貴調胹。", "木老雁被烹，吾師乃支離。"]'),
('45450ed8-53b9-4b12-bac7-62a5c99cbc8c','郡集虎渡亭賓主十人  其一','孔平仲','宋','宋诗','song-poetry','','[]','築館當陽月，驅車及上旬。',72,'全唐诗/poet.song.53000.json','["築館當陽月，驅車及上旬。", "盈分勸美酒，排旨聚佳賓。", "闕里推高第，姬朝倚亂臣。", "全醫參老手，駑駕望清塵。", "佛地前緣舊，堯曦普照均。", "瀛洲何足羨，天日坐中人。"]'),
('0c0b7134-92b9-4325-9acf-dbf086bbb63a','郡集虎渡亭賓主十人  其二','孔平仲','宋','宋诗','song-poetry','','[]','欲結朱輪日，相期已及旬。',72,'全唐诗/poet.song.53000.json','["欲結朱輪日，相期已及旬。", "木圖橫畫棟，玉德集談賓。", "濟濟多周伯，詵詵倍舜臣。", "身調宰夫膳，目視屬車塵。", "聞一才將埒，能千智亦均。", "可知前世陋，作者欠三人。"]'),
('f3dd1c3e-c650-42c6-98b7-69da30a66580','郡集虎渡亭賓主十人  其三','孔平仲','宋','宋诗','song-poetry','','[]','璜臺成百日，斗酒宴茲旬。',72,'全唐诗/poet.song.53000.json','["璜臺成百日，斗酒宴茲旬。", "文雅昇平客，風流結綺賓。", "橈椎皆敏手，諫俎必名臣。", "御史歸清望，黄門掃俗塵。", "專門知業廣，就傅亦年均。", "忠信推吾邑，疇非善行人。"]'),
('0bee9ed3-0640-4012-8d26-5b4e90fde768','郡集虎渡亭賓主十人  其四','孔平仲','宋','宋诗','song-poetry','','[]','盛比芳林會，歡非洛汭旬。',72,'全唐诗/poet.song.53000.json','["盛比芳林會，歡非洛汭旬。", "國城推帥長，龜數集朋賓。", "益一參卿列，增三補諫臣。", "天泉開象緯，日煇散光塵。", "束帛蒙恩厚，玈弓校力均。", "論言雖幼學，柳惲實兼人。"]'),
('009ad245-0e76-436d-aaad-d89930aee7e3','郡集虎渡亭賓主十人  其五','孔平仲','宋','宋诗','song-poetry','','[]','長亭接雙堠，良月屆初旬。',72,'全唐诗/poet.song.53000.json','["長亭接雙堠，良月屆初旬。", "修義推賢守，同心會衆賓。", "公卿正當位，輿隸迭相臣。", "庇蔭樓層勢，追隨驥步塵。", "束薪恩不薄，瑴玉價仍均。", "共取封侯貴，持旌將萬人。"]'),
('b887bf8c-d0b1-45cb-aec1-0744bdfa2fc7','一字至七字送夢錫夢錫託疾引歸','孔平仲','宋','宋诗','song-poetry','','[]','行，行。',70,'全唐诗/poet.song.53000.json','["行，行。", "宿駕，宵征。", "秋漸老，雨初晴。", "黄葉歸思，青山去程。", "身隨一雁遠，眼入故鄉明。", "流水光陰可惜，浮雲軒冕自輕。", "把酒日飛鸚鵡盞，尋花更到鳳凰城。"]'),
('c0b0244b-25ef-46fc-bd5d-43131c76cdce','七字至一字','孔平仲','宋','宋诗','song-poetry','','[]','仕宦千憂出海濤，功名一笑付秋毫。',70,'全唐诗/poet.song.53000.json','["仕宦千憂出海濤，功名一笑付秋毫。", "榮望棄如脫屣，歸心斷若操刀。", "東堂展圖畫，北牖綴風騷。", "晴煎越茗，寒汎宮醪。", "超世網，釋天弢。", "就逸，辭勞。", "高，高。"]'),
('d4766ace-f431-4f40-ada8-f74293cb175a','十一月十二日會集賓主共八人','孔平仲','宋','宋诗','song-poetry','','[]','自笑開陽畔，輝光接斗魁。',48,'全唐诗/poet.song.53000.json','["自笑開陽畔，輝光接斗魁。", "名希周士貴，德慕舜元才。", "共享珍羞美，同騎駿馬回。", "它時立天柱，曾作飲仙來。"]'),
('ab1c1988-5eca-4544-be01-095c436ea9b8','送程給事知越州','孔平仲','宋','宋诗','song-poetry','','[]','曾築長城制百蠻，歸來青瑣照朝班。',64,'全唐诗/poet.song.53000.json','["曾築長城制百蠻，歸來青瑣照朝班。", "一言不爲戎人屈，萬里能全漢節還。", "已有直聲留朔漠，更將吟興入稽山。", "陛辭天語尤稠密，知得蓬萊幾日閑。"]'),
('4d02fc9a-04f7-4d76-a088-5ccb9890a6b3','翠微亭','孔平仲','宋','宋诗','song-poetry','','[]','蠟屐縈紆洞府間，飛甍人在最高巔。',64,'全唐诗/poet.song.53000.json','["蠟屐縈紆洞府間，飛甍人在最高巔。", "青山東去無餘地，黄潦西來正接天。", "太子池塘烟漫漫，紫微蹤跡草芊芊。", "松枯石朽由來事，莫作常情嘆逝川。"]'),
('f185cac6-77d1-4a17-b934-b32fcd0071af','句  其一','孔平仲','宋','宋诗','song-poetry','','[]','簫韶有遺韵，流入武溪中。',12,'全唐诗/poet.song.53000.json','["簫韶有遺韵，流入武溪中。"]'),
('009d169c-1b1b-4187-9682-94a12727cdff','句  其二','孔平仲','宋','宋诗','song-poetry','','[]','斜拖闕角龍千尺，澹抹牆腰月半稜。',16,'全唐诗/poet.song.53000.json','["斜拖闕角龍千尺，澹抹牆腰月半稜。"]'),
('c8970ac1-ac3d-4244-b165-151e7f41e3c8','句  其三','孔平仲','宋','宋诗','song-poetry','','[]','遺愛海波無繼處，去思秋色有餘清。',16,'全唐诗/poet.song.53000.json','["遺愛海波無繼處，去思秋色有餘清。"]'),
('e7af10f7-f907-43aa-be7e-2d633d5b98cf','句  其四','孔平仲','宋','宋诗','song-poetry','','[]','寫出十分秋。',6,'全唐诗/poet.song.53000.json','["寫出十分秋。"]'),
('48c0deb8-8adc-45e6-9c46-8893afd450bf','存目  其一','孔平仲','宋','宋诗','song-poetry','','[]','詩題：了語首句：公餗欲成忽覆鼎。',16,'全唐诗/poet.song.53000.json','["詩題：了語首句：公餗欲成忽覆鼎。"]'),
('783cc6de-0074-4496-9ae1-3b7e7d10ebcf','存目  其二','孔平仲','宋','宋诗','song-poetry','','[]','詩題：不了語首句：無言以手尋珮環。',17,'全唐诗/poet.song.53000.json','["詩題：不了語首句：無言以手尋珮環。"]'),
('143218de-b981-4a12-8885-27393f90dae5','存目  其三','孔平仲','宋','宋诗','song-poetry','','[]','詩題：吳正憲夫人挽詩首句：贊夫成相業。',19,'全唐诗/poet.song.53000.json','["詩題：吳正憲夫人挽詩首句：贊夫成相業。"]'),
('a215cb04-313b-429e-afec-eb78d81d1c7a','晦堂歌爲邑令朱天經作','鄒極','宋','宋诗','song-poetry','','[]','吾邑有賢令，才猷足經國。',288,'全唐诗/poet.song.53000.json','["吾邑有賢令，才猷足經國。", "政成越一考，俊譽自赫赫。", "既圃闢後堂，背南面西北。", "爲愛園中景，花木皆手植。", "乘閒一造見，問名名未得。", "反覆爲君思，請以晦題額。", "晦取用而明，非謂入宴息。", "韜藏蒞衆術，蓄養輔世德。", "制動本以靜，對語定以默。", "大欲揚王庭，小亦去民忒。", "有如匣中劍，利在誅奸慝。", "又若山下泉，出乃作惠澤。", "公家急期會，訴牒仍堆積。", "一判情僞分，經目猶白黑。", "堂中琴寂寞，昔優今逼迫。", "堂內經縱橫，客至君欣懌。", "豈無詩酒興，相與樂暇隙。", "平臺歌舞地，池上有瑶席。", "坐揖竹風細，行依檜陰直。", "返照亙天紅，輕烟半山白。", "試觀禽鳥細，所畏網與弋。", "我晦異君子，終焉茲屏跡。", "出處各一時，俯仰無愧色。", "作詩見情性，擬古麗以則。"]'),
('6316c593-87da-40c6-bce3-cd9eb41d892e','一翁亭歌','鄒極','宋','宋诗','song-poetry','','[]','一翁亭高半空住，老健身輕若平步。',384,'全唐诗/poet.song.53000.json','["一翁亭高半空住，老健身輕若平步。", "昔約隠者招不來，今日招魂返何處。", "亭壓峻嶺出茂林，百里山水如鏡聚。", "俯窺井邑在澗底，鳳臺獅子沈烟霧。", "豁然氣象心胸開，陰晴異景天際來。", "巧思難窮畫工筆，冥搜不盡詩人才。", "春歸谷暖花卉亂，士女遊嬉情爛漫。", "暑風清快秋思多，玉樹瓊樓雪中看。", "時時獨上凭危欄，爲愛孤松不可攀。", "百年天畀作伴侶，偃蹇肯落塵凡間。", "有時携琴坐松下，竹徑雖掃門常關。", "風吹清韵月散影，家僮不至那知還。", "有時爲招三兩客，對松置酒味松德。", "壞梁棟撓彼小材，大夫自是粗官職。", "醉來摩松鱗觸手，汙松以官亦何有。", "許由洗耳常不嗔，伯夷餓死吾無取。", "登亭自負只一翁，四海退者豈我同。", "多緣失志畏罪廢，往往養譽要王公。", "我由蘭署出持節，按道適至親庭中。", "亟遭大變僅存息，無復有意圖勳庸。", "遂瀝丹誠叩天闕，乞得真館棲玉隆。", "歲餘尚厭仕籍在，抽簪解組顔猶紅。", "是非榮辱自此杜，生事無憂付農圃。", "種蔬植果雞魚肥，日具賓庖式歌舞。"]'),
('7a2b85fb-0e6a-474e-a1f7-4d540a3397d9','鑑泉歌爲邑令吳無求作','鄒極','宋','宋诗','song-poetry','','[]','鑑泉之竇山之麓，百年蕪穢暗渟滀。',288,'全唐诗/poet.song.53000.json','["鑑泉之竇山之麓，百年蕪穢暗渟滀。", "吳侯天與仁智資，退食俯窺嗟不足。", "試披沙滓鑿爲沼，深纔數尺闊盈幅。", "迸流日夕不可窮，碎如珠璣瑩如玉。", "南鄰野叟號逍遙，潄石枕泉真所欲。", "一來臨視推不去，草草杯盤勉君速。", "解衣款入凌陰坐，六月正午忘暑毒。", "滌煩沃渴汲復溢，長流清風去殘酷。", "此鑑不窺示養正，用明豈特鬚眉燭。", "巧非鎔範浄非磨，應物無心奸自伏。", "寶匳青銅世所貴，鳳舞龍盤耀人目。", "勿輕勺水當靜觀，能動天關翻地軸。", "主人寶此方澄清，野叟撓之安敢瀆。", "舉觴隨分擁叵羅，醉狂擬學鴛鴦浴。", "世無秦法飲無禁，心動膽張驚且縮。", "可憐渫在百里間，四海王明俱受福。", "顯幽用舍姑置之，君顔漸淍吾髮禿。", "相逢一顧一回笑，滿酌爲君歌此曲。"]'),
('f9b9e627-163c-465b-b4bd-0da95be66dd0','月菴歌','鄒極','宋','宋诗','song-poetry','','[]','吳侯之來適荒年，政修民蘇猶解懸。',192,'全唐诗/poet.song.53000.json','["吳侯之來適荒年，政修民蘇猶解懸。", "庭無留訟獄屢空，百姓愛悅奸吏悛。", "公餘何以度永日，坐督皂隸先疏泉。", "泉潴爲沼浄可鑑，清範即與名俱傳。", "今年時豐民事簡，退食縱步山之巔。", "誅鋤蕪穢出古木，矯如虬龍上參天。", "夷高培坳蔭其下，百里勝景盡目前。", "爛柯石局候仙侶，月菴竹榻容醉眠。", "或弄瑶琴或放歌，或談玄理或安禪。", "圓虛洞照萬緣息，乾坤有量斯無邊。", "菴中主人趣高上，喜我相過時留連。", "所嗟官滿差遷去，肯顧衰翁須後賢。"]'),
('7df3a232-82d0-4d81-a156-bbc91ffe1353','題顯陽寺疏快軒','鄒極','宋','宋诗','song-poetry','','[]','溪邊穿小徑，寺後起幽軒。',48,'全唐诗/poet.song.53000.json','["溪邊穿小徑，寺後起幽軒。", "伐使惡木盡，養教修竹繁。", "閒聽漁唱靜，臥隔市場喧。", "疏快宜人處，追惟子美言。"]'),
('30328486-7a25-48f7-9990-6a0a4c9e6600','題招福寺檀欒軒  其一','鄒極','宋','宋诗','song-poetry','','[]','開軒得幽致，檻外築檀欒。',48,'全唐诗/poet.song.53000.json','["開軒得幽致，檻外築檀欒。", "日射黄金碎，風敲碧玉寒。", "暑清移榻就，雪煖擁爐看。", "一水塵埃隔，壺中境界寬。"]'),
('56edc42f-8b49-4723-935e-ed5d0b60a0e4','題招福寺檀欒軒  其二','鄒極','宋','宋诗','song-poetry','','[]','出郭渡清溪，僧閒晝掩扉。',48,'全唐诗/poet.song.53000.json','["出郭渡清溪，僧閒晝掩扉。", "造軒惟愛竹，植杖即披衣。", "家舍杯盤近，村莊雞犬肥。", "頻來君莫厭，倒載夜深歸。"]'),
('4f77bfab-8a78-4511-9d2a-bde3770d9712','題縣簿清心亭','鄒極','宋','宋诗','song-poetry','','[]','君向池邊展舊亭，坐臨止水覺心清。',64,'全唐诗/poet.song.53000.json','["君向池邊展舊亭，坐臨止水覺心清。", "暑風菡萏塵難染，霜月蒼烝節更明。", "對酒獨醒公外況，隔牆人語靜中聲。", "誰憐老鳳堪棲棘，夢斷韶音奏九成。"]'),
('849d768f-c45b-4e2c-8dc4-6865cd04dd4c','遊曹山','鄒極','宋','宋诗','song-poetry','','[]','一到重來二紀餘，身閒方悞昔迷途。',64,'全唐诗/poet.song.53000.json','["一到重來二紀餘，身閒方悞昔迷途。", "龍迴澗合木長潤，聖隠巖空峰轉孤。", "自放山林隨處適，相逢雲水有心無。", "野僧見我猶生敬，我即休官祇舊儒。"]'),
('e1e7a866-49cb-4624-ae11-c1e6ae71c3b8','赤松寺書事','鄒極','宋','宋诗','song-poetry','','[]','宅畔池臺景自幽，御風更作赤松遊。',64,'全唐诗/poet.song.53000.json','["宅畔池臺景自幽，御風更作赤松遊。", "嵐光濃麗經梅雨，天氣淒清正麥秋。", "插稻農夫晨赤脚，繅絲蠶婦晝蓬頭。", "閒身免赴公家急，飽食無心爲汝謀。"]'),
('85db1d30-5a12-41ff-bd56-c5d062f4abe9','石䂬潺湲亭','鄒極','宋','宋诗','song-poetry','','[]','危亭跨幽澗，澗水日潺湲。',96,'全唐诗/poet.song.53000.json','["危亭跨幽澗，澗水日潺湲。", "響與鼓鐘應，靜無車馬喧。", "布金因利物，潄玉自澄源。", "練引千尋遠，珠傾萬斛繁。", "倚空橫石壁，夾岸带山樊。", "漲駭天河决，湍流地軸翻。", "僧棲真夢覺，客至滌塵煩。", "不盡登臨意，忘言愧有言。"]'),
('058405ad-54b5-4a0e-8176-cd0fdb7cc960','句  其一','鄒極','宋','宋诗','song-poetry','','[]','願君早作歸來計，同醉園林二十春。',16,'全唐诗/poet.song.53000.json','["願君早作歸來計，同醉園林二十春。"]'),
('a48427f1-e6f4-42d5-b594-3ce61fdedb25','句  其二','鄒極','宋','宋诗','song-poetry','','[]','休緣招隠空生嘆，自是中心悅美官。',16,'全唐诗/poet.song.53000.json','["休緣招隠空生嘆，自是中心悅美官。"]'),
('f2720da4-a1ed-4941-b9a1-83668b37a42b','句  其三','鄒極','宋','宋诗','song-poetry','','[]','如君報國須終老，閒健歸來只一翁。',16,'全唐诗/poet.song.53000.json','["如君報國須終老，閒健歸來只一翁。"]'),
('ea22f98c-2de1-4b7e-8574-7336c03f4568','偈','釋道楷','宋','宋诗','song-poetry','','[]','吾年七十六，世緣今已足。',40,'全唐诗/poet.song.53000.json','["吾年七十六，世緣今已足。", "生不愛天堂，死不怕地獄。", "撒手橫身三界外，騰騰任運何拘束。"]'),
('daf16443-6b03-4589-95a5-c04d92713cb7','妙唱不干舌偈','釋道楷','宋','宋诗','song-poetry','','[]','剎剎塵塵處處譚，不勞禪子善財參。',32,'全唐诗/poet.song.53000.json','["剎剎塵塵處處譚，不勞禪子善財參。", "空生也解通消息，花雨巖前鳥不嗛。"]'),
('dff44438-a7af-4a16-9b63-ade5ca4302f3','死蛇驚出草偈','釋道楷','宋','宋诗','song-poetry','','[]','日炙風吹草裏埋，觸他毒氣又還乖。',32,'全唐诗/poet.song.53000.json','["日炙風吹草裏埋，觸他毒氣又還乖。", "闇地若教開死口，長安依舊絕人來。"]'),
('e6b706b2-00e5-44fd-a1ff-9ca3a26636f0','解針枯骨吟偈','釋道楷','宋','宋诗','song-poetry','','[]','死中活得是非常，密用他家別有長。',32,'全唐诗/poet.song.53000.json','["死中活得是非常，密用他家別有長。", "半夜髑髏吟一曲，冰河紅燄却清凉。"]'),
('9f040a2d-7c71-4e95-98d7-8514edf001e7','鐵鋸和三臺偈','釋道楷','宋','宋诗','song-poetry','','[]','不是宮商調，誰人和一場。',24,'全唐诗/poet.song.53000.json','["不是宮商調，誰人和一場。", "伯牙何所措，此曲舊來長。"]'),
('eb3d3370-6d22-42b5-ba57-c88fa683bed3','古今無間偈','釋道楷','宋','宋诗','song-poetry','','[]','一法元無萬法空，箇中那許悟圓通。',32,'全唐诗/poet.song.53000.json','["一法元無萬法空，箇中那許悟圓通。", "將謂少林消息斷，桃華依舊笑春風。"]'),
('a6aeb337-9929-4e05-9654-1276d564f132','寄伊陽宰韓承議偈  其一','釋道楷','宋','宋诗','song-poetry','','[]','老愛依山人事稀，虎馴庵畔怪來遲。',32,'全唐诗/poet.song.53000.json','["老愛依山人事稀，虎馴庵畔怪來遲。", "寥寥石室塵埃滿，不知何日是歸期。"]'),
('07aeaef3-d097-413d-b1f5-8a089dd5c61a','寄伊陽宰韓承議偈  其二','釋道楷','宋','宋诗','song-poetry','','[]','數里無人到，山黄始覺秋。',24,'全唐诗/poet.song.53000.json','["數里無人到，山黄始覺秋。", "巖間一覺睡，忘却百年憂。"]'),
('b5d1be3d-060d-45bc-8522-9b169634bd12','答僧','釋慶璁','宋','宋诗','song-poetry','','[]','東山西嶺青，雨下却天晴。',24,'全唐诗/poet.song.53000.json','["東山西嶺青，雨下却天晴。", "更問箇中意，鵓鳩生鷂鷹。"]'),
('0b20e586-7bb0-4b44-a0bb-d99a0bedd0b7','頌','釋玄本','宋','宋诗','song-poetry','','[]','看經不識經，徒勞損眼睛。',24,'全唐诗/poet.song.53000.json','["看經不識經，徒勞損眼睛。", "欲得不損眼，分明識取經。"]'),
('a803f095-0504-4ded-91f5-8dd47abd1036','偈','釋覺海','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','碧落靜無雲，秋空月有明。',36,'全唐诗/poet.song.53000.json','["碧落靜無雲，秋空月有明。", "長江瑩如練，清風來不歇。", "林下道人幽，相看情共悅。"]'),
('e7fdc89d-da33-4a40-a9be-81ead4c9b857','偈','釋圓照','宋','宋诗','song-poetry','','[]','片月浸寒潭，微雲滿空碧。',24,'全唐诗/poet.song.53000.json','["片月浸寒潭，微雲滿空碧。", "若於達道人，好箇真消息。"]'),
('97a87b64-58a8-4604-9706-0ac94ac0038e','偈','釋慧通','宋','宋诗','song-poetry','','[]','從無入有易，從有入無難。',36,'全唐诗/poet.song.53000.json','["從無入有易，從有入無難。", "有無俱盡處，且莫自顢頇。", "舉來看，寒山拾得禮豐干。"]'),
('00a611d1-e8bf-4b88-aa9b-56a8d66d8014','偈','釋慧憲','宋','宋诗','song-poetry','','[]','我有一條拄杖，尋常將何比况。',56,'全唐诗/poet.song.53000.json','["我有一條拄杖，尋常將何比况。", "采來不在南山，亦非崑崙西嶂。", "拈起滿目光生，放下驪龍縮項。", "同徒若也借看，卓出人中之上。"]'),
('06067faf-58a5-4494-a245-b0173b16dbcf','偈','釋元善','宋','宋诗','song-poetry','','[]','君問西來意，馬師踏水潦。',48,'全唐诗/poet.song.53000.json','["君問西來意，馬師踏水潦。", "若認一毛頭，何曾知起倒。", "劫火纔洞然，愚夫覓乾草。", "寧知明眼人，爲君長懊惱。"]'),
('3e0d4bee-e5e0-42a2-bf13-0f4c9faed7f0','偈','釋用機','宋','宋诗','song-poetry','','[]','清平過水，投子賣油。',26,'全唐诗/poet.song.53000.json','["清平過水，投子賣油。", "一年三百六十日，不須頻向數中求。"]'),
('0cde7252-5aab-469b-90f7-6ed436a5e72e','辭衆偈','釋法明','宋','宋诗','song-poetry','','[]','平生醉裏顛蹶，醉裏却有分別。',29,'全唐诗/poet.song.53000.json','["平生醉裏顛蹶，醉裏却有分別。", "今宵酒醒何處，楊柳岸曉風殘月。"]'),
('5f8a7006-28fa-450b-9ad1-7cead8f66bb0','偈','釋真覺','宋','宋诗','song-poetry','','[]','善慧遺風五百年，雲黄山色祇依然。',32,'全唐诗/poet.song.53000.json','["善慧遺風五百年，雲黄山色祇依然。", "而今祖令重行也，一句流通徧大千。"]'),
('66b929f3-16b9-4f83-8af6-c9bd2e5812ea','偈  其一','釋祖鏡','宋','宋诗','song-poetry','','[]','蘭芳春谷菊秋籬，物必榮枯各有時。',32,'全唐诗/poet.song.53000.json','["蘭芳春谷菊秋籬，物必榮枯各有時。", "昔毀僧尼專奉道，後平道佞復僧尼。"]'),
('708b9499-e451-4f06-b563-e59d4d6952cc','偈  其二','釋祖鏡','宋','宋诗','song-poetry','','[]','吾頂從來似月圓，雖冠其髮不成仙。',32,'全唐诗/poet.song.53000.json','["吾頂從來似月圓，雖冠其髮不成仙。", "今朝拋下無遮障，放出神光透碧天。"]'),
('de82d759-8518-4a08-982f-5d95528c1420','偈  其三','釋祖鏡','宋','宋诗','song-poetry','','[]','如來昔日貿皮衣，數載慚將鶴氅披。',32,'全唐诗/poet.song.53000.json','["如來昔日貿皮衣，數載慚將鶴氅披。", "還我丈夫調御服，須知此物不相宜。"]'),
('faa84fea-947c-4d12-a61c-894ba5e46b65','偈  其四','釋祖鏡','宋','宋诗','song-poetry','','[]','爲嫌禪板太無端，豈料遭他象簡瞞。',32,'全唐诗/poet.song.53000.json','["爲嫌禪板太無端，豈料遭他象簡瞞。", "今日因何忽放下，普天致仕老仙官。"]'),
('3a0bb8c1-b20e-49cd-a1dd-2db24eff852f','偈  其五','釋祖鏡','宋','宋诗','song-poetry','','[]','達磨携將一隻歸，兒孫從此赤脚走。',48,'全唐诗/poet.song.54000.json','["達磨携將一隻歸，兒孫從此赤脚走。", "借他朱履代麻鞋，休道時難事掣肘。", "化鵬未遇不如鵾，畫虎不成反類狗。"]'),
('d6850e9e-2bdd-4190-a2fe-22498c312ada','偈  其六','釋祖鏡','宋','宋诗','song-poetry','','[]','今朝拄杖化爲龍，分破華山千萬重。',32,'全唐诗/poet.song.54000.json','["今朝拄杖化爲龍，分破華山千萬重。", "珍重佛心真聖主，好將堯德振吾宗。"]'),
('71865a57-92cf-44c1-8750-1fb5128a358d','句','釋祖鏡','宋','宋诗','song-poetry','','[]','一池荷葉衣無盡，數樹松花食有餘。',16,'全唐诗/poet.song.54000.json','["一池荷葉衣無盡，數樹松花食有餘。"]'),
('1bf7eb41-85e8-4481-8397-fe4e4d32cf07','臨終示偈','釋悟新','宋','宋诗','song-poetry','','[]','說時七顛八倒，默時落二落三。',28,'全唐诗/poet.song.54000.json','["說時七顛八倒，默時落二落三。", "爲報五湖禪客，心王自在休參。"]'),
('850ad199-0a22-4580-9b3c-5680e0ffa078','淩雲行','張商英','宋','宋诗','song-poetry','','[]','麻姑何代仙，南城有遺壇。',168,'全唐诗/poet.song.54000.json','["麻姑何代仙，南城有遺壇。", "雙練飛絕巘，天風逼人寒。", "枯螺抱怪石，幾見海水乾。", "清都在何許，烟霧不可干。", "宮闕鏤白玉，輜軿駕朱鸞。", "念非粗濁質，可以超雲端。", "沖虛盡塵滓，變化生羽翰。", "悠悠戚施子，汲汲營餔餐。", "頎然碩且大，軀幹壓馬鞍。", "奉養恐不至，齒髮忽已殘。", "呼吸一時絕，枯骸積巑岏。", "膝行望碧落，霄露零衣冠。", "願聞道之妙，不用擲米丹。", "人間寧足樂，棄去夫何難。"]'),
('1564ef59-f3bf-4eaf-93e4-75f3a48a7931','過梁口','張商英','宋','宋诗','song-poetry','','[]','迢迢一水遶千山，桑柘陰陰聚落寬。',32,'全唐诗/poet.song.54000.json','["迢迢一水遶千山，桑柘陰陰聚落寬。", "好事莫傳江上信，漁樵自不識衣冠。"]'),
('d10c4b96-c61f-43c8-9757-e162fd76d8df','贈玉巖','張商英','宋','宋诗','song-poetry','','[]','四圍岩谷上通天，岩底幽人抱腹眠。',64,'全唐诗/poet.song.54000.json','["四圍岩谷上通天，岩底幽人抱腹眠。", "不羨莊鵬摶九萬，肯隨齊客列三千。", "養成白雪高歌調，散盡黄金有簡編。", "野鹿今朝入城市，爲余有意下林泉。"]'),
('d9a7eff2-5e78-41ff-94dd-d702384a46de','睢陽五老圖','張商英','宋','宋诗','song-poetry','','[]','德政調元向道閒，天朝詔許實辭冠。',64,'全唐诗/poet.song.54000.json','["德政調元向道閒，天朝詔許實辭冠。", "丹心耿耿懸象魏，青史昭昭照玉桓。", "晚節友賢陽鳳暖，老年憂世谷駒寒。", "太平猶自存龜鑑，後進儀刑仰慕看。"]'),
('fa5dd543-af04-4c65-9d6b-cb10ad4ad863','蔣坊寺賜老僧','張商英','宋','宋诗','song-poetry','','[]','九十光陰欠五年，寒灰枯木老雲泉。',64,'全唐诗/poet.song.54000.json','["九十光陰欠五年，寒灰枯木老雲泉。", "眼明尚可穿針鼻，齒硬猶能嚼石蓮。", "疑是合知諸佛印，果然別得一枝禪。", "不因看破真贓物，安得囊中出小編。"]'),
('a9c271a3-0b75-47f9-9780-f174507458f7','香林院','張商英','宋','宋诗','song-poetry','','[]','瑟瑟松上風，冥冥竹間露。',48,'全唐诗/poet.song.54000.json','["瑟瑟松上風，冥冥竹間露。", "窗虛簟色寒，石側蒼苔古。", "長廊寂無人，殿閣下鈴語。", "此意兩蕭然，徘徊不能去。"]'),
('20dad5f2-0b31-4b1b-85a4-2df84e4ae564','金精山留題','張商英','宋','宋诗','song-poetry','','[]','秦亡項滅漢罷兵，分王宗室皆連城。',192,'全唐诗/poet.song.54000.json','["秦亡項滅漢罷兵，分王宗室皆連城。", "西方女子不用事，張氏有婦懷金精。", "吳山之下吳水曲，石鼓峰巒翠相矗。", "山幽水邃閨閣嚴，二八芳年貌如玉。", "吳王聞知心欲狂，珠琲繒纊羅千箱。", "苦憑青翼致消息，陳說富貴誇膏粱。", "玉人冷笑吾當許，汝第爲吾開洞府。", "洞成賦詩悲下土，悲哉下土人皆苦。", "飄飄仙袂淩上蒼，天街昴畢騰輝光。", "使回千里澀進步，目極五雲空斷腸。", "吳王悒悒忽不樂，入顧後宮情索寞。", "仙凡會合竟何年，多謝君王鑿洞天。"]'),
('6d954d7d-140b-4279-aa62-9a745a2bb9f5','孤憤吟二首  其一','張商英','宋','宋诗','song-poetry','','[]','平津諛武帝，堯舜未爲聰。',60,'全唐诗/poet.song.54000.json','["平津諛武帝，堯舜未爲聰。", "歸來東閣士，稱頌比周公。", "勢利變人心，上下交相蒙。", "低顔望眉睫，一喜生春風。", "優游卒茲歲，安知朝野空。"]'),
('d031e920-b416-4f86-8e1a-45acd5a90b9f','孤憤吟二首  其二','張商英','宋','宋诗','song-poetry','','[]','青青一本桑，下可百夫息。',60,'全唐诗/poet.song.54000.json','["青青一本桑，下可百夫息。", "泠泠一井泉，上有千人汲。", "千里以爲郡，百里以爲邑。", "生齒豈不繁，教化繄爾力。", "何事北窗人，歎此徒勞職。"]'),
('08457c1b-3300-4c79-9ca9-246322d9b60f','挽老蘇先生','張商英','宋','宋诗','song-poetry','','[]','近來天下文章格，盡是之人咳唾餘。',64,'全唐诗/poet.song.54000.json','["近來天下文章格，盡是之人咳唾餘。", "方喜丘園空繐帳，何期簫吹咽轜車。", "一生自抱蕭張術，萬古空傳楊孟書。", "大志未酬身已沒，爲君雙淚濕衣裾。"]'),
('9955a0a3-b887-46f1-b924-506dad354eb1','題關公像','張商英','宋','宋诗','song-poetry','','[]','月缺不改光，劍折不改鋩。',48,'全唐诗/poet.song.54000.json','["月缺不改光，劍折不改鋩。", "月缺白易滿，劍折尚带霜。", "勢利尋常事，難屈志士腸。", "男兒有死節，可殺不可量。"]'),
('209a8b23-8733-496b-84af-80368e117a69','護國寺','張商英','宋','宋诗','song-poetry','','[]','薄宦區區可歎嗟，寂寥寒館過村家。',64,'全唐诗/poet.song.54000.json','["薄宦區區可歎嗟，寂寥寒館過村家。", "神錐豈向囊中出，寶劍聊憑醉後誇。", "就祿勉持毛義檄，讀書空滿惠生車。", "掩關不識青春好，一夜狂風已落花。"]'),
('7da4fcc2-6d60-44bf-a6ca-4281941621e9','與劉跛子飲市橋','張商英','宋','宋诗','song-poetry','','[]','遷客湖湘召赴京，輪蹄迎迓一何榮。',32,'全唐诗/poet.song.54000.json','["遷客湖湘召赴京，輪蹄迎迓一何榮。", "爭如與子市橋飲，且免人間寵辱驚。"]'),
('a1214039-d9a3-4cff-963f-34247898bed3','遊天平山','張商英','宋','宋诗','song-poetry','','[]','洞天金闕天平爵，層{山廛}石崖寒玉削。',163,'全唐诗/poet.song.54000.json','["洞天金闕天平爵，層{山廛}石崖寒玉削。", "突兀雲生縹緲間，鬅鬆樹大侵寥廓。", "蒼鹿挨摧北斗魁，耍猿弄損南辰角。", "碑文壓破石鼇頭，琅玕爛折玉兔脚。", "背岩松柏碧森森，向日雜花紅灼灼。", "遮礙林慮半壁天，琢成雲漢千里壑。", "宮宰爐燒延壽香，避秦採得長生藥。", "風物依稀紫府宮，嵐光繚繞朱陵閣。", "路轉樵人目下迷，桃源仙子心無錯。", "千形萬狀天平山，剖判玄黄天地作。"]'),
('e906881a-eaf9-457c-9a24-58df702d808a','題天平山撲豬嶺','張商英','宋','宋诗','song-poetry','','[]','玉皇不禁上天梯，半築臨崖與斗齊。',32,'全唐诗/poet.song.54000.json','["玉皇不禁上天梯，半築臨崖與斗齊。", "昨日我因尋藥到，祇疑驚起日中雞。"]'),
('6adde7bb-0163-4f7b-88ff-bca209a1103d','五臺山','張商英','宋','宋诗','song-poetry','','[]','五頂嵯峨接太虛，就中偏稱我師居。',64,'全唐诗/poet.song.54000.json','["五頂嵯峨接太虛，就中偏稱我師居。", "毒龍池畔雲生早，猛獸巖前客過疏。", "冰雪滿山銀點綴，香花徧地錦舒鋪。", "展開坐具長三尺，方佔山河五百餘。"]'),
('efcbd015-e6ea-4009-972a-5fc8acd46d1e','見山亭','張商英','宋','宋诗','song-poetry','','[]','簾捲疏烟醉眼開，浮雲飛盡見崔嵬。',64,'全唐诗/poet.song.54000.json','["簾捲疏烟醉眼開，浮雲飛盡見崔嵬。", "苦嗟霖雨遮藏久，深謝晴風列致來。", "丹桂有時明月滿，舊山無路白猿哀。", "禪僧指我真空理，心火茫然一夜灰。"]'),
('1f9e40f8-68c2-4dee-b96a-3c0db3ccac7c','遊青原山','張商英','宋','宋诗','song-poetry','','[]','所至紛紛簿領堆，也須風月洗塵埃。',32,'全唐诗/poet.song.54000.json','["所至紛紛簿領堆，也須風月洗塵埃。", "明朝相與尋師去，况是同行掉臂來。"]'),
('3832ce55-8f9c-4b73-bcde-d0ccb1e38f8f','華陽洞','張商英','宋','宋诗','song-poetry','','[]','素虎斑虬躡紫烟，幾看滄海變桑田。',32,'全唐诗/poet.song.54000.json','["素虎斑虬躡紫烟，幾看滄海變桑田。", "赤城玉笥尋真後，又到華陽第八天。"]'),
('c94b80cd-666d-4839-9a69-c9c883515f41','溳陰亭','張商英','宋','宋诗','song-poetry','','[]','駕言晨出溳臺隅，溳上登臨酒拍壺。',32,'全唐诗/poet.song.54000.json','["駕言晨出溳臺隅，溳上登臨酒拍壺。", "不似峴山羊叔子，心隨漢水欲吞吳。"]'),
('767cd507-2677-4eb3-8485-1a32b12b1c7f','東臺','張商英','宋','宋诗','song-poetry','','[]','迢迢雲水涉峰巒，漸覺天低宇宙寬。',64,'全唐诗/poet.song.54000.json','["迢迢雲水涉峰巒，漸覺天低宇宙寬。", "東北分明睹大海，西南咫尺望長安。", "圓光化現珠千顆，聳日初昇火一團。", "風雨每從巖下起，那羅洞裏有龍蟠。"]'),
('0cbe5f9e-6fe4-420d-b980-faf69dfd5b64','南臺','張商英','宋','宋诗','song-poetry','','[]','迢迢策杖上南臺，北望清凉眼豁開。',64,'全唐诗/poet.song.54000.json','["迢迢策杖上南臺，北望清凉眼豁開。", "二片烟霞籠紫府，萬年松徑鎖蒼苔。", "人遊靈境涉溪去，我訪真容踏頂來。", "前後三三知者少，衲僧到此費徘徊。"]'),
('2b2495a8-fd81-4e8b-a3e8-71081fc8b21d','西臺','張商英','宋','宋诗','song-poetry','','[]','寶臺高峻足穹蒼，獅子遺蹤八水傍。',64,'全唐诗/poet.song.54000.json','["寶臺高峻足穹蒼，獅子遺蹤八水傍。", "五色雲中遊上界，九重天外看西方。", "三時雨淚龍宮冷，一夜風飄月桂香。", "土石尚能消罪障，何勞菩薩放神光。"]'),
('cc1a57c6-2a6d-4839-9c3a-a20c31a588ae','北臺','張商英','宋','宋诗','song-poetry','','[]','北臺高峻碧崔嵬，多少遊人到便迴。',64,'全唐诗/poet.song.54000.json','["北臺高峻碧崔嵬，多少遊人到便迴。", "怕見目前生地獄，愁聞耳畔發風雷。", "七星每夜霑峰頂，六出長年積澗隈。", "若遇黑龍靈懆者，人間心念自然灰。"]'),
('319a43af-c101-4035-b805-4f83e84ca509','中臺','張商英','宋','宋诗','song-poetry','','[]','中臺岌岌最堪觀，四面林峰擁翠巒。',64,'全唐诗/poet.song.54000.json','["中臺岌岌最堪觀，四面林峰擁翠巒。", "萬壑松聲心地嚮，數條山色骨毛寒。", "重重燕水東南闊，漠漠黄沙西北寬。", "總信文殊歸向者，大家高步白雲端。"]'),
('849a5629-78f0-42e0-a8bc-4f928c886093','凈明塔','張商英','宋','宋诗','song-poetry','','[]','月滿汾川寶鐸寒，誰來此地葬金棺。',64,'全唐诗/poet.song.54000.json','["月滿汾川寶鐸寒，誰來此地葬金棺。", "育王得道行空際，尊者飛光出指端。", "天上凝雲常覆定，人間劫火漫燒殘。", "三千世界無留跡，聊向閻浮示涅槃。"]'),
('369bf341-b4eb-45c4-94ff-b98d92987888','聖燈','張商英','宋','宋诗','song-poetry','','[]','雲貼西山日出東，一輪明相現雲中。',32,'全唐诗/poet.song.54000.json','["雲貼西山日出東，一輪明相現雲中。", "修行莫道無榜模，只恐修行落斷空。"]'),
('5198f2bc-6df9-4bb8-a972-b842b37080ed','解脫禪師道場','張商英','宋','宋诗','song-poetry','','[]','聖凡路上絕纖痕，解脫文殊各自論。',32,'全唐诗/poet.song.54000.json','["聖凡路上絕纖痕，解脫文殊各自論。", "東土西天無着處，佛光山下一龕存。"]'),
('2d53b129-d4ef-4731-b595-ef7a49fb6000','秘魔巖','張商英','宋','宋诗','song-poetry','','[]','閱盡龍宮五百函，三年不下秘魔巖。',32,'全唐诗/poet.song.54000.json','["閱盡龍宮五百函，三年不下秘魔巖。", "須知別有安身處，脫却如來鶻臭衫。"]'),
('7152d717-3be3-4bb6-a077-7f383abbb183','宋老生殉難詩','張商英','宋','宋诗','song-poetry','','[]','血戰保孤城，嗟哉宋老生。',48,'全唐诗/poet.song.54000.json','["血戰保孤城，嗟哉宋老生。", "身甘殉隋難，義不屈唐兵。", "骨已塵埃盡，光猶日月爭。", "裴劉等死耳，誰重復誰輕。"]'),
('f830d100-cfcf-4a38-a46f-ad7a16c3a9d0','和前韵','張商英','宋','宋诗','song-poetry','','[]','東湖水落露堤沙，舟過湖心藻荇斜。',64,'全唐诗/poet.song.54000.json','["東湖水落露堤沙，舟過湖心藻荇斜。", "野逕小橋穿竹巷，烟村疏柳間蘆花。", "新秔炊熟胭脂白，活鯽珍於丙穴嘉。", "飲散肩輿乘皓月，燭籠何用兩行紗。"]'),
('1824761a-35f7-434d-8ce5-4c7c628f26de','贈博士承議','張商英','宋','宋诗','song-poetry','','[]','南歸遷客氣平和，磊落胸中所得多。',64,'全唐诗/poet.song.54000.json','["南歸遷客氣平和，磊落胸中所得多。", "白日過從唯陸諝，清宵夢想適維摩。", "裴徊未忍捐雞肋，寂寞猶能顧雀羅。", "好與鄉人敦薄俗，莫因哺啜負岷峨。"]'),
('fe16212e-c48e-499d-ab95-49afe9dfe412','和孫右司沅州道上過元夕','張商英','宋','宋诗','song-poetry','','[]','三五皇州夜色鮮，使車方事武陵蠻。',64,'全唐诗/poet.song.54000.json','["三五皇州夜色鮮，使車方事武陵蠻。", "華燈邈想端門外，翠輦初臨太一還。", "月滿九衢聞舜樂，雲開雙闕見堯顔。", "自憐風雨新城道，陟彼崔嵬我馬艱。"]'),
('3a5d6d3b-4e5c-4a6a-947a-b133e509cb06','平陽道中過上元','張商英','宋','宋诗','song-poetry','','[]','元夕吾何處，吾行次晉郊。',48,'全唐诗/poet.song.54000.json','["元夕吾何處，吾行次晉郊。", "樂棚垂葦席，燈柱縛松梢。", "俚婦朱雙臉，村夫赤兩骹。", "春田誇積雪，酒膽醉仍杪。"]'),
('89ba3464-b45a-4556-893a-22a52edc93fb','上元秭歸溪西社火點燈  其一','張商英','宋','宋诗','song-poetry','','[]','百丈遊燈遶石坡，溪西保社事黄魔。',32,'全唐诗/poet.song.54000.json','["百丈遊燈遶石坡，溪西保社事黄魔。", "草花灼灼迎新福，腰鼓鼕鼕踏舊歌。"]'),
('df3e9f05-10e5-450b-ac5c-16527f1788f5','上元秭歸溪西社火點燈  其二','張商英','宋','宋诗','song-poetry','','[]','溪西燈社寶蓮臺，一點光明遠更開。',32,'全唐诗/poet.song.54000.json','["溪西燈社寶蓮臺，一點光明遠更開。", "料得長楊宮裏見，却疑仙火下雲來。"]'),
('b04fcd82-3473-4825-8d2f-328850c48788','和劉尉赤岸上巳  其一','張商英','宋','宋诗','song-poetry','','[]','教池天氣不勝情，携手聊同陌上行。',64,'全唐诗/poet.song.54000.json','["教池天氣不勝情，携手聊同陌上行。", "洛禊嬉遊修故事，楚歌歡笑集村氓。", "慕潘珍果盈車擲，挑卓幽琴滿座傾。", "爲報蘭亭王逸少，且無今日管弦聲。"]'),
('e820663a-64b9-472a-be41-efbcdee8ce2c','和劉尉赤岸上巳  其二','張商英','宋','宋诗','song-poetry','','[]','采蘭時節近清明，朝野歡娛值太平。',64,'全唐诗/poet.song.54000.json','["采蘭時節近清明，朝野歡娛值太平。", "坦率從來如庾亮，窮愁素不學虞卿。", "三年陽渚成何事，一覺邯鄲悟此生。", "把酒花前須醉倒，肯教風雨落繁英。"]'),
('05e74226-c12a-4459-a0a7-445b41cf28ad','上巳艤舟漢口命駕鳳栖成二絕句  其一','張商英','宋','宋诗','song-poetry','','[]','上巳嬉游集漢陽，雲收雨霽日舒光。',32,'全唐诗/poet.song.54000.json','["上巳嬉游集漢陽，雲收雨霽日舒光。", "瑞烟和氣橫寥廓，何用蘭亭祓不祥。"]'),
('e59a4b72-7e20-45a0-bc68-bb2006091174','上巳艤舟漢口命駕鳳栖成二絕句  其二','張商英','宋','宋诗','song-poetry','','[]','池上澄輝凍已銷，陽和巧思著花梢。',32,'全唐诗/poet.song.54000.json','["池上澄輝凍已銷，陽和巧思著花梢。", "殘雲斷靄歸何處，翠幰紅帷遍樂郊。"]'),
('1711fe32-544a-4dc1-b73c-8b35718226bd','競渡','張商英','宋','宋诗','song-poetry','','[]','龍舟鼓笛和吳歌，采索纏筒弔汨羅。',32,'全唐诗/poet.song.54000.json','["龍舟鼓笛和吳歌，采索纏筒弔汨羅。", "文腿千人齊舉棹，豈知湖海有風波。"]'),
('b510769f-e09e-4c5e-aeec-c31fdeec52c1','端午偶題','張商英','宋','宋诗','song-poetry','','[]','孤忠不屈赴湘流，甘與干逢地下遊。',32,'全唐诗/poet.song.54000.json','["孤忠不屈赴湘流，甘與干逢地下遊。", "若共蛟龍爭口食，何如附會楚王休。"]'),
('09a5c582-af3d-491e-8b38-501b47d536ab','端午獻扇','張商英','宋','宋诗','song-poetry','','[]','紈扇新成獻乃翁，草堂虛寂起清風。',32,'全唐诗/poet.song.54000.json','["紈扇新成獻乃翁，草堂虛寂起清風。", "欲知妙用真無有，不離而今掌握中。"]'),
('d8ad7b92-12f3-4c6d-86aa-17138e4bdbb7','端午同子宣平嵐榭晚酌望南山而有作','張商英','宋','宋诗','song-poetry','','[]','相見常嗟相聚稀，平嵐危榭對斜暉。',64,'全唐诗/poet.song.54000.json','["相見常嗟相聚稀，平嵐危榭對斜暉。", "牛羊遍野草初綠，槐柳成陰春已歸。", "頂上緋生麋角解，嘴邊黄盡燕初飛。", "白頭共作天涯客，幾向南山詠式微。"]'),
('e46bc0a5-dd84-4f8b-bdda-5868c2a7762b','立秋會監司','張商英','宋','宋诗','song-poetry','','[]','片葉飛空忽報秋，玉醅浮蟻恰新篘。',32,'全唐诗/poet.song.54000.json','["片葉飛空忽報秋，玉醅浮蟻恰新篘。", "相逢昂飲聊乘興，萬事從它一日休。"]'),
('6668f45a-fba6-4d2b-b2b5-828b59c34204','跋胡德林七夕','張商英','宋','宋诗','song-poetry','','[]','鼓盆新恨度良宵，悵望仙娥未見邀。',32,'全唐诗/poet.song.54000.json','["鼓盆新恨度良宵，悵望仙娥未見邀。", "會取天河離合意，何曾靈鵲久成橋。"]'),
('38b3e696-41e6-4bf2-b53a-e3d33c85f1c4','中秋夜寄克道運使','張商英','宋','宋诗','song-poetry','','[]','不見柯山客，中秋月又圓。',48,'全唐诗/poet.song.54000.json','["不見柯山客，中秋月又圓。", "夜分清滴露，天末淡收烟。", "念遠情非俗，凌虛骨欲仙。", "素琴明此恨，相與對嬋娟。"]'),
('d2f603f0-f0e1-45a5-afa3-5ff9d9bc081c','進賀冬至','張商英','宋','宋诗','song-poetry','','[]','燭滿天街曉漏長，杜門牢落歎臺綱。',64,'全唐诗/poet.song.54000.json','["燭滿天街曉漏長，杜門牢落歎臺綱。", "金吾六卒閑私第，玉笋千官守未央。", "五貴訏謨恩盜賊，一朝新事劾風霜。", "堯天咫尺橫雲霧，遙慶南山萬壽觴。"]'),
('63093ba9-d716-461d-bae4-279d0216bd20','偈一首','張商英','宋','宋诗','song-poetry','','[]','五老機緣共一方，神鋒各向袖中藏。',32,'全唐诗/poet.song.54000.json','["五老機緣共一方，神鋒各向袖中藏。", "明朝老將登壇看，便請橫矛戰一場。"]'),
('1c4dedfc-9eb3-41fb-b844-23378f2dbee5','頌一首','張商英','宋','宋诗','song-poetry','','[]','鼓寂鍾沉托鉢回，巖頭一拶語如雷。',32,'全唐诗/poet.song.54000.json','["鼓寂鍾沉托鉢回，巖頭一拶語如雷。", "果然只得三年活，莫是遭他受記來。"]'),
('9d373db0-4445-478d-a38c-15d05f1daf97','詩一首','張商英','宋','宋诗','song-poetry','','[]','野僧迎客下烟嵐，試問如何是翠巖。',32,'全唐诗/poet.song.54000.json','["野僧迎客下烟嵐，試問如何是翠巖。", "門近洪崖千尺井，石橋分水繞松杉。"]'),
('a0de7499-90a7-418a-bfe2-51c8d9bd6cd5','題真浄肖像','張商英','宋','宋诗','song-poetry','','[]','雲庵綱宗，能用能照。',40,'全唐诗/poet.song.54000.json','["雲庵綱宗，能用能照。", "冷面嚴眸，神光獨耀。", "孰傳其旨，覿露唯肖。", "前悅後洪，如融如肇。"]'),
('ba238289-a099-42e4-98b1-79d3dcbcfdb0','偈二首  其一','張商英','宋','宋诗','song-poetry','','[]','亂雲堆裏數峰高，絕學高人此遯逃。',32,'全唐诗/poet.song.54000.json','["亂雲堆裏數峰高，絕學高人此遯逃。", "無奈俗官尋住處，前驅一喝散猿猱。"]'),
('1de8229c-02fa-4fe2-9a6e-b4e56e278e5d','偈二首  其二','張商英','宋','宋诗','song-poetry','','[]','久嚮黄龍山裏龍，到來只見住山翁。',32,'全唐诗/poet.song.54000.json','["久嚮黄龍山裏龍，到來只見住山翁。", "須是背觸拳頭外，別有靈犀一點通。"]'),
('751f249d-7b4f-41c3-9b3e-95f303e042fc','雪','張商英','宋','宋诗','song-poetry','','[]','六出飄蕭萬瓦乾，冰壺天地不容看。',48,'全唐诗/poet.song.54000.json','["六出飄蕭萬瓦乾，冰壺天地不容看。", "金門賀客螭頭冷，草閣吟終粟瓦寒。", "故人家在西溪上，欲叩柴門興已闌。"]'),
('5295c346-3834-4279-8ed5-5f5ececb4442','神仙','張商英','宋','宋诗','song-poetry','','[]','土木形容殷七七，水雲情性許閒閒。',32,'全唐诗/poet.song.54000.json','["土木形容殷七七，水雲情性許閒閒。", "身中火棗無人會，此藥元來便駐顔。"]'),
('afef10a6-e4c9-4ff0-9ac4-d67af99257a3','涪州','張商英','宋','宋诗','song-poetry','','[]','瘴地風雲早，溫天氣候催。',24,'全唐诗/poet.song.54000.json','["瘴地風雲早，溫天氣候催。", "窮冬不見雪，正月已聞雷。"]'),
('2e873fca-0515-4235-94e5-5e462aadeeb5','詠戲仙亭','張商英','宋','宋诗','song-poetry','','[]','濃洄江水瀉高灘，中有神龍久屈蟠。',64,'全唐诗/poet.song.54000.json','["濃洄江水瀉高灘，中有神龍久屈蟠。", "衆樂妙音時響亮，雙娃長袖忽闌珊。", "世間變化無非幻，閣上登臨正好歡。", "觀幻見真真亦幻，谷花巖草謾凭闌。"]'),
('2d04308f-1706-4854-be7d-fe7a2c0f1679','貓','張商英','宋','宋诗','song-poetry','','[]','白玉狻猊藉錦茵，寫經湖上凈名軒。',64,'全唐诗/poet.song.54000.json','["白玉狻猊藉錦茵，寫經湖上凈名軒。", "吾方大謬求前定，爾亦何知不少喧。", "出沒任從倉內鼠，鑽窺寧似檻中猿。", "高眠永日長相對，更約冬裘共足溫。"]'),
('65e39ebb-5786-4f2e-b0d1-324590e46e10','賦新繁周表權如詔亭','張商英','宋','宋诗','song-poetry','','[]','烏犀解軸黄金裝，吳綾蜀錦鸞鳳翔。',144,'全唐诗/poet.song.54000.json','["烏犀解軸黄金裝，吳綾蜀錦鸞鳳翔。", "歐虞飛毫灑中詔，帝曰咨汝田曹郎。", "汝能教子以義方，濟濟來仕吾國光。", "賁汝爵秩及身章，潜德晦耀吾豈忘。", "田曹有亭在繁上，舊以義方揭亭榜。", "安知教子三千年，契合前言被天奬。", "翰林爲易如詔名，春入丘園添氣象。", "里老來觀歸責兒，急尋字解治王詩。", "綵衣朱旛典便郡，簡池太守真汝師。"]'),
('3e3b598b-4330-4f38-b1e6-3044649433d0','朱涇船子禪師','張商英','宋','宋诗','song-poetry','','[]','蘆葦蕭蕭江岸秋，長天獨月向西流。',32,'全唐诗/poet.song.54000.json','["蘆葦蕭蕭江岸秋，長天獨月向西流。", "離鈎三寸無人道，笑倚蘭橈自點頭。"]'),
('b2ed38a4-61aa-4f7d-b195-af85b8fcbbd4','四賢堂','張商英','宋','宋诗','song-poetry','','[]','文昭文定與文忠，內翰元之共四公。',64,'全唐诗/poet.song.54000.json','["文昭文定與文忠，內翰元之共四公。", "政事風流俱第一，典刑人物更誰同。", "能詩只有東坡老，到處唯尋六一翁。", "欲遣滁陽招作客，五星同聚此堂中。"]'),
('3ba21a67-6090-49fb-ab51-8ff290f8a29c','江陵','張商英','宋','宋诗','song-poetry','','[]','地連雲夢水無邊，天斷夷陵欲盡山。',32,'全唐诗/poet.song.54000.json','["地連雲夢水無邊，天斷夷陵欲盡山。", "曾是劉虬高飲地，不知何處扣玄關。"]'),
('a9698361-b9d4-41d2-8b33-1a4fb9a6de35','吳孟宗','張商英','宋','宋诗','song-poetry','','[]','孟宗泣竹冬笋生，豈是青青竹有情。',32,'全唐诗/poet.song.54000.json','["孟宗泣竹冬笋生，豈是青青竹有情。", "大抵主張非有物，人心但莫負幽明。"]'),
('5b00f0e8-44cf-4472-8c36-012bd7668e1f','靈泉寺著華嚴合論作','張商英','宋','宋诗','song-poetry','','[]','合論流通七卷經，點教開眼示群生。',32,'全唐诗/poet.song.54000.json','["合論流通七卷經，點教開眼示群生。", "不須天女添瓶水，自有靈泉一派清。"]'),
('a573c066-c56d-4355-96da-472f6abfa3c9','歸州','張商英','宋','宋诗','song-poetry','','[]','歸州男子屈靈均，歸鄉女兒王昭君。',64,'全唐诗/poet.song.54000.json','["歸州男子屈靈均，歸鄉女兒王昭君。", "山窮林薄不肥沃，生爾才貌空絕群。", "男爲逐臣沉湘水，女嫁穹廬夫萬里。", "漢宮無色楚無人，醜陋險邪君自喜。"]'),
('9d22219a-4279-4af3-922a-623782742bcd','秭歸  其一','張商英','宋','宋诗','song-poetry','','[]','亂石烏牛伏，驚濤白馬奔。',24,'全唐诗/poet.song.54000.json','["亂石烏牛伏，驚濤白馬奔。", "大家齊拭目，看我過龍門。"]'),
('1e6a344f-9b9d-45fd-b28d-ce0b5cce6c3c','秭歸  其二','張商英','宋','宋诗','song-poetry','','[]','驚心烏石蓮花淖，過眼黄牛竹節灘。',32,'全唐诗/poet.song.54000.json','["驚心烏石蓮花淖，過眼黄牛竹節灘。", "征棹直從中溜去，好山只得片時看。"]'),
('23f453a3-6f7f-40e6-88ed-ea88e1886b32','秋興亭','張商英','宋','宋诗','song-poetry','','[]','風送片帆來北客，霜凋萬木見東州。',32,'全唐诗/poet.song.54000.json','["風送片帆來北客，霜凋萬木見東州。", "湖光碧湛郎官水，葦岸黄深鸚鵡洲。"]'),
('83f5aef0-694f-4c92-bf92-496cfec74e1a','南峰寺','張商英','宋','宋诗','song-poetry','','[]','寺據南峰頂，僧傳北祖禪。',48,'全唐诗/poet.song.54000.json','["寺據南峰頂，僧傳北祖禪。", "孤雲飛遠嶠，落日滿平川。", "法界窮三大，河山遍大千。", "香燈方丈小，又結一來緣。"]'),
('db9358d1-0d99-42e5-949c-50a43e1a8ac0','擬峴亭','張商英','宋','宋诗','song-poetry','','[]','英雄往事堪歎息，欄干徙倚情何極。',32,'全唐诗/poet.song.54000.json','["英雄往事堪歎息，欄干徙倚情何極。", "學取山翁醉似泥，不同羊祜謀人國。"]'),
('5f5fd405-86ee-4568-abc8-a63a5467a5de','讀書燈','張商英','宋','宋诗','song-poetry','','[]','小籠疏四面，明紙罩孤燈。',48,'全唐诗/poet.song.54000.json','["小籠疏四面，明紙罩孤燈。", "自小共寒熱，相親如友朋。", "舊書曾遞照，新燭莫相憎。", "幾爲吟詩苦，留光到夙興。"]'),
('394e8e05-8c0d-47da-b0d4-7b22b669d63c','七夕歌','張商英','宋','宋诗','song-poetry','','[]','河東美人天帝子，機杼年年勞玉指。',80,'全唐诗/poet.song.54000.json','["河東美人天帝子，機杼年年勞玉指。", "織成雲霧紫綃衣，辛苦無懽容不理。", "帝憐獨居無與娛，河西嫁得牽牛夫。", "貪懽不歸天帝怒，謫歸却踏來時路。", "但令一歲一相逢，七月七日橋邊渡。"]'),
('7971e4a0-f723-48a8-b280-12c73cd43c79','頌一首','張商英','宋','宋诗','song-poetry','','[]','馬師一喝大雄峰，深入髑髏三日聾。',32,'全唐诗/poet.song.54000.json','["馬師一喝大雄峰，深入髑髏三日聾。", "黄蘗聞之驚吐舌，江西從此立宗風。"]'),
('853a624e-2309-423c-b03e-9659913d304d','答平禪師','張商英','宋','宋诗','song-poetry','','[]','吐舌耳聾師已曉，搥胸祇得哭蒼天。',32,'全唐诗/poet.song.54000.json','["吐舌耳聾師已曉，搥胸祇得哭蒼天。", "盤山會裏翻筋斗，到此方知普化顛。"]'),
('1542c424-6cd4-49f2-a4e0-d124263849ad','牡丹','張商英','宋','宋诗','song-poetry','','[]','落日賓朋醉帽斜，笙歌一曲上雲車。',32,'全唐诗/poet.song.54000.json','["落日賓朋醉帽斜，笙歌一曲上雲車。", "頗知春色隨軒去，不見東庵滿檻花。"]'),
('543abb04-366e-447d-abfe-d8e1db633f3d','龍眼','張商英','宋','宋诗','song-poetry','','[]','托根初不異南山，十八妖嬈带渥丹。',48,'全唐诗/poet.song.54000.json','["托根初不異南山，十八妖嬈带渥丹。", "玉潤滿苞甘露浥，文綃團蹙絳紗丸。", "便爲仙苑千年果，回笑幽皋九畹蘭。"]'),
('8f00a70a-1e91-4601-80cb-adfc75f5544b','笋二首  其一','張商英','宋','宋诗','song-poetry','','[]','臥病十餘日，不見西軒竹。',24,'全唐诗/poet.song.54000.json','["臥病十餘日，不見西軒竹。", "稚子忽報言，新笋抽五六。"]'),
('22608071-8b8d-4d8f-a6cb-bd2ba18faf73','笋二首  其二','張商英','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江縈繞地膏腴，風氣相連不甚殊。',32,'全唐诗/poet.song.54000.json','["長江縈繞地膏腴，風氣相連不甚殊。", "自是苦根分彼此，致令苦笋勝宜都。"]'),
('f9fabb72-eb0d-48d5-a7b8-bd658f8278f2','苦根','張商英','宋','宋诗','song-poetry','','[]','壑源山勢上連雲，合占南州第一春。',32,'全唐诗/poet.song.54000.json','["壑源山勢上連雲，合占南州第一春。", "自有化工鍾粹氣，時生靈葉奉嚴宸。"]'),
('7dcc2a5d-bd73-4e34-8298-00eb3868f481','銀杏','張商英','宋','宋诗','song-poetry','','[]','鴨脚半熟色猶青，紗囊馳寄江陵城。',48,'全唐诗/poet.song.54000.json','["鴨脚半熟色猶青，紗囊馳寄江陵城。", "城中朱門翰林宅，清風六月吹簾旌。", "玉纖雪椀白相照，爛銀殻破玻璃明。"]'),
('b8d5c143-8ef1-4602-b20b-82881cd501b5','跋王荆公題燕侍郎山水圖','張商英','宋','宋诗','song-poetry','','[]','相君開卷憶江東，彷彿鍾山與此同。',32,'全唐诗/poet.song.54000.json','["相君開卷憶江東，彷彿鍾山與此同。", "今日還爲一居士，翛然身在畫圖中。"]'),
('692bbade-75b3-4ae7-b8b8-abbc10bc35bf','留題慧山寺','張商英','宋','宋诗','song-poetry','','[]','咸陽獲重之明年，五月端午予泛船。',160,'全唐诗/poet.song.54000.json','["咸陽獲重之明年，五月端午予泛船。", "二閘新成洞常潤，組練直貫吳松川。", "淮南柁師初入浙，借問邑里猶茫然。", "茶經舊說慧山泉，海內知名五十年。", "今日親來酌泉水，一見信異傳聞千。", "置茶適自建安到，青杯石臼相爭先。", "輾羅萬過玉泥膩，小瓶蟹眼湯正煎。", "乳頭雲脚蓋盞面，吸嗅入鼻消睡眠。", "滌釜操壺貯甘液，緘題遠寄朱門宅。", "仙人見水是瑠璃，乃知陸羽非凡客。"]'),
('9a926b50-ea0c-4819-81c5-e11661a7b574','題風水洞','張商英','宋','宋诗','song-poetry','','[]','嶺頭松竹自生寒，兩穴茫茫徹鬼關。',64,'全唐诗/poet.song.54000.json','["嶺頭松竹自生寒，兩穴茫茫徹鬼關。", "風竊虎威時弄草，泉欺龍睡故離山。", "不嫌淅瀝驚塵耳，聊挹清冷洗病顔。", "窗外月高湘簟冷，更無閒夢到人間。"]'),
('7abd1385-5c48-42a1-b1e6-6a581f196cdc','題太平興龍寺','張商英','宋','宋诗','song-poetry','','[]','蕩蕩東風着物華，渡江初喜絕塵沙。',64,'全唐诗/poet.song.54000.json','["蕩蕩東風着物華，渡江初喜絕塵沙。", "蔽空杉徑四百里，在處旗亭三五家。", "山葉半青茶未過，水畦漫白稻初芽。", "慇懃說似潭園侶，南北隨鄉不是誇。"]'),
('03fb7be5-2581-4f1a-9884-202f94b972a6','乾明寺','張商英','宋','宋诗','song-poetry','','[]','隔垣禪律兩招提，却是人心咫尺迷。',32,'全唐诗/poet.song.54000.json','["隔垣禪律兩招提，却是人心咫尺迷。", "百億須彌四天下，憑君爲我指東西。"]'),
('90bfe9fb-e9f1-4413-86a1-278def7e604b','贊喻彌陀畫丈六佛','張商英','宋','宋诗','song-poetry','','[]','丈六金身，毫端三昧。',66,'全唐诗/poet.song.54000.json','["丈六金身，毫端三昧。", "精妙入神，充滿法界。", "善知衆藝，得大自在。", "游戲神通，一切無礙。", "恒河沙劫，金剛不壞。", "萬象森羅影現中，一顆圓光非內外。"]'),
('ca63062d-dc78-42c8-accf-ece572c50314','臨終偈','張商英','宋','宋诗','song-poetry','','[]','幻質朝章八十一，漚生漚滅誰人識。',32,'全唐诗/poet.song.54000.json','["幻質朝章八十一，漚生漚滅誰人識。", "撞破虛空歸去來，鐵牛入海無消息。"]'),
('68c568e1-66e2-41fe-bc65-be3cdc68fb7d','頭陀巖','張商英','宋','宋诗','song-poetry','','[]','半間囗室安禪地，蓋代功名不易磨。',32,'全唐诗/poet.song.54000.json','["半間囗室安禪地，蓋代功名不易磨。", "白囗老龍歸海去，巖中留得老頭陀。"]'),
('fc269abf-e9b4-43b8-bfab-0bdb0906f263','進仰山瑞禾詩宋大雅十三章  其一','張商英','宋','宋诗','song-poetry','','[]','彼修者禾，其穗七兮。',20,'全唐诗/poet.song.54000.json','["彼修者禾，其穗七兮。", "夐古所無，今感格兮。"]'),
('46fc953d-1185-419b-b9a9-1c2a7defb0bf','進仰山瑞禾詩宋大雅十三章  其二','張商英','宋','宋诗','song-poetry','','[]','歲在庚辰，利見大人。',40,'全唐诗/poet.song.54000.json','["歲在庚辰，利見大人。", "十有二祀，而紀庚寅。", "乾坤六子，遇庚則新。", "大人法天，有革有因。"]'),
('b4784922-8313-400a-85d2-52ea6c3abdf6','進仰山瑞禾詩宋大雅十三章  其三','張商英','宋','宋诗','song-poetry','','[]','皇帝孝仁，羹牆神考。',40,'全唐诗/poet.song.54000.json','["皇帝孝仁，羹牆神考。", "遹追先猷，三代之道。", "炳然規模，百世之寶。", "敢弗祇從，率意改造。"]'),
('aafbd925-4f89-4488-a0c6-d8b296da6c9b','進仰山瑞禾詩宋大雅十三章  其四','張商英','宋','宋诗','song-poetry','','[]','蔽自淵衷，恪遵熙豐。',20,'全唐诗/poet.song.54000.json','["蔽自淵衷，恪遵熙豐。", "法非補完，熙豐是同。"]'),
('33848f41-bb6e-4c2e-8cea-0f459bbe4cc2','進仰山瑞禾詩宋大雅十三章  其五','張商英','宋','宋诗','song-poetry','','[]','乃戢干戈，不勤遠略。',40,'全唐诗/poet.song.54000.json','["乃戢干戈，不勤遠略。", "煩斂是蠲，冗官是削。", "屏斥浮虛，尊敦儉樸。", "舳艫尾銜，泝流通洛。"]'),
('9fd848c2-9deb-4727-a5af-26510e3a060f','進仰山瑞禾詩宋大雅十三章  其六','張商英','宋','宋诗','song-poetry','','[]','泉幣既平，商旅雲行。',20,'全唐诗/poet.song.54000.json','["泉幣既平，商旅雲行。", "四民樂化，迭爲重輕。"]'),
('72e6fdac-7ea4-4959-a97f-23d3b57ded94','進仰山瑞禾詩宋大雅十三章  其七','張商英','宋','宋诗','song-poetry','','[]','乃疏禁網，及釋青枉。',40,'全唐诗/poet.song.54000.json','["乃疏禁網，及釋青枉。", "流徒賜還，鹿解禽放。", "戴恩和順，涵泳曠蕩。", "父子怡怡，朋友交餉。"]'),
('174d120a-ba9f-482e-b86d-e049ffc5db6e','進仰山瑞禾詩宋大雅十三章  其八','張商英','宋','宋诗','song-poetry','','[]','百度孔修，德澤滂流。',40,'全唐诗/poet.song.54000.json','["百度孔修，德澤滂流。", "官知奉法，吏畏納賕。", "農夫熙熙，服我先疇。", "桴鼓不鳴，奠枕靡憂。"]'),
('caf552ab-8a79-4a19-a54f-6b3b6c798f50','進仰山瑞禾詩宋大雅十三章  其九','張商英','宋','宋诗','song-poetry','','[]','職是善化，有赫臨下。',40,'全唐诗/poet.song.54000.json','["職是善化，有赫臨下。", "陰陽泰通，薰蒸陶冶。", "惠兩柔風，太和塞野。", "滲漉百嘉，芃芃禾稼。"]'),
('c413a1b2-20ad-4618-bbc9-3f0dd55f756a','進仰山瑞禾詩宋大雅十三章  其一○','張商英','宋','宋诗','song-poetry','','[]','帝宅中天，何知其然。',40,'全唐诗/poet.song.54000.json','["帝宅中天，何知其然。", "四方郡國，咸奏豐年。", "豐年之象，何以昭宣。", "爰有異粟，八節如鞭。"]'),
('768774fd-4d62-4d5a-b77c-1ed8d773bbb4','進仰山瑞禾詩宋大雅十三章  其一一','張商英','宋','宋诗','song-poetry','','[]','一本之上，雙莖相向。',20,'全唐诗/poet.song.54000.json','["一本之上，雙莖相向。", "穗葉敷榮，挺拔尋丈。"]'),
('ebdbbedb-7b39-4ab4-81fd-c40cbc22bda9','進仰山瑞禾詩宋大雅十三章  其一二','張商英','宋','宋诗','song-poetry','','[]','高而不危，神力扶持。',20,'全唐诗/poet.song.54000.json','["高而不危，神力扶持。", "同而能異，濟物是宜。"]'),
('1090b4d1-6b9f-4452-88c3-b9376cd166d7','進仰山瑞禾詩宋大雅十三章  其一三','張商英','宋','宋诗','song-poetry','','[]','彼修者禾，其實駢羅。',20,'全唐诗/poet.song.54000.json','["彼修者禾，其實駢羅。", "天子萬年，本枝蕃多。"]'),
('0a5ff02e-ba2a-425d-8224-ab3f6fcadd34','濮公山','張商英','宋','宋诗','song-poetry','','[]','野陂衰草接荒城，千里浮光點太清。',64,'全唐诗/poet.song.54000.json','["野陂衰草接荒城，千里浮光點太清。", "不與衆山爲伴侶，自然八面露崢嶸。", "偶因仕宦身來到，漸遠塵埃眼更明。", "問道膝行無處所，渡頭新月小舟橫。"]'),
('60f04cd2-d735-4e51-91dd-9967710a0954','青原山七祖塔','張商英','宋','宋诗','song-poetry','','[]','一派青原出少林，信衣到此只傳心。',32,'全唐诗/poet.song.54000.json','["一派青原出少林，信衣到此只傳心。", "尋常示衆無人會，盡向廬陵米價尋。"]'),
('58c50e62-e54a-42ee-af1b-d76ec8f28c94','望仙曲','張商英','宋','宋诗','song-poetry','','[]','麻姑王蔡迹已往，望仙亭在孤峰上。',104,'全唐诗/poet.song.54000.json','["麻姑王蔡迹已往，望仙亭在孤峰上。", "朝見五雲飛，暮見五雲歸。", "雲飛雲歸自今古，仙來仙去誰可知。", "勿望仙，望仙目眩徒茫然。", "白石可煮誰能言，不愛插翼沖青天。", "玉池且酌太和酒，一醉壽同天地久。", "陶陶與物任浮沉，肯顧霞衣雲組綬。"]'),
('2040a6b0-a330-43c5-9870-bf3631187e5a','過新城院','張商英','宋','宋诗','song-poetry','','[]','昔讀旴川集，嘗聞泰伯賢。',48,'全唐诗/poet.song.54000.json','["昔讀旴川集，嘗聞泰伯賢。", "新城文刻在，往事野僧傳。", "氣格終驚俗，光芒合貫天。", "田翁不知價，只得十千錢。"]'),
('4054dcae-3cd5-4baf-9a96-6f3a6b99845d','蛇谷道中聞杜宇','張商英','宋','宋诗','song-poetry','','[]','高杉何亭亭，北接岢嵐山。',96,'全唐诗/poet.song.54000.json','["高杉何亭亭，北接岢嵐山。", "如何蜀杜宇，飛鳴來此間。", "羽翼誤爾身，浩蕩迷鄉關。", "日長岩谷迥，口角流朱殷。", "我亦有先廬，三峨出塵寰。", "別來二十年，仕宦髮欲斑。", "豈不懷西歸，青葱映潺湲。", "有翼尚飄泊，無翼何時還。"]'),
('288f5c1d-31fd-4566-ad2f-9440640ccec8','題介公廟','張商英','宋','宋诗','song-poetry','','[]','十九年從晉重耳，艱棘憂危同踐履。',160,'全唐诗/poet.song.54000.json','["十九年從晉重耳，艱棘憂危同踐履。", "田中乞食桑下謀，繭足周旋垂萬里。", "一心奉事不自欺，逆知天意開公子。", "及河忽聞舅犯言，如以朝衣蹈泥滓。", "鄙夫豈可與同行，携母入山甘隠藏。", "公子歸來霸業强，築壇踐土尊天王。", "大夫卿士環佩鏘，斬袪寺人紛頡頏。", "念子昔者皆奔亡，舍我長逝情怛傷。", "大蒐縱火焚山岡，烈焰不肯回剛腸。", "嗟乎義士不可量，何人謬作龍蛇章。"]'),
('3add19a9-72b2-407d-ad4e-e0756e84af10','高光堡道中','張商英','宋','宋诗','song-poetry','','[]','故碾迎朝日，高光眩晚霞。',48,'全唐诗/poet.song.54000.json','["故碾迎朝日，高光眩晚霞。", "峰巒成地勢，桑柘似人家。", "柳葉依牆密，溪流刷石斜。", "土氓尊使者，再拜饋酥茶。"]'),
('01fab6be-f693-406b-95c3-a69f091274c9','溪亭二首  其一','張商英','宋','宋诗','song-poetry','','[]','林檎園北小橋南，水綠山青不易兼。',64,'全唐诗/poet.song.54000.json','["林檎園北小橋南，水綠山青不易兼。", "戴勝降時桑破甲，駕犁啼處稻抽尖。", "柳因倒植風流甚，花爲新移蓓蕾纖。", "獨碾雲龍坐溪石，幾人今夕共銀蟾。"]'),
('c5e5274c-93a2-4b71-b9db-c6c588c754ba','溪亭二首  其二','張商英','宋','宋诗','song-poetry','','[]','蕭寺回環石磴間，山光草色遠相連。',64,'全唐诗/poet.song.54000.json','["蕭寺回環石磴間，山光草色遠相連。", "坐中清景追唐蹟，門外紅塵接渭川。", "落澗飛泉千丈玉，過牆修竹一梢烟。", "畫工誰繪當時巧，移得江南在眼前。"]'),
('b93dd9fa-c74d-4a24-80af-25e5a36726cc','游綿山','張商英','宋','宋诗','song-poetry','','[]','夕陽返照影流東，點點寒鴉過遠峰。',64,'全唐诗/poet.song.54000.json','["夕陽返照影流東，點點寒鴉過遠峰。", "漁叟罷竿收釣餌，牧童吹笛弄西風。", "日光隠隠沉滄海，山色青青聳碧空。", "萬壑千崖增秀麗，往來人在畫圖中。"]'),
('d11a15c6-ead2-4435-b8c5-5487e55c32a8','凌雲行','張商英','宋','宋诗','song-poetry','','[]','我本耕釣夫，素嗜山水樂。',96,'全唐诗/poet.song.54000.json','["我本耕釣夫，素嗜山水樂。", "補吏來旴江，潜解組綬縛。", "獨上凌雲行，青梯入寥廓。", "萬象富觀覽，四面峻巖壑。", "天風襲衣襟，斷霞半空落。", "仙家雞犬鳴，驚起巢松鶴。", "勝遊最後時，萍梗念漂泊。", "回首顧人間，佳景滿城郭。"]'),
('aa2aaa56-c242-4f25-a06c-b92531d67dac','步虛詞','張商英','宋','宋诗','song-poetry','','[]','珠珮珊珊路絕塵，鳳凰山上夕朝真。',64,'全唐诗/poet.song.54000.json','["珠珮珊珊路絕塵，鳳凰山上夕朝真。", "甘棠美政行南國，列宿寒光拱北辰。", "篆冷金盤雲屋曉，書飛玉闕洞天春。", "一聲遼鶴歸傳報，壽益君王福在民。"]'),
('f06a1d5f-edff-41b5-9433-fdd9feb79760','句  其一','張商英','宋','宋诗','song-poetry','','[]','天連遠水三吳闊，人倚危樓萬象低。',16,'全唐诗/poet.song.54000.json','["天連遠水三吳闊，人倚危樓萬象低。"]'),
('35ca01b5-309a-494c-920c-2827838be6cd','句  其二','張商英','宋','宋诗','song-poetry','','[]','湖上青山一抹高，烟中草木細如毫。',16,'全唐诗/poet.song.54000.json','["湖上青山一抹高，烟中草木細如毫。"]'),
('504f9b6e-caff-460f-a6d1-567d2fe0f424','句  其三','張商英','宋','宋诗','song-poetry','','[]','安得將相似仲山。',8,'全唐诗/poet.song.54000.json','["安得將相似仲山。"]'),
('236b1cf6-608c-4122-b9bc-f870102b1a73','句  其四','張商英','宋','宋诗','song-poetry','','[]','大士慈悲度有情，亦要時節因緣并。',32,'全唐诗/poet.song.54000.json','["大士慈悲度有情，亦要時節因緣并。", "也應笑我空經營，雖多手眼難支撐。"]'),
('caab3d46-0bf6-46b4-8562-35a3dc785887','句  其五','張商英','宋','宋诗','song-poetry','','[]','靈山會上別世尊，各以願力濟群生。',32,'全唐诗/poet.song.54000.json','["靈山會上別世尊，各以願力濟群生。", "子勿誚我徒經營，手眼太少難支撐。"]'),
('8f6de388-ce83-4d3d-9686-435e5c68ca13','句  其六','張商英','宋','宋诗','song-poetry','','[]','每聞回列進，不覺寸心忙。',12,'全唐诗/poet.song.54000.json','["每聞回列進，不覺寸心忙。"]'),
('438b0cad-8903-4087-9997-70bef178748a','句  其七','張商英','宋','宋诗','song-poetry','','[]','星文占地讖，巽水直江流。',12,'全唐诗/poet.song.54000.json','["星文占地讖，巽水直江流。"]'),
('eef1c982-84ad-413c-b2ca-1be53bc908c0','句  其八','張商英','宋','宋诗','song-poetry','','[]','雖贋猶堪貴，前賢况可師。',12,'全唐诗/poet.song.54000.json','["雖贋猶堪貴，前賢况可師。"]'),
('0dc15f1e-2270-4656-9f25-c79c51274f78','句  其九','張商英','宋','宋诗','song-poetry','','[]','欲到嶮頭尋怪石，夜來春水漲前溪。',16,'全唐诗/poet.song.54000.json','["欲到嶮頭尋怪石，夜來春水漲前溪。"]'),
('5c7f78c8-66dd-4c33-b16b-36b6f7b20d0b','句  其一○','張商英','宋','宋诗','song-poetry','','[]','贊唐山石裂半岸，壅遏波濤雪霜起。',16,'全唐诗/poet.song.54000.json','["贊唐山石裂半岸，壅遏波濤雪霜起。"]'),
('0e7b12b0-bd39-4565-be96-e9d7155a4af0','句  其一一','張商英','宋','宋诗','song-poetry','','[]','櫓聲嘔啞下巴東，路接陽臺十二峰。',16,'全唐诗/poet.song.54000.json','["櫓聲嘔啞下巴東，路接陽臺十二峰。"]'),
('0ccd2846-698d-4275-9f3e-85d81c902092','句  其一二','張商英','宋','宋诗','song-poetry','','[]','因尋太上長生訣，偶到青城大面山。',16,'全唐诗/poet.song.54000.json','["因尋太上長生訣，偶到青城大面山。"]'),
('8e147951-5586-4696-97f6-64ca82909d6d','句  其一三','張商英','宋','宋诗','song-poetry','','[]','楠生石合頭陀出，此記傳聞歲月遙。',16,'全唐诗/poet.song.54000.json','["楠生石合頭陀出，此記傳聞歲月遙。"]'),
('9590d455-980c-4efe-a38f-3fa3eb2c7f95','句  其一四','張商英','宋','宋诗','song-poetry','','[]','水味甘腴偏宜煮，茗非陸羽莫能辨。',16,'全唐诗/poet.song.54000.json','["水味甘腴偏宜煮，茗非陸羽莫能辨。"]'),
('2310563e-bc94-4321-8cbf-048a45d0a344','句  其一五','張商英','宋','宋诗','song-poetry','','[]','四時積雪瞻岷嶺，三派飛泉出洞天。',16,'全唐诗/poet.song.54000.json','["四時積雪瞻岷嶺，三派飛泉出洞天。"]'),
('e5165ccd-47cb-46f3-8c1b-3edf111eec6f','句  其一六','張商英','宋','宋诗','song-poetry','','[]','空將淚作雨滂沱，淚痕有盡愁無竭。',16,'全唐诗/poet.song.54000.json','["空將淚作雨滂沱，淚痕有盡愁無竭。"]'),
('887ddc20-962e-445b-a130-e2c883c3295e','句  其一七','張商英','宋','宋诗','song-poetry','','[]','靈官召集役神鵲，直渡銀河橫作橋。',16,'全唐诗/poet.song.54000.json','["靈官召集役神鵲，直渡銀河橫作橋。"]'),
('53d2e366-727d-4a0a-97ac-af5b6b21fb29','句  其一八','張商英','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','不向廬山尋落處，象王鼻孔謾遼天。',16,'全唐诗/poet.song.54000.json','["不向廬山尋落處，象王鼻孔謾遼天。"]'),
('e577ec83-7b9c-4a0d-9eb6-a2cd5b717d36','句  其一九','張商英','宋','宋诗','song-poetry','','[]','秦庭繁杏兩株開。',8,'全唐诗/poet.song.54000.json','["秦庭繁杏兩株開。"]'),
('84d41b96-2153-47e1-a8b0-f544fc98d70b','句  其二○','張商英','宋','宋诗','song-poetry','','[]','庭前積水過不流，落葉千片水上浮。',32,'全唐诗/poet.song.54000.json','["庭前積水過不流，落葉千片水上浮。", "憐花不忍見凋謝，風力顛猛摧嬌柔。"]'),
('2086f552-c804-40f9-9466-b5248ac750f5','句  其二一','張商英','宋','宋诗','song-poetry','','[]','水晶肉白殻皮紅，色變香移味不同。',16,'全唐诗/poet.song.54000.json','["水晶肉白殻皮紅，色變香移味不同。"]'),
('a8d55110-3312-41c6-a50d-12ee6629e9e4','句  其二二','張商英','宋','宋诗','song-poetry','','[]','如障如屏如繡畫，似幢似蓋似旌旗。',16,'全唐诗/poet.song.54000.json','["如障如屏如繡畫，似幢似蓋似旌旗。"]'),
('6785c88f-23df-4143-922b-ff607e729378','句  其二三','張商英','宋','宋诗','song-poetry','','[]','分付着身先引去，免教人道販私茶。',16,'全唐诗/poet.song.54000.json','["分付着身先引去，免教人道販私茶。"]'),
('4830593d-1633-4015-9684-4f997e443811','句  其二四','張商英','宋','宋诗','song-poetry','','[]','最憐高塚臨官道，細細烟莎編燒痕。',16,'全唐诗/poet.song.54000.json','["最憐高塚臨官道，細細烟莎編燒痕。"]'),
('5a99f1b9-d656-4bc7-b74e-4740b72bde64','句  其二五','張商英','宋','宋诗','song-poetry','','[]','鶴髮飄飄紫府仙，摩娑金狄不知年。',16,'全唐诗/poet.song.54000.json','["鶴髮飄飄紫府仙，摩娑金狄不知年。"]'),
('66fc0895-2f00-4ff8-a692-117bd72b538e','賀拜罷南郊獻詩','黄裳','宋','宋诗','song-poetry','','[]','中天臺上聞天語，將下人間會真主。',272,'全唐诗/poet.song.54000.json','["中天臺上聞天語，將下人間會真主。", "王室堂開秋意深，匆匆瑞氣排羣陰。", "插空儀物望不斷，文采高下成遙林。", "鐵衣十萬熊羆勇，忽擁天衢海濤動。", "兩序朱簾語相慶，皆謂君王能紹聖。", "昭昭神考體天德，昔向明堂布仁政。", "君王欲報天地恩，乃修宗祀開端門。", "玉輅亭亭張日月，中望堯雲降天闕。", "清宮行事齋心微，默與神交誰得知。", "獻饗歸來待祠殿，上帝先從道心見。", "龍衣登降天香濃，一片鈞天庭燎中。", "振鷺于飛珮聲響，恍如三代觀臣工。", "先皇基緒既肯構，配侑豈或慚高穹。", "安得公尸不來燕，自是諸侯皆望風。", "奏歌已薦致和樂，飲受乃酢持盈功。", "曉來忽聽道傍語，從此天觀觀九敘。", "瑣瑣愚臣何所補，只願獻詩歸樂府。"]'),
('d26b51aa-de39-4da4-aa53-26a4c3fc369e','次魯直烹密雲龍之韵  其一','黄裳','宋','宋诗','song-poetry','','[]','密雲晚出小團塊，雖得一餠猶爲豐。',104,'全唐诗/poet.song.54000.json','["密雲晚出小團塊，雖得一餠猶爲豐。", "相對幽亭致清話，十三同事皆詩翁。", "蒼龍碾下想化去，但見白雲生碧空。", "雨前含蓄氣未散，乃知天貺誰能同。", "不足數啜有餘興，兩腋欲跨清都風，豈與凡羽誇雕籠。", "雙井主人煎百椀，費得家山能幾本。"]'),
('4578d159-eba8-451d-adea-e1204caf5651','次魯直烹密雲龍之韵  其二','黄裳','宋','宋诗','song-poetry','','[]','春來腰筥修溪童，摘山歸去如年豐。',104,'全唐诗/poet.song.54000.json','["春來腰筥修溪童，摘山歸去如年豐。", "主人長啜不言酒，焉用兒女扶山翁。", "聞說佳致欲相遂，勞生急放塵緣空。", "時走長鬚汲雙井，豈吝七椀邀盧仝。", "夜歸須步三峰月，曉望還乘五桂風，靜中且看狙公籠。", "此樂吾宗好方寸，已向清齋望根本。"]'),
('24096486-bc4a-4184-af48-a02a1aae1e42','次魯直烹密雲龍之韵  其三','黄裳','宋','宋诗','song-poetry','','[]','三峰峭拔如武夷，秀氣入草根幹豐。',104,'全唐诗/poet.song.54000.json','["三峰峭拔如武夷，秀氣入草根幹豐。", "秋堂一笑詩相共，竹杖未化誰知翁。", "非特鷹爪致我啜，芋栗亦慰腸中空。", "脩魚上釣開酒甕，但欲醉我君寧同。", "須飲一斗寄混沌，吹使自覺桃源風，此言當踐非相籠。", "百歲豈能空自窘，萬頃汪汪同一本。"]'),
('97886963-bd50-4eca-9885-dd744af26c31','次魯直烹密雲龍之韵  其四','黄裳','宋','宋诗','song-poetry','','[]','春山椎鼓雀舌細，石澗垂絲魚肉豐。',104,'全唐诗/poet.song.54000.json','["春山椎鼓雀舌細，石澗垂絲魚肉豐。", "異時相逐許餘地，杖藜自號田家翁。", "有年無累反觀處，水天雲盡涵秋空。", "雖然出處有義命，必欲長往非人同。", "校書千古竄訛謬，日長閒御瀛洲風，故園且付烟雲籠。", "落筆成詩今幾卷，洗我煩襟求副本。"]'),
('bd3b5c48-2004-49e7-9102-178d9034b211','次曾德宣竹窗之韵','黄裳','宋','宋诗','song-poetry','','[]','導彼清泠泉，育此嬋娟身。',48,'全唐诗/poet.song.54000.json','["導彼清泠泉，育此嬋娟身。", "幽哉窗戶間，猗猗窺鱗鱗。", "有霜能獨留，無德難相親。", "乃聞曾子風，嗜好非今人。"]'),
('7304954c-5eb1-4e6b-a315-2f5b3b7954f8','簡政堂','黄裳','宋','宋诗','song-poetry','','[]','簡政豈在事，養源無他心。',48,'全唐诗/poet.song.54000.json','["簡政豈在事，養源無他心。", "持守得綱領，施設從胸襟。", "虛靜古意遠，平易人情深。", "光景塵不染，悉付公餘吟。"]'),
('032381a8-c4c0-413e-8743-4e94dfc342ce','題楊氏聚義軒','黄裳','宋','宋诗','song-poetry','','[]','聚義歸清虛，無欠亦無餘。',132,'全唐诗/poet.song.54000.json','["聚義歸清虛，無欠亦無餘。", "聚利赴嗜慾，自喪俄自續。", "義在詩與書，利在金與珠。", "金珠壯人顔，俯仰一世間。", "我去彼不隨，彼去我不觀。", "詩書入青瞳，藏蓄心腑中。", "貽之修乃孫，操之修乃躬。", "秧種秀沃壤，願飽萬腹空。", "源泉洌清甃，既與還不窮。", "開軒有意哉，短什嘉仙翁。", "黽勉慎所交，高攀古人風。"]'),
('c6daafe7-3633-4993-b59f-a11b401c90a0','聽隠士琴','黄裳','宋','宋诗','song-poetry','','[]','幽意不可象，因聲而後形。',112,'全唐诗/poet.song.54000.json','["幽意不可象，因聲而後形。", "至聲不可僞，因心而後生。", "三尺膝上孤，一寸胸中鳴。", "急聲如飛泉，瀉瀉秋雲邊。", "巧聲如流鶑，歷歷春風前。", "幽人無此心，素弦無此聲。", "心與手相忘，意與聲相迎。", "彈者自到古，聞者誰知音。", "但見風色吹我清，欲御此風天上行。"]'),
('1ed253a1-3b09-4920-9717-91caabe5dce1','送胡君遊洛','黄裳','宋','宋诗','song-poetry','','[]','得喪紛紛轉羣慾，誰及愛嵩三十六。',188,'全唐诗/poet.song.54000.json','["得喪紛紛轉羣慾，誰及愛嵩三十六。", "有客忽自東南來，已爲湖山飽雙目。", "逸興不住皇州春，天津橋南酒初熟。", "長念花王司馬坂，洛陽今寓誰家館。", "已聞香信滿東風，嬪御相從水光畔。", "芳容須向盛時吟，昔也醉翁長恨晚。", "穀雨且老黄鸝聲，急上征鞍望瀍澗。", "送行詩句無纖塵，自有交遊在霄漢。", "藜莧腸中何所須，但愧銀鈎落香翰。", "看花知遺生，看山知養神。", "妖奇怪麗九十種，未失東風助培壅。", "三十六峰元氣清，獨插太虛無古今。"]'),
('b420d488-d7d2-487b-80ad-4957e8092187','湖上閒賦','黄裳','宋','宋诗','song-poetry','','["\u897f\u6e56"]','錢塘吳之雄，西湖乃其貳。',168,'全唐诗/poet.song.54000.json','["錢塘吳之雄，西湖乃其貳。", "晴虛混高下，寒光墮蒼翠。", "俯仰睨澄澈，融結會幽邃。", "日月司晦明，烟雲管開閉。", "樓閣生有無，塵凡換奇異。", "素藹俄包藏，物象已非二。", "中有虛一子，四顧銀色世。", "雲罅漏餘晷，稍盛却陰翳。", "遽回天漢明，收攝何所置。", "近影認遙碧，故態獻新媚。", "振羽鷺初起，一葦出天際。", "大巧現奇畫，人歡發幽思。", "杖履秋林深，弦管春波細。", "名字人不知，閒藏洞霄吏。"]'),
('b69a06b6-2254-4090-b3d3-7fd690d2231d','寄題存心堂因簡正仲運使','黄裳','宋','宋诗','song-poetry','','[]','有樂不在物，况當仕而優。',156,'全唐诗/poet.song.54000.json','["有樂不在物，况當仕而優。", "外騖乃自苦，作德能日休。", "身計苟未適，安能爲道謀。", "基址更所寓，得地東南陬。", "經營喜宋子，闡繹嘉毛侯。", "紛囂落寂境，蒸鬰回素秋。", "事少德機靜，風微花信幽。", "林悄鳥相應，日閒絲自遊。", "中發靈臺光，下照彪池流。", "神怡况味遠，意虛才智周。", "真見造不滅，妄想降無求。", "所示良可助，所超安可酬。", "會合果有道，寧復嗟阻修。"]'),
('d04c8e8a-5a16-4222-8ad8-bd3dc507c97d','惇禮兵部久不作詩偶成數韵奉戲','黄裳','宋','宋诗','song-poetry','','[]','南宮先生好談古，齒牙所掛多老杜。',64,'全唐诗/poet.song.54000.json','["南宮先生好談古，齒牙所掛多老杜。", "劍氣中盤幾時吐，欲看光芒出庭戶。", "平生氣直易言語，不解聱牙斲詩句。", "先生莫學東野苦，我願爲雲相逐去。"]'),
('0ef6eb93-636e-49d9-a3be-4d934ff6d66f','汴河解凍郭公域將行以詩奉寄','黄裳','宋','宋诗','song-poetry','','[]','霜華一望銀河道，聞說行艫猶未果。',80,'全唐诗/poet.song.54000.json','["霜華一望銀河道，聞說行艫猶未果。", "清暘想快東去情，未斬凝冰已先破。", "東鄰空憶樽前佐，爲誰更把金巵倒。", "汾陽遠裔今有人，不見纖塵落幽抱。", "畫梁燕子趁時歸，故園莫放春光老。"]'),
('a8a853eb-12c9-4bab-b633-c06ac9f06b57','簡元輿祠部  其一','黄裳','宋','宋诗','song-poetry','','[]','文藝相從春欲暮，未去皇州散還聚。',144,'全唐诗/poet.song.54000.json','["文藝相從春欲暮，未去皇州散還聚。", "豈期擾擾凶器場，却會高談翫千古。", "冷官輒對華省郎，亦許烹煎待賓主。", "文章雖自根本來，裂破大全空縷縷。", "如公自蓄胸中奇，長短豈能欺五度。", "曠野羣陂渴霖雨，欲叫蝦蟆已窺戶。", "春衫未疊麥寒薄，最愜含毫斲詩句。", "如公簡靜意尤遠，卒邇清風慰遐慕。", "牽率鄙興遊太虛，滿我縑箱始歸去。"]'),
('37326f58-4418-443c-bb09-4adcf85667ac','簡元輿祠部  其二','黄裳','宋','宋诗','song-poetry','','[]','百花巖上仙人住，巖下爲州山水聚。',144,'全唐诗/poet.song.54000.json','["百花巖上仙人住，巖下爲州山水聚。", "白頭青冢南北人，倒影沈沈獨懷古。", "倚欄把酒與誰同，况是使君爲獻主。", "應喚漁舟疏葦中，旋膾游鱗落紅縷。", "秘書座上最軒昂，能共春雲爭態度。", "紅衣带月今何處，幾轉春殘掩朱戶。", "飛船送客空斷腸，梁塵漫落聲中句。", "虛白亭前湖水閒，忽爲霓裳起思慕。", "出門沙土亂如雨，薰風吹夢天南去。"]'),
('f1ea7a08-e687-4210-ac72-1f939558050e','觀試','黄裳','宋','宋诗','song-poetry','','[]','題墨脫新鎸，扃鑰開清曉。',156,'全唐诗/poet.song.54000.json','["題墨脫新鎸，扃鑰開清曉。", "文衡朝士高，香案天風小。", "銀袍带殘月，玉鷺集寒沼。", "赳赳干城材，銜枚出遠徼。", "才氣方自强，未戰意先挑。", "臨文尋汝賢，形見乃微妙。", "人才焉可齊，雲漢多年少。", "慳思憂明膏，俊性翫斜照。", "得喪召榮辱，美惡露嚬笑。", "修毫飲流液，靈珠落光耀。", "雕琢破巨璞，歌舞探長鞘。", "含蓄既寂寂，運動還渺渺。", "重賞豈敢吝，行當塞明詔。"]'),
('586b0b4d-cad6-4268-a7c9-f62c04636443','簡無咎學士','黄裳','宋','宋诗','song-poetry','','[]','北澶車馬來何暮，芹茅池邊失歡聚。',144,'全唐诗/poet.song.54000.json','["北澶車馬來何暮，芹茅池邊失歡聚。", "有分共爲文字遊，却向西郊話今古。", "人頼聰明多自僞，信厚期君中有主。", "職事無塵靜相對，滿榻詩書香數縷。", "嚴扃如在柳陰中，綠幄朱簾細風度。", "紫犀銙破雪花濃，石鼎煎聲遶窗戶。", "準擬七椀邀盧仝，清滌煩襟出新句。", "共笑先生最貧苦，誤使簾前客相慕。", "虛名薄利能幾多，裹飯區區來復去。"]'),
('10cc1611-007c-48a3-b78c-0025110c29e8','酬羅正之提刑城東賞花之什','黄裳','宋','宋诗','song-poetry','','[]','一氣適來顔色明，一氣適去顔色衰。',256,'全唐诗/poet.song.54000.json','["一氣適來顔色明，一氣適去顔色衰。", "花緣根蒂豈所托，顔色亦非花可爲。", "花約一時枯且榮，人約百歲行復歸。", "一時百歲孰多寡，花發乃知人盛時。", "一回花發一度醉，已無百與花爲期。", "韓子空尋院中長，走馬歸來謾惆悵。", "昔日城西未同醉，今日城東還獨賞。", "萬事著意令人悲，邂逅多歡人願隨。", "破臘中來春漸漸，閒見芳梢青數點。", "韶華九十猶更長，未嘗一朝遊醉鄉。", "中含萬巧欲傾瀉，將與才思爭光芒。", "天台近得醉吟老，寄我新篇頌花好。", "揚鞭直指都城中，已踏東風楊柳道。", "上苑初開芳意濃，急走長鬚爲余報。", "競香論色如夢中，蝴蝶翩翩遶芳草。", "朱顔未愧雕欄紅，莫向忙中放春過。"]'),
('fc20314e-98b0-4d19-89b9-6d196dd0c03c','寄題妙光亭','黄裳','宋','宋诗','song-poetry','','[]','天邊月下雲初盡，江上潮來風已定。',80,'全唐诗/poet.song.54000.json','["天邊月下雲初盡，江上潮來風已定。", "兩物無情豈有期，但見圓光非遠近。", "潮回月落杳難尋，元無此景何須問。", "沙北渡頭人自忙，誰爲山翁說真性。", "滌除塵垢無少休，他日危樓與君凭。"]'),
('849e408f-014f-47e6-a7d6-f7b9cf94f140','觀蠶','黄裳','宋','宋诗','song-poetry','','[]','大巧不爲蠶上簇，機婦飛梭雙注目。',32,'全唐诗/poet.song.54000.json','["大巧不爲蠶上簇，機婦飛梭雙注目。", "腹空萬緒徒自勞，縑素如山人未足。"]'),
('146a2653-1f1e-439c-9482-70b33ca005d4','圓石六題 迎暉亭','黄裳','宋','宋诗','song-poetry','','[]','始自暘谷見，餘霞斂微明。',84,'全唐诗/poet.song.54000.json','["始自暘谷見，餘霞斂微明。", "亟從林末動，幽禽發清聲。", "羣陰既掃迹，衆象聊遣情。", "捲簾取遙望，揮毫寫初迎。", "行樂自此始，勿爲多事縈。", "一世如過隙，頃刻寧可輕。", "勝概豈虛置，倒樽慰浮生。"]'),
('fe952746-6aeb-488d-8748-f5d38e178446','圓石六題 邀月亭','黄裳','宋','宋诗','song-poetry','','[]','迎暉不覺一日盡，邀月又會三人閒。',96,'全唐诗/poet.song.54000.json','["迎暉不覺一日盡，邀月又會三人閒。", "未言期約綠巖畔，且共歌舞清樽間。", "霜輪皎皎無今古，世途擾擾多新故。", "今月曾經照故人，古人問月今何處。", "百年光景行復催，有月可邀能幾回。", "雙巖達士不須說，始見迎暉復邀月。"]'),
('1dc6a4d8-dacc-4661-a09f-463d6d833402','圓石六題 清輝亭','黄裳','宋','宋诗','song-poetry','','[]','山色翠欲流，水光澄可照。',48,'全唐诗/poet.song.54000.json','["山色翠欲流，水光澄可照。", "二物偶相際，清風發微妙。", "中有逍遙翁，寓意得歡笑。", "此道復何求，仁智姑自劭。"]'),
('6fc15f67-f6c6-4c3b-9869-8e8dc8375d45','圓石六題 翠筠庵','黄裳','宋','宋诗','song-poetry','','[]','外環碧玉千尋直，中起真香一篆清。',32,'全唐诗/poet.song.54000.json','["外環碧玉千尋直，中起真香一篆清。", "宴坐主人俄出定，歲寒枝上得秋聲。"]'),
('967272c6-a4b1-4381-b6c2-070ea9443bd3','圓石六題 快覽亭','黄裳','宋','宋诗','song-poetry','','[]','欲跨晴虛兩腋風，曲欄干外意無窮。',64,'全唐诗/poet.song.54000.json','["欲跨晴虛兩腋風，曲欄干外意無窮。", "忘形獨坐雙巖下，遣興旁觀萬象中。", "數韵瑰奇聊自適，滿懷清爽可誰同。", "颯然而下吾能賦，未必登臨愧楚宮。"]'),
('e5698a14-0fb6-43bb-a388-266f44c357b3','圓石六題 招仙亭','黄裳','宋','宋诗','song-poetry','','[]','仙人豈可招，固有招仙道。',96,'全唐诗/poet.song.54000.json','["仙人豈可招，固有招仙道。", "欽信勿自欺，仁恕滿中抱。", "何慚紫芝翁，惠然及予坐。", "衆行示要路，羣實指虛果。", "脫落形數中，行在從所好。", "躊躇即有礙，清樽急須倒。", "天風欻爾動，相忘一何果。", "幾日當復來，斜陽滿芳草。"]'),
('07345df3-d97a-4e4d-97dc-2bca04ef3dc2','龍鳳茶寄照覺禪師','黄裳','宋','宋诗','song-poetry','','[]','有物吞食月輪盡，鳳翥龍驤紫光隠。',144,'全唐诗/poet.song.54000.json','["有物吞食月輪盡，鳳翥龍驤紫光隠。", "雨前已見纖雲從，雪意猶在渾淪中。", "忽带天香墮吾篋，自有同幹欣相逢。", "寄向仙廬引飛瀑，一簇蠅聲急須腹。", "禪翁初起宴坐間，接見陶公方解顔。", "頤指長鬚運金碾，未白眉毛且須轉。", "爲我對啜延高談，亦使色味超塵凡。", "破悶通靈此何取，兩腋風生豈須御。", "昔云木馬能嘶風，今看茶龍解行雨。"]'),
('aa83440c-fe89-4641-bb98-dcb219909509','送范子鎮','黄裳','宋','宋诗','song-poetry','','[]','東南有人不可攀，生輕義重人所難。',208,'全唐诗/poet.song.54000.json','["東南有人不可攀，生輕義重人所難。", "此風彫落不復見，得公今日如芝蘭。", "千人忽墮風濤間，義氣有感心生寒。", "以情論法不可枉，使法可枉吾寧閒。", "兼遺物己爲虛舟，遂授此屬還平流。", "相逢鷹犬顔何厚，劍水閩山公不朽。", "有恩流到墓中魂，無累乞尋林下友。", "得官西去心膽雄，帳下將軍望公久。", "此生義在公無慚，未到青雲空白首。", "男子屈伸當有時，行置長纓遠夷脰。", "浩歌一闋公臨政，馬上東風曲堤柳。", "卯酒醺醺吹復醒，纖毫謾引無中有。", "灑然得句誰其酬，寄我須煩置郵走。"]'),
('c8e53989-aabc-438d-afa3-4f54a2fe8f7f','卜居潮山','黄裳','宋','宋诗','song-poetry','','[]','勝致久不示，幽居今已該。',276,'全唐诗/poet.song.54000.json','["勝致久不示，幽居今已該。", "蓋待出塵子，將作還玄齋。", "升高獨南望，大巧安用裁。", "天目形勢落，秋空屏障開。", "吳境岸邊斷，越峰天際回。", "雙臂龍虎揖，兩潮風雨來。", "直視江渚印，蛟蜃遺靈胎。", "旁聞海門出，波浪生春雷。", "平生樂山水，邂逅奚所猜。", "秋老竹林冷，攀竹趨巖隈。", "得石喜奇怪，且席青錢苔。", "泉甘地脈正，吸泉如傳杯。", "人靜道始集，境幽心易灰。", "老圃聽吾語，勿以慵相推。", "勤將日力進，速副韶光催。", "長生且有道，當悟接與栽。", "務使翠華遠，長大如嬰孩。", "瓊蕊覆青徑，木香兼荼梅。", "疏鑿取清淺，結甃移碑材。", "飛橋渡流水，俯仰無纖埃。", "雖謂夕陽好，見月還徘徊。", "卜築非偶爾，供吟何快哉。", "棲養此固足，會晤誰可偕。"]'),
('c80a8155-6a00-4400-83fe-1e8535ecc4c1','假山','黄裳','宋','宋诗','song-poetry','','[]','天作乃說真，人作故云假。',144,'全唐诗/poet.song.54000.json','["天作乃說真，人作故云假。", "堆疊孕奇怪，含思亦如畫。", "遙岑出寸碧，羣岫擁而亞。", "蒼苔抱秀骨，尤愜時雨灑。", "去來何所人，度嶺策羸馬。", "安得無心雲，經從斷而挂。", "日落行且休，寒巖峙孤舍。", "假合雖使然，登覽憂亦寫。", "萬法資諸心，一念有神化。", "締構况融結，猶造秋與夏。", "攝用還一空，何取亦何捨。", "莫認假與真，外樂聊以借。"]'),
('f9c1c3a0-3ae4-4b06-8848-0d398b026c55','謝人惠茶器并茶','黄裳','宋','宋诗','song-poetry','','[]','三事文華出何處，巖上含章插烟霧。',144,'全唐诗/poet.song.54000.json','["三事文華出何處，巖上含章插烟霧。", "曾被西風吹異香，飄落人寰月中度。", "美林見器安所施，六角靈犀用相副。", "目下發緘誰致勤，愛竹山翁傍雲住。", "遽命長鬚烹且煎，一簇蠅聲急須吐。", "每思北苑滑與甘，嘗厭鄉人寄來苦。", "試君所惠良可稱，往往曾沾石坑雨。", "不畏七椀鳴饑腸，但覺清多却炎暑。", "幾時對話愛竹軒，更引毫甌斲詩句。"]'),
('26d6772e-ce15-4485-80d7-934a603779b6','陪會稽太守遊鑑湖會于禹祠之下','黄裳','宋','宋诗','song-poetry','','[]','一鑑沈沈含萬象，千巖競秀還相向。',160,'全唐诗/poet.song.54000.json','["一鑑沈沈含萬象，千巖競秀還相向。", "季真夢斷歸去來，數頃寒光對夷曠。", "管弦公外與民同，祕閣先生千騎長。", "從公于邁巷無人，畫船解纜爭先放。", "去探禹穴升稽山，語笑相逢洞天上。", "玉帛紛紛何處尋，謾對遺陵起悽愴。", "越王羞辱微之歡，山水依然人獨往。", "先生揖我欹金巵，吾道本來無得喪。", "日月如飛奚用勞，醉舞言歸勿令蕩。", "湘靈不見湘江閒，回首斜陽落秦望。"]'),
('0a8d3005-5e5e-4ac2-8e79-d8ae6ea1f2ee','送滿龍圖守奉化','黄裳','宋','宋诗','song-poetry','','[]','臺省兩稱公，郡國三換節。',144,'全唐诗/poet.song.54000.json','["臺省兩稱公，郡國三換節。", "海角承重寄，螭頭懷遠別。", "俯仰七遷迅，覺夢一炊熱。", "先生自怡怡，浮世誰惙惙。", "暴霖駕西洛，華艫指東浙。", "香徑摧芰荷，豐厨拾魚鼈。", "窺影入賀鑑，訪古探禹穴。", "未暇登四明，方思白華潔。", "使車貽親榮，閩山迓來轍。", "豈須老萊衣，始能事耆耋。", "往往回首時，千巖看堆雪。", "行觀真卿書，德政滿青碣。"]'),
('101bfe81-bf2b-448e-89a5-4bface121af3','次舒堯文秋夜有感之韵','黄裳','宋','宋诗','song-poetry','','[]','自越趨儒林，由吳兩江渡。',156,'全唐诗/poet.song.54000.json','["自越趨儒林，由吳兩江渡。", "四年如退之，疏慵傲名數。", "西風今又來，庭柯泣珠露。", "榮枯幾番新，閒日常自度。", "誓爲天漢遊，搗藥看玉兔。", "逆行非吾心，焉用憂日暮。", "典籍猶可捐，寧雕子雲賦。", "萬事歸自然，所得先去故。", "灑落桐廬君，高源欲東赴。", "外物非所謀，此學良足據。", "但以中致虛，元氣腹當飫。", "壯懷感暮秋，羣動還太素。", "宋玉悲何爲，忘失聊適屨。"]'),
('368105ab-11f0-4299-8848-313972c2ed1f','送劉和甫之江東','黄裳','宋','宋诗','song-poetry','','[]','去年相逢時，霜華輕壓梅花枝。',252,'全唐诗/poet.song.54000.json','["去年相逢時，霜華輕壓梅花枝。", "今年相別日，蘋末秋風慘行色。", "逢時易爲樂，別時易爲傷。", "誰知傷與樂，各是羈旅腸。", "送者難爲留，離者難爲行。", "誰知離與合，各是天涯人。", "離合有分不可料，彼此有適當忘情。", "君今此去何時來，韋編頻向燈前開。", "讀書患在少思索，時將寸管書清才。", "君今此去何時到，風力攻帆急如火。", "秋光照人益瀟洒，一葉輕舠又東下。", "松陵鱸膾是時節，無惜霜鋒傍船切。", "泛入東南第一州，八月仙濤駕天白。", "江頭此景須吟看，少留軒旆開朱顔。", "徐徐踰江詣所舍，心閒應愛雲中山。", "用其所樂以自遣，莫教鄉思爲心關。", "他時握手又西上，多在後歲秋風間。"]'),
('882e2aef-828f-4f21-83ce-c6874f94f5b8','酬子明冬後出思正夏中見招之什','黄裳','宋','宋诗','song-poetry','','[]','大學閒官閉門坐，漬墨磨丹滿文藁。',224,'全唐诗/poet.song.54000.json','["大學閒官閉門坐，漬墨磨丹滿文藁。", "霜風門外潮頭過，馬首長鬚欲吹倒。", "雙眸厭爲塵沙昏，出外遽止從予好。", "不復見君今幾時，相憶還驚歲華老。", "恨得新詩何太晚，瓜李爲期閒夢斷。", "餘酒喜見忘機翁，聲色嘗與心相同。", "小沼荷花未云昨，君來且負爐中紅。", "東鄰交友亦愛客，烹鮮盤饌工于儂。", "青蝸烏賊欠此可，蟹蛤已有吳間風。", "勞生多故豈足念，莫不有分勞沖沖。", "有錢取醉亦足矣，滿腹以外吾何容。", "漫漫雪意稍含蓄，瑶池將見涵春空。", "兩騎翩翩踏瓊玖，州北主人相望久。", "解顔一笑如君難，區區論報非吾友。"]'),
('f991523f-8fc5-4473-a958-488665b64fb1','酬程忠彥見贈','黄裳','宋','宋诗','song-poetry','','[]','與子邂逅春闈中，子未及壯文何雄。',224,'全唐诗/poet.song.54000.json','["與子邂逅春闈中，子未及壯文何雄。", "淡書名姓青雲旁，天風吹我襟懷香。", "巨源耻作尋常流，洪濤忽駕西江秋。", "剽竊襲蹈非子情，伯樂一睨人皆驚。", "乃更退托多楚狂，謂我有感潭中央。", "腰間躍去爲龍藏，斗牛下接亭亭光。", "嘗言文章氣所寓，養氣未及柔與剛。", "烏能發露與劍比，而不與我非其長。", "紅塵丹漢不足較，儻來勿使心常忙。", "安得小艇劍溪上，與子邂逅飛雙槳。", "滿溪烟雨蘆花春，漁人一曲聲無塵。", "夜明潭上人初靜，神明欲腥姦與佞。", "寶氣深盤盤不得，直上羣陰俱失色。", "此時與子同行藏，倚樓人往空斜陽。"]'),
('e2eb7708-644d-44e5-85e6-02abbc653142','送延平太守','黄裳','宋','宋诗','song-poetry','','[]','南有溪山誰可托，須擁旌麾日邊落。',272,'全唐诗/poet.song.54000.json','["南有溪山誰可托，須擁旌麾日邊落。", "無政人向溪山愁，公徒追索情如酬。", "有政人向溪山醉，鼓吹尋幽鬧如市。", "七閩山水世所議，尤喜延平得高致。", "山光水色秋意清，月華劍氣空體明。", "雙流既往却再顧，五龍雖奮還相迎。", "斷雲天北列寸碧，中有仙人騎鶴行。", "仙人巖前萬人聚，金碧下瞰天津橫。", "霽色還空影高下，蓬萊幻化俄頃生。", "太原使君未下車，公論已許程與吳。", "獨遊才刃安能拘，發遣萬事歸玄無。", "洗眼待看鄉老書，使君政事當起予。", "年豐訟少民已蘇，兩稅競了誰無襦。", "萬戶有酒錢足酤，飄飄帘下吹笙竽。", "山水圖中聲色活，大小從公四園闊。", "颯颯山風吹夕照，想見頹然使君笑。", "南來莫使詩筒少，慰我塵勞空擾擾。"]'),
('3908628e-099b-4772-bef5-4845360485fc','夏雲','黄裳','宋','宋诗','song-poetry','','[]','數疊奇峰插空碧，舒卷光陰度紅日。',96,'全唐诗/poet.song.54000.json','["數疊奇峰插空碧，舒卷光陰度紅日。", "莫道無心空自閒，天地爲爐果何恤。", "願移炎赫歸至冥，請開蒸鬰還太清。", "從龍以往蕩妖氣，蟊賊欲滋今自坑。", "晚來載雨落何處，一片俄從北偏舉。", "區區此意焉用留，能作幾家軒上秋。"]'),
('24f0b590-6bb9-48a1-99e0-3c38001d567e','矮松','黄裳','宋','宋诗','song-poetry','','[]','枝幹偃蹇奇可誇，本根融結杳難測。',64,'全唐诗/poet.song.54000.json','["枝幹偃蹇奇可誇，本根融結杳難測。", "龍蛇已抱千載靈，梁棟何煩萬牛力。", "雖減半天風雨聲，却得三冬雪霜色。", "衛生已免斧斤人，粧景何辭吟醉客。"]'),
('07df3e18-1825-4e66-8d42-5d70228fc684','不流軒','黄裳','宋','宋诗','song-poetry','','[]','大道果安在，無流亦無止。',72,'全唐诗/poet.song.54000.json','["大道果安在，無流亦無止。", "有流落色界，無流在空體。", "用向體中存，見否瞪而視。", "空色兩相忘，有無還自爾。", "月明孕澄寂，山寒臥清泚。", "一葉天際來，歌聲聳吾耳。"]'),
('11beb714-9955-4083-8a12-c33eb10fc822','春霽','黄裳','宋','宋诗','song-poetry','','[]','動潤畢化事，清暘却陰翳。',72,'全唐诗/poet.song.54000.json','["動潤畢化事，清暘却陰翳。", "披雲出寸碧，銀色爛盈地。", "芳徑導衆樂，頑凍展羣翠。", "雨霽春且老，良時固難計。", "好景歸新詩，清樽接佳士。", "韶光宜夕陽，醉笑莫輕起。"]'),
('346e0a73-90e6-48d1-ae20-e74515262dfb','送郭公域','黄裳','宋','宋诗','song-poetry','','[]','官冷猶能願鄰好，側聽歡聲亦開抱。',128,'全唐诗/poet.song.54000.json','["官冷猶能願鄰好，側聽歡聲亦開抱。", "朝曦未合敗頑凍，來問仙舟已登道。", "但見風鈴送餘韵，慧佐尊前迹如掃。", "汾陽遠裔今有人，插架萬軸誰能貧。", "豪氣欲吞天下士，舌上古今時復陳。", "熙朝未遇將誰尤，芳辰不樂還自嗔。", "聚散浮雲眼前過，且作閒人靜中坐。", "畫梁燕子急歸來，莫放故園春自老。"]'),
('c4a9a946-449a-4f00-9ec7-575469d880df','寄連君佐','黄裳','宋','宋诗','song-poetry','','[]','樽酒會君江上樓，高談不與世俗侔。',64,'全唐诗/poet.song.54000.json','["樽酒會君江上樓，高談不與世俗侔。", "淮陰將軍跨下過，魯國至人東家丘。", "氣吐胸中斗牛夜，筆落手下烟雲秋。", "丈夫得失聊自樂，一身一計何足憂。"]'),
('a1f8b0a7-2987-4da2-9fa3-383953543b27','送人歸符離','黄裳','宋','宋诗','song-poetry','','[]','百尺危樓一杯酒，與君話別秋風老。',76,'全唐诗/poet.song.54000.json','["百尺危樓一杯酒，與君話別秋風老。", "明日解舟逐流水，不挂片帆急如火。", "符離風物好，一覺仙舟到。", "平時高奮丈夫事，匹馬西來亦須早。", "好是天涯逢故舊，笑言何處重携手。"]'),
('a7417a85-6498-4710-9f70-b8c413c6e613','送林疑獨教授','黄裳','宋','宋诗','song-poetry','','[]','猶記龍津曾把手，閒對雲山一樽酒。',160,'全唐诗/poet.song.54000.json','["猶記龍津曾把手，閒對雲山一樽酒。", "談高稍犯禪師疆，遙指青尖露疏牖。", "璧水起人新思濃，旁釋奇文到科斗。", "自笑山翁緘默多，來處長疑抱真叟。", "君雖健語猶相知，乃欲同歸上忠厚。", "假合此生塵已多，肯復隨流逐人後。", "再喜相逢春意中，忽見天機在楊柳。", "幽花野水時可尋，趕馬長鬚有罍鋀。", "柰何汴洛貪送人，掃蕩頑冰一梭走。", "義在人心難可欺，浮玉山南望風久。"]'),
('7001fbae-c23f-4d14-8284-d8a77f5e58b9','閒書','黄裳','宋','宋诗','song-poetry','','[]','一笑待毀譽，一歌待窮通。',36,'全唐诗/poet.song.54000.json','["一笑待毀譽，一歌待窮通。", "笑歌未能忘，猶落諸環中。", "無待用笑歌，此理西即東。"]'),
('ec16e29d-f4f0-49fe-9cf6-c25c9bf16398','尉氏五題 蔡相廟','黄裳','宋','宋诗','song-poetry','','[]','范叔脫身車簀間，一言悟主才所難。',192,'全唐诗/poet.song.54000.json','["范叔脫身車簀間，一言悟主才所難。", "死齊辱賈逐四貴，合爲昭王留武安。", "萬里青雲雖自致，燕客相尋亦天意。", "琅琅乘機敘消息，能使先生謹承德。", "願歸相印臣不如，結綬懷金豈勞力。", "富貴只資唇舌能，休笑魋顔與攣膝。", "人生遭遇合有時，羈旅入秦誰與知。", "攬權數月何爲懼，非義所安人或惡。", "四十三年雄俊間，歸與不歸函谷關。", "孤墳却使鄭人看，只恐燕昭由此還。", "千古英靈果何往，人間禍福空相訪。", "春入祠庭燕御風，交龍旌墮香塵中。"]'),
('0a1f03b3-886c-4448-a3e0-ccd17f218ff6','尉氏五題 三亭崗','黄裳','宋','宋诗','song-poetry','','[]','相得語未究，相知心已陳。',48,'全唐诗/poet.song.54000.json','["相得語未究，相知心已陳。", "喜生崗上夜，痛定簀中身。", "興廢自王鄭，恩酬生魏秦。", "滿懷機變學，豈謂有燕人。"]'),
('af40510f-fee6-42bd-be43-d91dbd9bce69','尉氏五題 蓬池','黄裳','宋','宋诗','song-poetry','','[]','曠野飲綠水，往往如具區。',132,'全唐诗/poet.song.54000.json','["曠野飲綠水，往往如具區。", "尉氏得此景，賜民非自娛。", "想成獨樂戒，故能與民俱。", "阮籍方外豪，徘徊顧梁都。", "亦恐感嘉惠，豈特懷壯圖。", "逸興果何類，茫茫誰與拘。", "度量貯天漢，豈不容葭蘆。", "興廢未始定，陵谷俄已殊。", "昔爲鳧鷖鄉，今爲狐鼠廬。", "厚澤瘞膏壤，能復滋耕夫。", "得利已足喜，懷古安用吁。"]'),
('c3bcf22c-eeac-4921-9780-89863cf72e9a','尉氏五題 嘯臺','黄裳','宋','宋诗','song-poetry','','[]','脫身魏晉間，嗣宗南阮英。',132,'全唐诗/poet.song.54000.json','["脫身魏晉間，嗣宗南阮英。", "長嘯寫逸興，偶爲臺上行。", "或带竹林醉，獨駕無將迎。", "風月乃所友，相投清與明。", "微引踵中息，稍從唇齒鳴。", "漸漸薄林杪，飄墮令人驚。", "憂憤聞而平，貪濁聞而清。", "蘇門得孫子，答以鸞鳳聲。", "不應乃深應，栖導良自誠。", "當悟嘯中旨，可傳言外情。", "臺在聲不傳，萬籟徒汝爭。"]'),
('d5ffff4f-9f33-4f93-9393-85624462bcb6','尉氏五題 七賢里','黄裳','宋','宋诗','song-poetry','','[]','遙想七賢會，空留七賢里。',180,'全唐诗/poet.song.54000.json','["遙想七賢會，空留七賢里。", "神交遺形骸，清流外塵滓。", "脫略墮險怪，嵇阮兩高士。", "白視驕法家，紅鍛傲公子。", "所識不及才，或殆或以死。", "山公頗適用，選職尤可喜。", "立少規不祥，去備憂不軌。", "竊恐阮與嵇，于此未能耳。", "向秀稍知義，由父謾知止。", "酒隠名劉伶，無志君子仕。", "王戎貪聚錢，阮咸亟追婢。", "觀德清流中，二子有臧否。", "修短歸黄埃，毀譽落青史。", "盛世人已非，荒原物空是。", "賢者觀我吟，聊用擇所履。"]'),
('2460a728-76c5-4051-9a67-ecd78b367966','靈草','黄裳','宋','宋诗','song-poetry','','[]','五行在萬類，惟草最柔弱。',96,'全唐诗/poet.song.54000.json','["五行在萬類，惟草最柔弱。", "春至忙發生，秋來遽衰落。", "如何却有靈，陰制長生藥。", "金石走或飛，落鼎誰能捉。", "若乃赤帝兵，飛走請自縛。", "萬鍊致妙用，造化猶天作。", "中抱陰陽精，淺陋安可度。", "莫笑榮復枯，浮生尚堪托。"]'),
('3e26b7d9-f194-4dd0-b9a2-5495865cb48d','歲寒堂','黄裳','宋','宋诗','song-poetry','','[]','歲寒堂前歲寒栢，接見東君無愧色。',96,'全唐诗/poet.song.54000.json','["歲寒堂前歲寒栢，接見東君無愧色。", "正似屠龍方外人，綠鬢還生未垂白。", "酒盃放手情已疏，可鄙當時背文客。", "世態何足留齒牙，且踐清陰坐幽石。", "雲門對面如有情，安得青童報消息。", "莫使仙人開北扉，見我勞生空汩汩。"]'),
('623df9c5-c8f6-4048-a9e5-803ef5599d43','豐提刑理赴西蜀','黄裳','宋','宋诗','song-poetry','','[]','氣柔語音低，欲靜神色明。',180,'全唐诗/poet.song.54000.json','["氣柔語音低，欲靜神色明。", "擾擾勞生中，望道心如傾。", "煩苛患庶士，抵冒悲羣氓。", "眷眷自中降，悠悠傃西征。", "曉霜毛袖重，卯酒面花輕。", "出關誰最舊，過棧子何平。", "施設快拘守，跋涉勞將迎。", "路難休咏蜀，夢遠亦登瀛。", "胸中文藝光，域中監牧榮。", "以淡却私狥，以默靜紛爭。", "萬累喪民德，一嚬生道情。", "行聞化無欲，圜扉芳草生。", "公餘廢俗樂，反一天全精。", "源源踵中來，趨者已屢更。", "安知我所寓，山國望神京。"]'),
('6336ab0e-d40b-40eb-b21e-bfca13d3c0a7','贈靈谷山人','黄裳','宋','宋诗','song-poetry','','[]','無緣一步如秦湘，有緣千里如門牆。',352,'全唐诗/poet.song.54000.json','["無緣一步如秦湘，有緣千里如門牆。", "山人安得不相訪，囗如昔也同行藏。", "自從別後樂何處，靈谷山中養沖素。", "懶與塵凡爭是非，拂袖俄趨長樂府。", "十洞真人懷宿契，陰使來陳掌中示。", "不著乎書惟口傳，千古茫然索根蔕。", "或亂枝條無計尋，大還只欠鉛中金。", "玉簡朱書落吾耳，安用冥搜遶天地。", "紫玄忽見老翁笑，家住崑崙何杳杳。", "神爐已寘龍山椒，蓬壺可聽東溟潮。", "溫泉名界甘復泚，一轂符行坎宮沸。", "七十二候承天時，三五一法明天機。", "晤言再卜春爲期，沖和有道當依歸。", "山水多誇武林好，更有龍椒愜幽抱。", "桃源惟在山腰間，越出寸碧窺吳巒。", "雷驅猛雨玉龍過，月明人上朝元壇。", "五符金鼎任還返，須知造化由陰丹。", "願屈沖和講幽秘，莫獨雲山孕鉛水。", "紫府賓，丹臺身。", "去來在我若爲情，谷風時送步虛聲。", "山花徑，水月沼。", "樂因談到長生妙，偶坐俄行無事了。", "或將得一問因緣，江天爲指歸舟到。"]'),
('88719808-8207-47bc-ae36-343c0c63acee','寄隠者','黄裳','宋','宋诗','song-poetry','','[]','守道宋高士，築室齊東鄙。',120,'全唐诗/poet.song.54000.json','["守道宋高士，築室齊東鄙。", "植竹看歲寒，種田助形委。", "束書捐古今，抱易究生死。", "不以外移內，不以行責止。", "九十留童顔，湖山飽清視。", "或顧先生云，時平可以起。", "先生本無求，棄置如弊屣。", "俄聞與物化，精一未嘗毀。", "汗簡書逸民，義風洗貪士。", "東望呈肺肝，遙瀉一巵水。"]'),
('3cc5c94a-8f2e-4d9c-af67-aed2689ba4a3','送陳知縣','黄裳','宋','宋诗','song-poetry','','[]','握手州東花鬧時，瀉酒胸中如漏巵。',128,'全唐诗/poet.song.54000.json','["握手州東花鬧時，瀉酒胸中如漏巵。", "各無官守竟信意，坐間只有春相隨。", "十年暌遠何所得，但悟世情能守一。", "昨日小軒君不遊，荷葉雨聲池上秋。", "明珠得喪百萬斛，何慮炎蒸金欲流。", "一樽獨對清都夢，可憐幽思無人共。", "今日聞君馬已西，不覺毫端得詩諷。", "汝陽縣長多清風，壺中有客當相送。"]'),
('94c97a1e-7c4c-4932-b92d-816991044f0a','和張仲時次歐陽文公覽李白集之韵','黄裳','宋','宋诗','song-poetry','','[]','紫微所拱皆仙官，開元無事長庚閒。',208,'全唐诗/poet.song.54000.json','["紫微所拱皆仙官，開元無事長庚閒。", "偶緣一念來人間，詩才到白誠無難。", "英華峻發根自天，春空藹藹飛翔烟。", "雲濤雪浪滄溟喧，四面滔滔朝白川。", "重與論文不須細，且貴胸襟寫來易。", "易中自有驚人詞，繩墨空高何足貴。", "苦談杜甫峻談李，文人相輕古如此。", "始惟通道繼而醉，萬事紛紛寧復記。", "三人分散難爲攀，夢魂應覺星躔寒。", "乃與月影同交歡，豈有俗態趨人寰。", "若在真府如同家，瓊丹我已修河車。", "仙源將果蟠桃花，安知不共遊烟霞。", "便看琪園越三島，休羨垂楊與芳草。"]'),
('db3412ac-ea4b-4d8a-b7af-4c111c590eb3','覽武夷記','黄裳','宋','宋诗','song-poetry','','[]','武夷山中十三子，邂逅相尋良有以。',80,'全唐诗/poet.song.54000.json','["武夷山中十三子，邂逅相尋良有以。", "頃向上筵何事醉，一時謫在人間世。", "八百年後還升真，武夷真君真主人。", "天台有籍安得知，不謁子騫誰與祈。", "紫雲中下龍潭雨，尤喜張仙好詩句。"]'),
('9dda0549-1d28-4772-acf2-59a43c17a8b1','結交','黄裳','宋','宋诗','song-poetry','','[]','道義出君子，勢利通小人。',84,'全唐诗/poet.song.54000.json','["道義出君子，勢利通小人。", "有無故所自，甘淡交所因。", "離合見難易，情文生僞真。", "聖主審所任，禍福延吾民。", "賢士慎汝擇，利害歸吾身。", "公患勢利强，私患朋黨親。", "邪正若弗辨，安危難復陳。"]'),
('7c1ed793-7741-4288-a19a-a4891f65507b','留題琴軒','黄裳','宋','宋诗','song-poetry','','[]','軒閣競華麗，誰肯厭絲管。',112,'全唐诗/poet.song.54000.json','["軒閣競華麗，誰肯厭絲管。", "豪華既交歡，盛麗亦同翫。", "鳴弦雖侑觴，惟宜素纖按。", "聲色方爭高，耳目及中亂。", "古意始興懷，曲終情已換。", "黄子尋天真，開軒名以琴。", "問琴意何在，答以琴爲心。", "我願聽以目，與子爲知音。", "無弦之琴聲無聲，世間此曲今何人。"]'),
('0d26fdfc-e963-4925-bd6e-22dcaac87a1f','讀羅隠孟郊集','黄裳','宋','宋诗','song-poetry','','[]','羅隠寓以駡，孟郊鳴其窮。',108,'全唐诗/poet.song.54000.json','["羅隠寓以駡，孟郊鳴其窮。", "始讀鬰吾氣，再味濡我胸。", "如何志與氣，發作瓶甕中。", "大見無賢愚，大樂非窮通。", "棄置二子集，追攀千古風。", "中兼六義異，下與萬物同。", "妙象生丹青，利器資陶鎔。", "心手適相遇，變化從色空。", "感寓復收斂，兀然無我翁。"]'),
('034b6d6a-8aea-49f9-a743-89ac8d2fe312','答仲時高軒小酌之什','黄裳','宋','宋诗','song-poetry','','[]','韓公浩浩樂文字，乃笑紅裙醉豪子。',128,'全唐诗/poet.song.54000.json','["韓公浩浩樂文字，乃笑紅裙醉豪子。", "張侯切切務高潔，亦鄙雙鬟獻回雪。", "東野先生窮且愁，蚯蚓竅中煎百憂。", "北舍主人貧亦歡，典衣取酒更未闌。", "悲愁傷氣豈足尚，揀擇害道非所安。", "空色皆無適相遇，衮衮百年誰自苦。", "太平功業時可爲，萬丈虹蜺不須吐。", "一源湛湛吾忘情，四人毀譽浮漚生。"]'),
('07475f58-5115-4018-baa6-27251cfadea9','送駱君歸隠廬阜','黄裳','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','究竟此生安可逃，凈土社中風最高。',96,'全唐诗/poet.song.54000.json','["究竟此生安可逃，凈土社中風最高。", "紛紛一夢喚不覺，衮衮白頭流落多。", "駱子翻然去尤早，寒堂誓結廬山草。", "寸陰早在精進中，四十司徒未爲老。", "黄紙除書無此期，只爲松雲動幽抱。", "世人發願多自欺，十八逸民今友誰。"]'),
('865e570b-fb9c-4875-9529-19c8606b6d25','遊東山大乘寺','黄裳','宋','宋诗','song-poetry','','[]','奔逸高真避秦侶，遠入閩山豈惟楚。',240,'全唐诗/poet.song.54000.json','["奔逸高真避秦侶，遠入閩山豈惟楚。", "落花流水來何處，遂鹿人從石門路。", "遂造洞門誰得知，雞黍生涯貫今古。", "樵客見留何事去，分合隨緣落塵土。", "回頭已在塵勞中，手把榴花如寐寤。", "紫玄素抱超然情，到此令人心骨清。", "閒跂長林跨深壑，遙見猿鶴來相迎。", "靈源爲我寫幽思，但聞歷歷朱弦鳴。", "獅子峰前狐退藏，當泯頑空還混茫。", "龍首澗邊雲并合，或作人間時雨行。", "杜鵑有聲山意真，杜鵑有花山色明。", "偶逢奇石可且上，幸乘此興聊飛觥。", "顧語娉婷莫予翼，脚力猶爭年少輕。", "三盃通道聊自適，還被谷風吹復醒。", "忽忽流光已云暮，紅燭如林樂聲舉。"]'),
('0a34feca-20bd-456d-8729-840a05aa9ff1','題桃花菊','黄裳','宋','宋诗','song-poetry','','[]','人面亦相映，龍山應獨賞。',72,'全唐诗/poet.song.54000.json','["人面亦相映，龍山應獨賞。", "却因清淡中，艷異尤堪尚。", "靖節籬下吟，幽懷忽馳想。", "武林溪上遊，芳容若迎望。", "妙本自無二，佳名誰有兩。", "辨事惟頼香，根蒂豈容妄。"]'),
('0fbeb696-f9b3-4eca-bc07-95b7dd62f143','題水雲村','黄裳','宋','宋诗','song-poetry','','[]','水雲深處尋幽客，競把銀瓶飛虎珀。',64,'全唐诗/poet.song.54000.json','["水雲深處尋幽客，競把銀瓶飛虎珀。", "坐間玉篆流盃來，時伴桃花獻春色。", "塵勞不到清樽前，何幸山翁設歌席。", "人在夕陽方醉時，回首雲迷武陵宅。"]'),
('aecaab33-ed47-40ac-bc45-5204269ce27d','送方彥稽解元','黄裳','宋','宋诗','song-poetry','','[]','壺公山下多偉人，嘗謂方寸無纖塵。',208,'全唐诗/poet.song.54000.json','["壺公山下多偉人，嘗謂方寸無纖塵。", "雙眼孤鷹在霄漢，俯視燕雀尤有神。", "兩冠羣英出微妙，失第春官恬自笑。", "歸去壺公山下遊，長鬚肩上何所憂。", "遠烟萬劑實行橐，置此雅好吾無求。", "松軒日午片石冷，水中天小雲油油。", "時復窺影且自遣，毫末造化同春秋。", "可能含蓄南國意，洗我滯思如清流。", "方握齊紈却新暑，明月團團滿寰宇。", "馬上塵沙摇不開，空羨江湖鷺輕舉。", "勿因世俗還低頭，義理所在無今古。", "生死只繫簞豆中，誰爲萬鍾移出處。", "六翮沖天觀一飛，所養先須微賤時。"]'),
('5d859719-870e-4b07-8d43-472a4654a5da','道倫竹閣','黄裳','宋','宋诗','song-poetry','','[]','曾看孤山翠微麓，回環閣下千莖竹。',144,'全唐诗/poet.song.54000.json','["曾看孤山翠微麓，回環閣下千莖竹。", "醉吟先生唐室賢，灑落情懷出流俗。", "赤城德士攀高風，特借嘉名榜山腹。", "雪霜難犯爲心虛，直節凌雲聳蒼玉。", "月華弄影無纖塵，合有丹霄鳳來宿。", "趙州庭栢如己知，掃却閒言且觀獨。", "九年當作無生遊，慎勿窺紅墮私欲。", "况是天台掌仙籙，煉礦成金石龍谷。", "落花流水好尋真，豈特蕭蕭閣前綠。"]'),
('def42be1-3b81-480f-9a69-90459a19eb34','曲水亭','黄裳','宋','宋诗','song-poetry','','[]','盤龍偃蹇吸長澗，數篆寒光來向人。',64,'全唐诗/poet.song.54000.json','["盤龍偃蹇吸長澗，數篆寒光來向人。", "誰信雲門有仙子，灑落恐是華筵賓。", "落英俄逐酒船到，世間乃得漁溪春。", "素纖舉盞寧可却，清光聊滌胸中塵。"]'),
('aa9b038d-64a4-4b8c-87ce-3639a52c6421','覽和靖章安西湖之什','黄裳','宋','宋诗','song-poetry','','["\u897f\u6e56"]','和靖苦而豪，章安平而麗。',96,'全唐诗/poet.song.54000.json','["和靖苦而豪，章安平而麗。", "馳情遶佳景，盈軸卷幽思。", "二子各何往，人非物還是。", "四時有行藏，彼物如郵置。", "百年有死生，斯人如夢寐。", "兩幻相追攀，一覺都廢棄。", "感寓聊自娛，興盡娛亦弊。", "安坐湖山間，誰能以數計。"]'),
('aaa446c4-cc14-4b03-ad0c-e5ff43ba5ca2','送人赴官秘閣','黄裳','宋','宋诗','song-poetry','','[]','經行當年已充賦，却遂鹿官走塵土。',288,'全唐诗/poet.song.54000.json','["經行當年已充賦，却遂鹿官走塵土。", "百里牛刀未甘弄，况有文章自當貢。", "屢扣天閽出奇語，落筆紛紛動堯禹。", "雪天得職懷抱清，道山入局憂慮寧。", "今也無慚故鄉舉，幽閒更有登真路。", "惟我曾遊今已古，想見朋從散還聚。", "豈事塗改如排牙，忽落鉛刀得依據。", "常笑蠹魚乾自忙，正似求生轍中鮒。", "學海無從今幾年，謾惜公家費毫楮。", "春芽竟好清晝深，石鼎蠅聲遶庭戶。", "恍然似揖前朝人，高下圖書迓青顧。", "養才此地良有因，入鬧誰醒靜方悟。", "要使中虛心鑑明，乃欲他時照紛遽。", "名利人人情正炎，我抱天君獨爲主。", "設官之意非徒然，君恩可報唯心淵。", "案牒相忘花字閒，養心乃在雲日邊。", "佳氣葱葱指歸處，頓覺身輕如插羽。", "扁舟莫怯霜華濃，已有東風送君去。"]'),
('ef65d758-b98d-449e-9f5a-b192bd11958e','題臥陶軒','黄裳','宋','宋诗','song-poetry','','[]','不爲形役心方縱，乘化悠悠豈須控。',128,'全唐诗/poet.song.54000.json','["不爲形役心方縱，乘化悠悠豈須控。", "歸去來兮歸自公，北窗高臥南來風。", "吹我飄飄骨毛聳，恐是洪濤浸清夢。", "八月仙槎偶相送，寥廓孤飛與誰共。", "天機不逐纖塵動，折腰五斗非君俸。", "靜挂山圖探遙趣，閒眄庭柯薦幽哢。", "君置弦徽貽我聲，我遺耳目知君情。", "相知之流樂如是，五柳鳴蜩謾如沸。"]'),
('8fc672b6-7d7e-4ab4-9159-f959e03daa18','初夏書呈同舍','黄裳','宋','宋诗','song-poetry','','[]','萬種浮華春事了，誰供青帳千林曉。',80,'全唐诗/poet.song.54000.json','["萬種浮華春事了，誰供青帳千林曉。", "雨集池塘螻蟈鳴，蝸牛已過銀鈎橫。", "貼水圓荷蓋猶小，覽鏡美人音耗悄。", "行看天上奇峰生，莫放塵緣空擾擾。", "何處亭臺公外期，共立薰風臨渺渺。"]'),
('0826ffed-6b92-439f-9e7e-a86c92eb4980','暑中喜雨','黄裳','宋','宋诗','song-poetry','','[]','小雨破炎熾，滿懷貯清爽。',24,'全唐诗/poet.song.54000.json','["小雨破炎熾，滿懷貯清爽。", "忽御兩腋風，太虛一登賞。"]'),
('a04edb9c-3db8-450d-88be-c198fe0d7303','重九遣興','黄裳','宋','宋诗','song-poetry','','[]','佳節嘆短晷，清爽愜幽抱。',84,'全唐诗/poet.song.54000.json','["佳節嘆短晷，清爽愜幽抱。", "新故遽相代，意思幸長好。", "百年如秋時，行行越中道。", "重九雖百回，半百已云過。", "雲液傾新醅，籬花摘靈草。", "但約金巵空，何愁玉山倒。", "且趁馬臺遊，莫管龍山帽。"]'),
('09ada2ef-4daf-40c8-87ab-dbe455147555','雙源六題 水閣','黄裳','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','水閣上，襟带水光浮。',38,'全唐诗/poet.song.54000.json','["水閣上，襟带水光浮。", "丹桂月來天漢夜，白蘋風起洞庭秋。", "塵勞人衮衮，瀟灑與誰遊。"]'),
('2fbd5211-67e0-406a-a272-0a8034994919','雙源六題 釣磯','黄裳','宋','宋诗','song-poetry','','[]','釣磯上，閒適向金鱗。',38,'全唐诗/poet.song.54000.json','["釣磯上，閒適向金鱗。", "秋後江邊思膾客，古來溪上得璜人。", "尋幽尋至此，聊寄自由身。"]'),
('cefbfc81-a796-4e7d-bf74-341ba5bc5b9a','雙源六題 澄心堂','黄裳','宋','宋诗','song-poetry','','[]','澄心堂上閒來客，水與心同誰見得。',32,'全唐诗/poet.song.54000.json','["澄心堂上閒來客，水與心同誰見得。", "微風不過波瀾休，無礙空中秋月白。"]'),
('442327c7-59c8-4cae-81be-9d653ac65c9b','雙源六題 濯纓堂','黄裳','宋','宋诗','song-poetry','','[]','濯纓之水山幽幽，本來似鑑無庸流。',48,'全唐诗/poet.song.54000.json','["濯纓之水山幽幽，本來似鑑無庸流。", "到此令人肝膽醒，滌除萬累開襟靈。", "一源莫誤登臨目，紛紛世上紅塵足。"]'),
('cbcff7ea-451f-47d3-aa55-4088b3b34a02','雙源六題 重蓮軒','黄裳','宋','宋诗','song-poetry','','[]','宛轉雙源花在處，花葉重重瑞炎暑。',64,'全唐诗/poet.song.54000.json','["宛轉雙源花在處，花葉重重瑞炎暑。", "日光相照鉛華鮮，翠蓋紛紛擁紅女。", "不貪青子老芳容，薰風偷出香無數。", "乃知源上有神仙，何必夭桃隨水去。"]'),
('b4a2e077-f21d-42ca-9532-a64e7543d119','雙源六題 日休亭','黄裳','宋','宋诗','song-poetry','','[]','分外鑿私智，役役壯且老。',60,'全唐诗/poet.song.54000.json','["分外鑿私智，役役壯且老。", "此生本自然，何者削窘我。", "止水觀而心，運用無不可。", "玉液靜中味，萬累門外過。", "時復一盃酒，聊用沃心火。"]'),
('63210c38-66ce-4f9c-875c-ffb6e93a7538','寄臥雲先生','黄裳','宋','宋诗','song-poetry','','[]','臥雲先生由內觀，謂使妻子忘我難。',160,'全唐诗/poet.song.54000.json','["臥雲先生由內觀，謂使妻子忘我難。", "顧予且不自有父，安得有汝爲悲歡。", "武林溪上乃所寄，今且幾歲無往還。", "源頭流水去復去，落花繽紛春屢殘。", "秦人漢世不須問，寂然自在桃花灣。", "嵩嶽遊人忽相逐，羣碧插空三十六。", "漁人不見空懷想，路迷山口今誰訪。", "幾時行，幾時歸。", "本無行止吾何疑，豈將眼力隨塵機。", "行亦可，歸亦可。", "長沮桀溺非通道，此生未必山中老。"]'),
('3a90072f-c32e-4482-ad9f-a86c2707052b','五祖長老惠竹簟','黄裳','宋','宋诗','song-poetry','','[]','六月如蒸火方老，三伏炎炎撓清抱。',112,'全唐诗/poet.song.54000.json','["六月如蒸火方老，三伏炎炎撓清抱。", "閒中雨汗林末悄，忽得禪師祖山耗。", "笛材未許龍鳳吟，却織雙紋愜高臥。", "卷送西來尤是時，乃似烏薪雪天到。", "長鬚爲我掃幽榻，數尺漣漪細風過。", "謾入祖山何所聞，但覺雷聲肅慵墮。", "欲酬此意知未能，且學文公贈相好。"]'),
('ee851784-0de6-4cc2-9803-87f59341578b','贈方外士','黄裳','宋','宋诗','song-poetry','','[]','擾擾紅塵高臥客，紅塵不染人難識。',64,'全唐诗/poet.song.54000.json','["擾擾紅塵高臥客，紅塵不染人難識。", "琅琅爲講還丹篇，若有清風濯胸臆。", "玉兔走入流珠宮，正向時人失中得。", "根本蓋自仙翁傳，仙翁住世千餘年。"]'),
('f10af65d-12c0-4184-886a-52ce5ee8ee1f','贈崔風子','黄裳','宋','宋诗','song-poetry','','[]','崔風不風人莫測，只恐時人問消息。',96,'全唐诗/poet.song.54000.json','["崔風不風人莫測，只恐時人問消息。", "子聞妙道今幾年，百刻光陰貫今昔。", "天柱峰頭獨看月，火裏青龍産芽雪。", "屋上無霜春勢强，十二危樓電光徹。", "劍潭居士心相從，何時遂扣逍遙翁。", "自知心骨異凡物，豈願老死浮生中。"]'),
('5c998ffa-89ee-46cd-98b7-651edf7c3564','貽李道士','黄裳','宋','宋诗','song-poetry','','[]','道士初來鶴衣白，無事猖狂走南北。',80,'全唐诗/poet.song.54000.json','["道士初來鶴衣白，無事猖狂走南北。", "偶得秘訣烟霞間，鬼谷先生眼睛碧。", "謂我當接王公談，且與天庭二分術。", "儻來已感仙翁靈，占夢夢中宜自驚。", "妙光照物乃是道，結廬歸去南山青。"]'),
('75fae3b1-83d0-482d-8552-15c997eb0aa2','琴軒','黄裳','宋','宋诗','song-poetry','','[]','聲音求我皆邪道，有琴可聽非深造。',32,'全唐诗/poet.song.54000.json','["聲音求我皆邪道，有琴可聽非深造。", "無弦弦上聲無聲，世間此曲今何人。"]'),
('03ea86f8-75c8-403c-af22-a534d68f9066','仙會樓','黄裳','宋','宋诗','song-poetry','','[]','金碧崢嶸演山脚，合有雲駢下寥廓。',112,'全唐诗/poet.song.54000.json','["金碧崢嶸演山脚，合有雲駢下寥廓。", "自嗟本是烟霞翁，一念人間已知錯。", "聞說樓成歸思濃，想見羣真多綽約。", "水虎火龍方得傳，看破浮生豈能縛。", "夜深時獨倚欄干，誰見金花當面落。", "此道既與羣真同，雖隔霄壤常相通。", "演客千載無遺蹤，佇聞杖履來相從。"]'),
('089e5f69-927e-4e5c-aeb5-8e48264296cd','讀王黄州遊官篇','黄裳','宋','宋诗','song-poetry','','[]','感義區區謀國士，竟爲升平模稜子。',64,'全唐诗/poet.song.54000.json','["感義區區謀國士，竟爲升平模稜子。", "抗章言事來去忙，左提右挈歸之理。", "見姓書名安且榮，寧問賢愚落青史。", "隠居到此當忘言，對月且倒無憂罇。"]'),
('bc7103cc-56fa-4ba5-8278-228c70c7f297','積雪','黄裳','宋','宋诗','song-poetry','','[]','能積又能亡，時高又時低。',72,'全唐诗/poet.song.54000.json','["能積又能亡，時高又時低。", "圭璧隨所寓，陵谷豈可齊。", "夷坦掩曲徑，勿使狐生疑。", "光明破宿靄，勿使雞求棲。", "在臘方得時，此意非爾知。", "知我爲餘寒，不知爲繁禧。"]'),
('a03fb7ea-82df-4cbb-9eb4-06fa4426666e','交遊','黄裳','宋','宋诗','song-poetry','','[]','率爾相會遇，欣然同醉吟。',48,'全唐诗/poet.song.54000.json','["率爾相會遇，欣然同醉吟。", "意外談笑易，胸中矛戟深。", "契合好甘醴，聽聞嫌正音。", "交結自此始，刎頸當知心。"]'),
('66a896ef-5669-48a2-b287-ef1d6e02bd0e','酬程忠彥見寄  其一','黄裳','宋','宋诗','song-poetry','','[]','新吟走長鬚，喜鵲鳴高枝。',36,'全唐诗/poet.song.54000.json','["新吟走長鬚，喜鵲鳴高枝。", "邂逅固有分，非人所能期。", "對坐俯寒壁，得予尤相宜。"]'),
('4d5b6899-c2d6-4fe6-ab59-a449302cccc2','酬程忠彥見寄  其二','黄裳','宋','宋诗','song-poetry','','[]','進取俄比肩，歡笑亦傾蓋。',36,'全唐诗/poet.song.54000.json','["進取俄比肩，歡笑亦傾蓋。", "一夢長相尋，尋子江天外。", "子來慰所思，苦吟酬適會。"]'),
('e9252746-47b5-4c08-8044-eec59abb8bea','酬程忠彥見寄  其三','黄裳','宋','宋诗','song-poetry','','[]','京塵化我衣，吳風變子語。',36,'全唐诗/poet.song.54000.json','["京塵化我衣，吳風變子語。", "二人還相逢，道在無今古。", "薰澤何所爲，本無緇與素。"]'),
('5fd9ea7c-086d-4ec1-8070-931bc0c6882a','酬程忠彥見寄  其四','黄裳','宋','宋诗','song-poetry','','[]','儒林小官冷，僕馬略勝步。',36,'全唐诗/poet.song.54000.json','["儒林小官冷，僕馬略勝步。", "竹素園中遊，青眼勞一顧。", "孰與歐廬間，閒雲自來去。"]'),
('db0f80f7-eb97-40a2-9712-d4c4965ea801','酬程忠彥見寄  其五','黄裳','宋','宋诗','song-poetry','','[]','側承雙筩聲，自作天籟鳴。',36,'全唐诗/poet.song.54000.json','["側承雙筩聲，自作天籟鳴。", "聳耳願一聽，使我泠然清。", "誰云吳儂音，能變中正情。"]'),
('7201f4cb-ed2f-4c96-b567-671865843bbf','送紀宣教','黄裳','宋','宋诗','song-poetry','','[]','名利場中化君子，偶得延平二高士。',128,'全唐诗/poet.song.54000.json','["名利場中化君子，偶得延平二高士。", "王子好談兼好行，行如不及談如傾。", "此生根蒂果安在，寧復計校枯與榮。", "紀子忘知更忘說，行所當然孰云別。", "坐間自有雷霆聲，何事區區論標月。", "二子躬行人所稀，但恐東野無由隨。", "香爐峰前幾時過，興龍禪師故鄉老。", "草堂夜話燈影寒，瞬息春風我先到。"]'),
('20d6e265-aead-4239-a4ef-60349d938bd9','貽儒生','黄裳','宋','宋诗','song-poetry','','[]','含章緣俊雅，發理自聰明。',72,'全唐诗/poet.song.54000.json','["含章緣俊雅，發理自聰明。", "德行孔庭秀，公卿唐彀英。", "博嫌愚作弊，文恐僞爲情。", "御世教方盛，動人風更清。", "反三雖稍悟，得一豈須驚。", "竟置伊周列，難忘齊魯生。"]'),
('36050a87-b6c3-4292-925a-23a0e6f2c322','送公表判官解官南歸','黄裳','宋','宋诗','song-poetry','','[]','污吏物勝志，俗吏勢勝義。',252,'全唐诗/poet.song.54000.json','["污吏物勝志，俗吏勢勝義。", "志義不可勝，勢物如脫屣。", "古云士大夫，此道既墜地。", "俯首拾蹴與，仰視忽高致。", "仕塗無清風，大望失所寄。", "志士獨懷古，義氣已屢喟。", "從事彭城公，不求亦不忮。", "接下斷驕簡，清慎遣外累。", "三載日猶短，六計滿物議。", "薦章何所歸，見敬乃虛器。", "得喪固有命，失士豈無愧。", "顧我眼力壯，古貌入青視。", "方恨相得晚，笑語未獲醉。", "官滿不可留，年華促歸計。", "雨後雲既收，日上春已至。", "雙水勢愈活，南注飛不洎。", "兩山夾長流，稍稍有青意。", "此景送君何處遊，荔枝林下維扁舟。", "窮通身外不足念，醉吟可寫塵中憂。", "至誠所與暫睽遠，時復一嚏聊相求。"]'),
('28181c1c-505e-4776-9753-8f330bc771f6','贈謝殿元','黄裳','宋','宋诗','song-poetry','','[]','風自東山吹厥後，義重生輕公所有。',64,'全唐诗/poet.song.54000.json','["風自東山吹厥後，義重生輕公所有。", "懷抱應書霜雪明，一封十事龍鱗輕。", "青雲失志蕡無悔，且喜歲寒柯未改。", "名節稍從言路愛，待向烏臺觀慷慨。"]'),
('744aafe8-b700-4ffc-8a4c-6724d206cacc','東湖留題 雲門館','黄裳','宋','宋诗','song-poetry','','[]','冥冥出世既云往，急急度人還復來。',64,'全唐诗/poet.song.54000.json','["冥冥出世既云往，急急度人還復來。", "會當爲物落城市，誰探北扉開未開。", "下視東秦在諸掌，一念已到非蓬萊。", "與子邂逅固有分，况是胸臆無纖埃。"]'),
('3be680a1-19d8-4365-b502-5b431f5f1efa','東湖留題 鷺下亭','黄裳','宋','宋诗','song-poetry','','[]','白鷺下遙水，青銅絕纖埃。',48,'全唐诗/poet.song.54000.json','["白鷺下遙水，青銅絕纖埃。", "窺魚風色定，移渚客聲來。", "事傃明明遣，樽臨渺渺開。", "靜憐閒意好，爲過夕陽回。"]'),
('a96e297e-6aa6-49d1-bffa-f98d19231d9d','東湖留題 釣璜臺','黄裳','宋','宋诗','song-poetry','','[]','想見海濱老，坐觀臺畔清。',48,'全唐诗/poet.song.54000.json','["想見海濱老，坐觀臺畔清。", "一綸聊自適，萬戶本無情。", "魚躍心機靜，鷹閒世事平。", "行藏天意在，千古跂功名。"]'),
('30495bfc-e267-45df-8fc7-03b19190eb20','東湖留題 駐興橋','黄裳','宋','宋诗','song-poetry','','[]','方上大鼇背，俄生五湖心。',24,'全唐诗/poet.song.54000.json','["方上大鼇背，俄生五湖心。", "急急遊此道，擾擾休相尋。"]'),
('84a6f78b-b10c-45b5-a106-f2db1cfd91ee','東湖留題 步虛橋','黄裳','宋','宋诗','song-poetry','','[]','俯仰是天漢，陟降非世路。',24,'全唐诗/poet.song.54000.json','["俯仰是天漢，陟降非世路。", "常聞步虛詞，時聳採蓮女。"]'),
('84ec0c70-3464-4b40-b3c4-665d15f08dc1','東湖留題 鴛鴦渚','黄裳','宋','宋诗','song-poetry','','[]','江海風波外，陰陽化育中。',24,'全唐诗/poet.song.54000.json','["江海風波外，陰陽化育中。", "相隨還戢翼，得性渚西東。"]'),
('3298401e-7a65-42d0-bec6-a6a66a93af22','東湖留題 鴻雁渚','黄裳','宋','宋诗','song-poetry','','[]','兼忘物我翫鷗客，自得行藏遵渚鴻。',32,'全唐诗/poet.song.54000.json','["兼忘物我翫鷗客，自得行藏遵渚鴻。", "看破眼前人與物，紫玄翁在小橋東。"]'),
('a9943d61-c67a-43e8-8757-3f5f9a59e5d5','東湖留題 翫鷗亭 其一','黄裳','宋','宋诗','song-poetry','','[]','水面浮沈聊自適，人心得喪便相疑。',32,'全唐诗/poet.song.54000.json','["水面浮沈聊自適，人心得喪便相疑。", "徘徊聽我樽前唱，莫道機忘了不知。"]'),
('342b9db0-f8ca-49a0-986a-fbcf0cd0d641','東湖留題 翫鷗亭 其二','黄裳','宋','宋诗','song-poetry','','[]','意息機乃息，人忘鷗亦忘。',48,'全唐诗/poet.song.54000.json','["意息機乃息，人忘鷗亦忘。", "逍遙方自得，邂逅豈相妨。", "靜見水天闊，閒知春日長。", "浮沈無一累，誰更問行藏。"]'),
('e7af6774-de27-467e-8192-f12e8e4337a8','東湖留題 綠巖亭','黄裳','宋','宋诗','song-poetry','','[]','半巖亭勢俯漣漪，北顧尤宜鷺下時。',32,'全唐诗/poet.song.54000.json','["半巖亭勢俯漣漪，北顧尤宜鷺下時。", "終是謫仙風思好，無情常與月相期。"]'),
('d894499c-83b6-49ca-bffc-4dd7535d3444','東湖留題 歌豐堂','黄裳','宋','宋诗','song-poetry','','[]','禮樂看公暇，陰陽報歲豐。',80,'全唐诗/poet.song.54000.json','["禮樂看公暇，陰陽報歲豐。", "四并當共樂，一氣已相通。", "歡笑壺天上，清虛色界中。", "可歸猶待月，未放曲聲終。", "可喜年豐自忙少，豈特明明得歡笑。", "三樂光陰誰與知，但向魯詩尋政要。"]'),
('01c2314b-ce3a-4f36-8ce5-f0f7db5a2ff3','東湖留題 醉歸亭','黄裳','宋','宋诗','song-poetry','','[]','醉舞既成樂，醉歸還有儀。',48,'全唐诗/poet.song.54000.json','["醉舞既成樂，醉歸還有儀。", "漣漪閒自囗，渾沌有誰知。", "噦噦鸞鳴處，振振鷺起時。", "忘歸忘未得，方釋魯公詩。"]'),
('883a022c-a080-41b4-a5ea-e45c05e06344','東湖留題 水鑑亭','黄裳','宋','宋诗','song-poetry','','[]','蘋藻風初定，鸞鳳匣已開。',48,'全唐诗/poet.song.54000.json','["蘋藻風初定，鸞鳳匣已開。", "有時開妙象，無處拂纖埃。", "樂共世人到，醉從天漢回。", "不知誰作記，寥廓臥樓臺。"]'),
('dd56d82e-acf8-4dc5-9ea8-d7284ab26bfc','東湖留題 竹林齋','黄裳','宋','宋诗','song-poetry','','[]','桃溪出世境，竹林居士鄉。',48,'全唐诗/poet.song.54000.json','["桃溪出世境，竹林居士鄉。", "中虛秘天韵，外直凌秋霜。", "靜久世味淡，翠深人意凉。", "觸目多俗物，見君何日忘。"]'),
('3d3c8f78-e48e-447e-bccc-1c96bd9e01ec','東湖留題 湘江亭','黄裳','宋','宋诗','song-poetry','','[]','休論湘江僞與真，楚花窺影玉霄春。',32,'全唐诗/poet.song.54000.json','["休論湘江僞與真，楚花窺影玉霄春。", "琴聲如鼓如妃子，豈意相投似故人。"]'),
('e9b5eb75-5a24-4eb2-82de-662e87335259','東湖留題 桃溪庵','黄裳','宋','宋诗','song-poetry','','[]','灼灼芳意鬧，涓涓朱弦鳴。',120,'全唐诗/poet.song.54000.json','["灼灼芳意鬧，涓涓朱弦鳴。", "晴光發清淺，翠華相合并。", "寒涘通遊徑，清盃得落英。", "且慰浮生勞，勿念閒名輕。", "桃溪日日流，弗止何獨行。", "桃花年年開，既落還復榮。", "昔聞避世士，有物應混成。", "不行亦不止，不死亦不生。", "祇聞莊學羨，俄失何必驚。", "此語誰與解，住庵如登瀛。"]'),
('4d16d346-697d-4cce-a743-d174be833f83','東湖留題 贈周生','黄裳','宋','宋诗','song-poetry','','[]','七峰山下無塵客，方寸有能人未識。',96,'全唐诗/poet.song.54000.json','["七峰山下無塵客，方寸有能人未識。", "風吹山水意飄飄，月照市廛機寂寂。", "將使居人聞此聲，既澄世慮虛生白。", "英華滿軸非春能，銀鈎更有千鈞力。", "忽然欲運胸中奇，一揮時落雲間壁。", "何當便跨圖南鵬，聲意相尋七峰側。"]'),
('37b6ec2c-0d92-4c9b-8b14-eeb39ce8c58d','經遊湆澹留題澄寂軒','黄裳','宋','宋诗','song-poetry','','[]','湆澹險怪士，氣馬如狂濤。',108,'全唐诗/poet.song.54000.json','["湆澹險怪士，氣馬如狂濤。", "趨蹶日萬變，風石常相遭。", "浮沈有命在，險易如人何。", "此累稍稍遠，十里無橫波。", "劍潭澄寂客，注酌無喪得。", "狂心到此闌，觀水還無觀。", "蟾光中夜靜，銀色滿襟寒。", "謾對浮屠笑，若心應了了。", "莫看灘上湧，但取潭中照。"]'),
('a09528b3-564e-4a30-8ce9-8377fc21ff26','昭君行','黄裳','宋','宋诗','song-poetry','','[]','良家有子惠而秀，昔在漢宮誰更有。',336,'全唐诗/poet.song.54000.json','["良家有子惠而秀，昔在漢宮誰更有。", "入宮見妬名不傳，咫尺君王望恩久。", "柰何賦分薄如人，却屬畫工爲好醜。", "千金買笑那敢當，無賂應嗟落人後。", "俄聞召見喜且驚，自以閒雅文輕盈。", "將謂君王必回顧，行且遂承恩與榮。", "權兼天下失所制，女子未免匈奴行。", "此身既係國休戚，君王雖悔難復更。", "雪怨雲愁竟何語，自小誰知北征苦。", "既知中華棲上清，乃托胡人爲死生。", "平居悵望一成夢，用傃遐荒尋去程。", "胸前但殞默默淚，門外已抗悠悠旌。", "轅馬悲鳴日云遠，行經幾處單于城。", "平沙莽莽春不青，頑陰漫漫天不明。", "隨無鴛鴦歡悅情，送有琵琶哀怨聲。", "大抵言意非吾類，眷眷向前愁益并。", "寧落家鄉作孀婦，焉用閼氏尊予名。", "人惟適性乃有樂，未必膏粱勝藜藿。", "當時將相若爲策，豈意安邊用顔色。", "君雖不幸功可稱，莫道佳人只傾國。", "思歸曲在人已非，青塚空悲塞南客。"]'),
('c4868def-3fcc-4f28-bd20-3abca08f878f','燕子樓','黄裳','宋','宋诗','song-poetry','','[]','盼盼初歸樓上時，想如燕子長雙飛。',160,'全唐诗/poet.song.54000.json','["盼盼初歸樓上時，想如燕子長雙飛。", "有才將色世間少，况復節義猶堪依。", "將軍一去十餘載，玉簫瑶瑟無心解。", "豈不能死空相隨，以色累公非所知。", "白老曾爲賦詩客，風裊花枝醉無力。", "後會勳郎漢陽驛，因語歔欷已成昔。", "走筆還賡美人句，猶感白楊堪作柱。", "我來登賞非唐人，尚引多情聊愴神。", "人生真盡皆爲塵，百年一餉難留春。", "高樓人散誰復親，只有燕子年年新。"]'),
('950ac2c4-29f4-4564-86c2-173e9db90fe9','春日寄友人','黄裳','宋','宋诗','song-poetry','','[]','青春可愛如才華，使人詩思如楊花。',336,'全唐诗/poet.song.54000.json','["青春可愛如才華，使人詩思如楊花。", "飄然去來不可繫，又似春雲靄然起。", "惟人適性而樂生，子雲閉戶非其情。", "亦曾郊上爲遊人，兩袖香風雙眼明。", "葉下鶑鶑兒女語，聲聲似喚遊人住。", "忽睹狂蝶過他枝，一带深黄又飛去。", "倒樽取醉花枝側，我是主人春是客。", "胸襟不貯世俗事，酒力相攻易相失。", "青銅三百慚子慳，乃至解佩窮清歡。", "萬事亨途誰滿意，百年生計自開顔。", "樽前兀兀坐者誰，頹然醉倒春風間。", "歌者自歌舞者舞，塵機不動天真閒。", "呼童伸牋走吟筆，醉字欹斜不能立。", "楚狂韓子傾餘才，感春章句如花開。", "兕觥入手滔滔瀉，此後摇毫如駿馬。", "數子苦醉俱分飛，夕陽含山空翠微。", "乃自曲肱臥芳草，蝴蝶與周何所疑。", "紅杏風來吹我起，黄粱成飯還多時。", "醉亦如醒夢如覺，勿于四者分毫釐。", "聊與物化天地中，願君與我閒相從。", "郊上之遊速爲報，春風欲放桃花老。"]'),
('c457ea74-bb2e-4f37-82aa-7578de8617df','中秋月','黄裳','宋','宋诗','song-poetry','','[]','秋容瘦，秋聲寂。',184,'全唐诗/poet.song.54000.json','["秋容瘦，秋聲寂。", "浮雲散盡霜宇寒，未見疏星點空碧。", "升自東方人望濃，十二回圓喜今夕。", "窺澄江，開暗室。", "閃閃金銀動宮闕，森森冷雪排劍戟。", "秋氣清，秋色白。", "六陰中處金權高，清白合并成此魄。", "玉兔搗藥將何爲，應造神丹送仙伯。", "乘興高人無定筵，瓊步徘徊未須急。", "金波汗漫清人神，桂華飄渺明人衣。", "邀月已作明年期，月是人非寧復悲。", "倒盡芳樽臥清影，休問醉翁歸未歸。", "是非今古乃常理，此情莫落霜娥耳。"]'),
('f5c3be0f-60aa-4860-8d0e-930db64f6d7b','送王慎中','黄裳','宋','宋诗','song-poetry','','[]','爲貧爲仕我與君，失意以歸南北雲。',267,'全唐诗/poet.song.54000.json','["爲貧爲仕我與君，失意以歸南北雲。", "豈把去留論適莫，豈因得喪悲離合。", "人是人非春覺夢，物來物去花開落。", "攀緣一斷六塵空，緣至乃施無斧鑿。", "不求脫，不與縛，君期萬法無憂樂。", "不可減，不可增，君期一性無虧成。", "世人{土適}埴誰知己，不怨不知知不喜。", "塵縈嘗與衆凡悲，流轉域中而已矣。", "君之入道人不知，不得已事君不爲。", "天然淡薄日一飯，心機不用如嬰兒。", "聞其風者少當愧，此道亦更清于夷。", "君歸休，白心碧眼非庸流。", "內觀無物四肢墮，性天虛闊陰雲收。", "君歸去，曉猿夜鶴無尋處。", "爐中靈藥果誰傳，林下老人終共語。", "何時我向江邊來，相從方外幽懷開。", "長願爲雲逐東野，莫教風思生塵埃。"]'),
('d6651778-18f5-4d08-832d-93f57f7c3145','再遊普光寺','黄裳','宋','宋诗','song-poetry','','[]','春來時，春紅照我銜清盃。',88,'全唐诗/poet.song.54000.json','["春來時，春紅照我銜清盃。", "老僧樸野自合道，只從一笑忘形骸。", "秋時到，詩翁清瘦秋容老。", "吟成興盡可以歸，一雨巖前恰初過。", "勞生自適能幾人，白雲流水誰相親。", "黄金滿屋莫使悟，悟便輸他方外春。"]'),
('aa49e248-58ea-4082-8396-fc920df33dd2','中秋日賓興宴','黄裳','宋','宋诗','song-poetry','','[]','九十秋分今夜景，銀色界中秋意靜。',135,'全唐诗/poet.song.54000.json','["九十秋分今夜景，銀色界中秋意靜。", "獻賢時入帝王州，鼓瑟筵開山水境。", "西風勁，衫袖冷。", "遙度天香到酒邊，中有醉翁吹復醒。", "徘徊態，淩亂影。", "急須行樂慰勞生，相得相忘無食頃。", "姮娥信，諸生聽。", "一年人愛此回圓，十分仙桂都開盡。", "自有清光隨我身，遊寶蠟何須秉。", "明年誰是奪標人，史君推轂今何幸。"]'),
('e56d50fa-60d4-4ff3-8bfb-22e4268c50b7','贈天台禪鑒','黄裳','宋','宋诗','song-poetry','','[]','逸興東西自難卜，快可追風白花足。',264,'全唐诗/poet.song.54000.json','["逸興東西自難卜，快可追風白花足。", "巾飄飄，蓑蔌蔌。", "每引三盃通道瓢，即陳一闋離塵曲。", "獨忘懷，人注目。", "恐是秦漁來混俗，落花流水難拘束。", "幾度桃花春又復，戲翫人生榮與辱。", "石火光中寄此生，故山休問歸遲速。", "東秦別後無行蹤，忽見回轅自西蜀。", "二十光陰一轉頭，新白已能班舊綠。", "偶懷起滅寒生粟，蓋亦超然坐觀獨。", "便望雲山歸去來，無生之師在巖谷。", "由禪而入從真修，休效諸山編語錄。", "如來藏裏磨尼珠，走上玉爐光斷續。", "螺髻明，鵲巢驚。", "向死生中脫死生，象罔得之方始靈。", "掃除物我雙何有，懷抱乾坤一混成。", "十三位上窺憂喜，正法眼開無處避。", "是時人道真仙子，方尚圖中舊行止。"]'),
('b25b7556-97e0-4bd2-ab81-952f350c5cac','通道瓢吟','黄裳','宋','宋诗','song-poetry','','[]','通道三盃太和好，已同五氣誰能到。',280,'全唐诗/poet.song.54000.json','["通道三盃太和好，已同五氣誰能到。", "漸造醉鄉方自然，忽體杳冥如得道。", "坐上一時能兩忘，萬緣既斷非吾我。", "須期有物渾成時，先自醉鄉聊得耗。", "若從泰定真相逢，含盡三才是懷抱。", "道方喪物無閒愁，休管垂楊與芳草。", "感懷偶向桃溪路，落花流水年年去。", "仙家日月無古今，此景示人人不悟。", "青衣爲我折幽芳，待插陶巾訪真侶。", "笑而迎，寂而處，五行自是無尋處。", "空將日月怨春風，日月烏能離得數。", "但明結果自然成，到了無生無一句。", "聖賢絕口自難言，愚衆摇頭誰可度。", "青衣兩畔長鬚後，駸駸小駿山間走。", "光陰猶長渭川叟，幸有雲山靜中壽。", "大道盃，自然斗。", "天遊杳杳長庚吟，天樂陶陶紫玄酒。", "宛如對月成二人，九老圖中有無有。"]'),
('fc5be46f-9a17-44be-a860-98ce11583e1b','謝莊顔延之吟','黄裳','宋','宋诗','song-poetry','','[]','千里共明月，彼此惟月知。',144,'全唐诗/poet.song.54000.json','["千里共明月，彼此惟月知。", "音信雖不聞，有月難爲詢。", "對月祇自恨，中夜還窺人。", "姝子想無寐，瞻望應敷陳。", "既然默默得心腑，那更徐徐入庭戶。", "因笑延之題，歿爲長不歸。", "一息已云往，寧復爲歸期。", "稚子亦自曉，安用延之持。", "希逸辨既妄，徒洩延之非。", "兩詩寓意囗囗好，雲海沈沈杳無耗。", "紅顔銷盡那得聞，惟勝知之遇凶暴。"]'),
('84b62383-c19c-4c1a-a9a9-500d3cc05300','喧犬行','黄裳','宋','宋诗','song-poetry','','[]','禦惡不禦良，守實不守空。',100,'全唐诗/poet.song.54000.json','["禦惡不禦良，守實不守空。", "主人得犬勝高墉。", "有堯汝喧喧，有跖汝默默。", "主人得犬勝幽賊。", "犬也徐有云，容犬對以臆。", "犬爲跖守即吠堯，犬爲堯守即吠跖。", "是則庸犬而已矣，比犬之良汝何益。", "穿窬得間無人疑，喪家之犬將何之。"]'),
('034a10db-21cb-4dc1-b11c-12727a47f800','懵鷹行','黄裳','宋','宋诗','song-poetry','','[]','兩翅一展秋雲高，兩睛四顧秋林肅。',112,'全唐诗/poet.song.54000.json','["兩翅一展秋雲高，兩睛四顧秋林肅。", "狐兔忽落爪距下，肝腦須臾厭其腹。", "是藝汝有固有性，是物汝得固有命。", "韝上如何寄此身，休誇豪氣與精神。", "一雉死生非所必，有數存焉擒不獲。", "主人失意未可量，鷹也兩失而行藏。", "中陵自在無由樂，飽則翱翔饑則攫。"]'),
('72396d7c-29b5-4633-ba7c-8b2b291dd0af','巧蛛行','黄裳','宋','宋诗','song-poetry','','[]','柔絲轉危簷，結網日初卯。',108,'全唐诗/poet.song.54000.json','["柔絲轉危簷，結網日初卯。", "條理滿腹中，萬慮無一攪。", "紀綱國政强，經緯天理巧。", "所吐勤如簇上蠶，所織巧如機上婦。", "婦織一尺長，蠶吐一兩多，輕暖之利爲春和。", "蜘蛛兼有蠶婦事，蜘蛛獨爲身腹計。", "此勤不必爲，此巧不可施，慮有無意空中飛。"]'),
('d117c714-2780-4767-bb30-3239b7b9eefa','元會次宰臣之韵  其一','黄裳','宋','宋诗','song-poetry','','[]','風吹香信下丹霄，遠望如雲共戴堯。',64,'全唐诗/poet.song.54000.json','["風吹香信下丹霄，遠望如雲共戴堯。", "誰詣獸樽心諤諤，獨贏經席氣飄飄。", "千靈已得回春律，萬歲何須却老椒。", "弗愧陰陽開妙化，先天方許與公調。"]'),
('dc616247-ba70-4e34-92fa-9d889de45cc8','元會次宰臣之韵  其二','黄裳','宋','宋诗','song-poetry','','[]','玉皇宮殿得春朝，冠綬紛紛百辟朝。',64,'全唐诗/poet.song.54000.json','["玉皇宮殿得春朝，冠綬紛紛百辟朝。", "未見魚龍供漢戲，已聞星露入虞韶。", "清都夢到驚華麗，寒谷春回喜富饒。", "付史幾多祥瑞事，終隨和氣作歡謠。"]'),
('c2a187ea-7fdf-486e-90ed-6f0908b15271','元會次宰臣之韵  其三','黄裳','宋','宋诗','song-poetry','','[]','太極朝正小道消，豈勞身勢借扶摇。',64,'全唐诗/poet.song.54000.json','["太極朝正小道消，豈勞身勢借扶摇。", "履新忽聽傳天語，革故初看轉斗杓。", "四面橫龍嚴部樂，兩班垂玉肅朋僚。", "不教計吏空歸去，雨露相隨詔五條。"]'),
('c0132894-3b91-4552-995e-92493481ae92','侍宴池上','黄裳','宋','宋诗','song-poetry','','[]','來侍君王看物華，紫微深處宴忠嘉。',64,'全唐诗/poet.song.54000.json','["來侍君王看物華，紫微深處宴忠嘉。", "萬年獻壽金巵酒，百世尊王綺席花。", "振鷺朋從靈沼闊，遊鱗音耗綵絲斜。", "仙源此景須吟盡，留與人寰處處誇。"]'),
('aadb78a8-88d9-4477-8659-e063db6e61d9','集英殿考試酬唱  其一','黄裳','宋','宋诗','song-poetry','','[]','玉皇親自策才猷，誰作靈鼇上釣鈎。',64,'全唐诗/poet.song.54000.json','["玉皇親自策才猷，誰作靈鼇上釣鈎。", "俊思內窺天問邃，韶光中看御香浮。", "尚懷獻藝趨前列，何幸持衡綴上流。", "欲向鸞輿心未放，更須銀燭始回頭。"]'),
('f623663e-afae-4f98-95c0-6ca101246a80','集英殿考試酬唱  其二','黄裳','宋','宋诗','song-poetry','','[]','磊落英游誤許陪，相望樓閣倚雲開。',64,'全唐诗/poet.song.54000.json','["磊落英游誤許陪，相望樓閣倚雲開。", "春風暗遞天香到，星使俄傳帝語來。", "紫府已知仙籍就，清都還逐化龍回。", "彀中喜得辭如海，不是區區小有才。"]'),
('683c8077-764a-41b9-b1bd-ffad3b0d529f','集英殿考試酬唱  其三','黄裳','宋','宋诗','song-poetry','','[]','靜窺千卷喜才華，不恨詩情未到花。',32,'全唐诗/poet.song.54000.json','["靜窺千卷喜才華，不恨詩情未到花。", "欲醉春風歸去近，曉來新得數聲鴉。"]'),
('f1bfc6b6-b662-47e8-bf5a-1ce274f14642','集英殿考試酬唱  其四','黄裳','宋','宋诗','song-poetry','','[]','雨過春空紫泰高，列星初擁絳紗袍。',64,'全唐诗/poet.song.54000.json','["雨過春空紫泰高，列星初擁絳紗袍。", "三題天漢文章麗，萬字秋鷹氣勢豪。", "聊欲彎弓須尚志，謾勞談律莫吹毛。", "行看衫色青于草，不覺南溟失素濤。"]'),
('dddcd436-de1a-4f90-bdcb-7a038632f213','集英殿考試酬唱  其五','黄裳','宋','宋诗','song-poetry','','[]','紫微方夢斷，燈火解嚴時。',48,'全唐诗/poet.song.54000.json','["紫微方夢斷，燈火解嚴時。", "日欲銜龍闕，風先掃鳳池。", "自憐夜氣在，誰笑道冠欹。", "豈爲雲團惜，消閒頼有詩。"]'),
('4bb51a0a-69a7-4458-88fa-3ee86dea1e30','降虜來朝次葉尚書韵','黄裳','宋','宋诗','song-poetry','','[]','頑虜勞戎索，神機屈睿謨。',72,'全唐诗/poet.song.54000.json','["頑虜勞戎索，神機屈睿謨。", "鷹鸇臨遠帳，狐兔落清都。", "勇逐龍韜喪，驚隨虎士趨。", "瞻天蒙覆育，塗地脫須臾。", "即看宣登版，何煩禹泣辜。", "但聞多屬國，五鳳似元符。"]'),
('a7655400-01ef-45b2-9c7c-e457daa432c6','次門下侍郎東省懷左丞之韵','黄裳','宋','宋诗','song-poetry','','[]','喜看韓孟作雲龍，同御天衢萬里風。',64,'全唐诗/poet.song.54000.json','["喜看韓孟作雲龍，同御天衢萬里風。", "詩入中臺推戴敏，月來東省照盧公。", "祠庭拜貺精誠共，試殿逢知學問同。", "廣樂數聲誰敢和，但疑身在化人宮。"]'),
('ac4581a1-c605-450a-9f36-4f79cc9188c9','次東閣內翰感舊之韵','黄裳','宋','宋诗','song-poetry','','[]','二十星霜一轉頭，坐間誰共昔年遊。',64,'全唐诗/poet.song.54000.json','["二十星霜一轉頭，坐間誰共昔年遊。", "是非擾擾夢還覺，榮謝紛紛春復秋。", "罇俎且看圖籍府，風雲方命帝王州。", "金蓮花燭公歸處，此更仙源最下流。"]'),
('951fc0c9-a78e-40a0-ad5d-0cfdee9fc1d8','青社宴遣貢士','黄裳','宋','宋诗','song-poetry','','[]','曉來門外駐鸞聲，且喜東藩俊造成。',64,'全唐诗/poet.song.54000.json','["曉來門外駐鸞聲，且喜東藩俊造成。", "行藝簿多窗下志，賢能書振日邊名。", "琴風清躍西征騎，璧水寒窺上舍生。", "佳兆豈惟多吉士，三元從古有豪英。"]'),
('216dd721-4e3c-4ba5-bec7-11baa872905c','次常父著作曝書之韵','黄裳','宋','宋诗','song-poetry','','[]','內閤儒方集，先朝事不忘。',144,'全唐诗/poet.song.54000.json','["內閤儒方集，先朝事不忘。", "曝書開綺席，偃武斂牙璋。", "籤軸陳千古，金朱萃一堂。", "日華窺鳥迹，冰艷照金觴。", "已掃斷簡蠹，更增東壁光。", "士高閒粹語，天近覽幽香。", "見博思唐庫，恩新仰舜廊。", "名山纔向曉，振鷺已成行。", "官職塵勞少，朋從語笑長。", "但慚甘若醴，寧恨冷如漿。", "小說誅瀰漫，雄文薦煒煌。", "培風誰有志，從此好南翔。"]'),
('21e0dea7-77ca-4ee4-ba6f-f9a2b731441c','送都鈐郭太尉','黄裳','宋','宋诗','song-poetry','','[]','將帥門庭喜見人，只看行止早堪親。',64,'全唐诗/poet.song.54000.json','["將帥門庭喜見人，只看行止早堪親。", "軍人事業離羣久，帳下謀猷觸類新。", "東土別懷應有恨，西都歸思已無塵。", "故園未許閒遊日，丹鳳重飛不到春。"]'),
('70c5d89a-ca95-4afc-9845-3ef13233f1e6','送中吳太守','黄裳','宋','宋诗','song-poetry','','[]','華省人閒去領麾，出關風景正相宜。',64,'全唐诗/poet.song.54000.json','["華省人閒去領麾，出關風景正相宜。", "唐虞民物氣和日，吳楚江山秋靜時。", "語接鄉音尤喜近，舟行蓮渚莫嫌遲。", "古云循吏君知否，先悟無爲始有爲。"]'),
('1295525d-963c-47d4-a7e1-db21b57f8e2c','送袁運判赴荆湖','黄裳','宋','宋诗','song-poetry','','[]','未果爲雲逐去龍，楚江行處玉涵空。',64,'全唐诗/poet.song.54000.json','["未果爲雲逐去龍，楚江行處玉涵空。", "斡旋地利來天上，籠絡人才入彀中。", "仕路莫驚離合易，貢闈猶想笑言同。", "龍山便到秋還近，幽興從他落帽風。"]'),
('d8de9786-1fba-4154-8bd7-d36271eafc2a','陳瑩中赴定遠','黄裳','宋','宋诗','song-poetry','','[]','秀發風神子也都，想因塵果下栟櫚。',96,'全唐诗/poet.song.54000.json','["秀發風神子也都，想因塵果下栟櫚。", "一階道在誰窮達，百里才多自卷舒。", "北闕瞻言蟬靜後，東山歡笑麥寒初。", "便須養氣觀雙劍，豈暇回頭較一豬。", "無事謾留工部句，有時閒落右軍書。", "漢榮楚辱人休問，且聽弦歌出舊徐。"]'),
('1ec10bf7-f9a8-42be-b631-41dcfa514545','送衡州太守','黄裳','宋','宋诗','song-poetry','','[]','幾度明庭聚又分，玉皇香落衆中聞。',64,'全唐诗/poet.song.54000.json','["幾度明庭聚又分，玉皇香落衆中聞。", "忽拋桂玉泛隋水，便擁旌麾穿楚雲。", "岣嶁山高尋禹誌，蒹葭江遠憶韓文。", "隨車多少南飛雁，先向秋風得使君。"]'),
('f451095d-2e06-4623-bccc-c77dbe9b6a5f','送袁志行戶曹','黄裳','宋','宋诗','song-poetry','','[]','十年場屋費才華，謾有詩名子可嗟。',64,'全唐诗/poet.song.54000.json','["十年場屋費才華，謾有詩名子可嗟。", "未入儒林升俊造，且行春雨到天家。", "遠乘澤國三秋月，高跨天河八月槎。", "道阻且長瞻不及，空吟霜露滿蒹葭。"]'),
('c8b60f64-d4b5-426e-a633-e26511f03e28','贈呂夢得','黄裳','宋','宋诗','song-poetry','','[]','壯年場屋便歸休，趨向逍遙獨自遊。',64,'全唐诗/poet.song.54000.json','["壯年場屋便歸休，趨向逍遙獨自遊。", "貧後誰知心匪石，老來猶更氣橫秋。", "人無直道君難合，詩有清風我怕酬。", "香爇一爐經一卷，紅塵應是懶回頭。"]'),
('7491c714-3b70-4009-8dee-a6d761d1d27a','次齊守巖老見示東湖之韵  其一','黄裳','宋','宋诗','song-poetry','','[]','近將餘事作東湖，公外閒來物外居。',64,'全唐诗/poet.song.54000.json','["近將餘事作東湖，公外閒來物外居。", "蓮吐花時看晉社，桃隨流處得秦漁。", "放懷把酒須尋友，適性垂綸豈問魚。", "報我故人三樂意，翠珉新刻右軍書。"]'),
('1e8a4481-c8a3-4278-b88a-5d45cfb0e831','次齊守巖老見示東湖之韵  其二','黄裳','宋','宋诗','song-poetry','','[]','月華西下日華東，閃閃湖光渺渺中。',64,'全唐诗/poet.song.54000.json','["月華西下日華東，閃閃湖光渺渺中。", "天地會通銀色界，亭臺還合水晶宮。", "披襟望處清生白，穿徑遊時翠引紅。", "自許此生心已了，湖山尤稱道家風。"]'),
('68c7e17f-de26-4384-b93a-7ae498f5c87c','次齊守巖老見示東湖之韵  其三','黄裳','宋','宋诗','song-poetry','','[]','共辭蘭省作諸侯，更領東蕃第一州。',32,'全唐诗/poet.song.54000.json','["共辭蘭省作諸侯，更領東蕃第一州。", "萬事了時尋好景，兩崗盤處得寒流。"]'),
('4493792c-9744-4366-b5a8-9f0567837748','送王道原判官','黄裳','宋','宋诗','song-poetry','','[]','言無枝葉色無塵，自是中間已悟真。',64,'全唐诗/poet.song.54000.json','["言無枝葉色無塵，自是中間已悟真。", "且免此生占噩夢，更從何處卜通津。", "徘徊州縣諳多事，荏苒江湖過幾春。", "三已轉官歸吏隠，蓮花池上友何人。"]'),
('33339cbc-5524-4c0e-adb9-5c34c781ee9f','和馮達夫小沼之什','黄裳','宋','宋诗','song-poetry','','[]','坐間長愛水相從，間鑿方池貯碧空。',64,'全唐诗/poet.song.54000.json','["坐間長愛水相從，間鑿方池貯碧空。", "十尺清泠雖有限，一襟瀟洒已無窮。", "龜魚世界東西近，河漢光芒上下通。", "數卷芰荷時得雨，洒然如在楚江中。"]'),
('00d28107-fa92-4daf-a4aa-cde41ce0bf0b','寄五峰長老','黄裳','宋','宋诗','song-poetry','','[]','自從南去失歸期，海嶼生涯祖一支。',64,'全唐诗/poet.song.54000.json','["自從南去失歸期，海嶼生涯祖一支。", "百歲塵緣誰尚在，五峰禪老獨應知。", "且看秋水呈千月，謾寫雲山寄一詩。", "邂逅有時言笑處，越王臺下擁旌麾。"]'),
('52e91174-27c3-4152-b1d9-0a0731e3adb6','送斛絳侍親之官','黄裳','宋','宋诗','song-poetry','','[]','解顔而笑偶相從，澄寂潭邊五載中。',64,'全唐诗/poet.song.54000.json','["解顔而笑偶相從，澄寂潭邊五載中。", "學道南來無爾隠，侍親西去有誰同。", "夜歌一劍胸中氣，卯酒三盃馬上風。", "塞北功名須黽勉，自來渾厚出山東。"]'),
('865e41ab-b0d6-4b45-acfc-522c2078ec80','寄鵝湖佛智長老','黄裳','宋','宋诗','song-poetry','','[]','十年光景一回頭，聞住鵝湖且六周。',64,'全唐诗/poet.song.54000.json','["十年光景一回頭，聞住鵝湖且六周。", "堂上雷鳴通妙用，鼎中龍伏得真修。", "報恩香篆雲山曉，傳法心涵水月秋。", "莫笑紫玄翁未去，已懷烟浪作扁舟。"]'),
('9c45f2a3-5d98-43c5-98f6-56fc47e02e19','會黄正臣','黄裳','宋','宋诗','song-poetry','','[]','北山亭上共看書，少壯相逢氣尚粗。',64,'全唐诗/poet.song.54000.json','["北山亭上共看書，少壯相逢氣尚粗。", "樂事每聞高義長，病文嘗借遠烟塗。", "樽罍且慰人離合，龜鑑應知我有無。", "蟋蟀在堂年又晚，欲邀鄉語負寒爐。"]'),
('31b0b107-9712-4507-aa0c-f56558f50c36','雪中泛舟','黄裳','宋','宋诗','song-poetry','','[]','雲漢雙眸冷，瑶池兩槳輕。',48,'全唐诗/poet.song.54000.json','["雲漢雙眸冷，瑶池兩槳輕。", "六花來酒面，萬霰作蓬聲。", "虛實終何有，高低已混成。", "拏舟緣此景，豈爲戴君行。"]'),
('25830850-9156-4189-8486-473aced7184d','題妙光堂','黄裳','宋','宋诗','song-poetry','','[]','獨坐夜如晝，相投清與明。',72,'全唐诗/poet.song.54000.json','["獨坐夜如晝，相投清與明。", "風微塵跡悄，波定月華輕。", "此景方中見，何人性上生。", "涵虛難立象，照物自無情。", "寶鑑非鎔就，靈珠乃混成。", "忽驚居士眼，一點與强名。"]'),
('c07d36bd-7afc-4ca4-814b-5358197c0bda','書懷呈同志','黄裳','宋','宋诗','song-poetry','','[]','處己心雖白，逢君眼更青。',48,'全唐诗/poet.song.54000.json','["處己心雖白，逢君眼更青。", "獨來還得侶，相照即忘形。", "用意誰無累，開襟自有靈。", "遞年何所樂，終日醉遺經。"]'),
('7a6594b7-6b0a-4256-b365-a02c6e9611eb','秋雨喜霽','黄裳','宋','宋诗','song-poetry','','[]','陽光方接物，陰蔽已開關。',48,'全唐诗/poet.song.54000.json','["陽光方接物，陰蔽已開關。", "水落盈虛定，雲收去就閒。", "菊花窺曉日，松影撼秋山。", "滯思可乘興，一聯還解顔。"]'),
('891f71c2-b257-41c1-8fd3-1acc02980416','錢塘山居早起','黄裳','宋','宋诗','song-poetry','','[]','熟了黄粱一覺眠，起來身在紫霄邊。',64,'全唐诗/poet.song.54000.json','["熟了黄粱一覺眠，起來身在紫霄邊。", "林巒已淡東傾月，旗鼓將嚴北渡船。", "岑碧漸分雲外境，陽光初動海中天。", "夙興夜寐人空老，難把塵勞綰謫仙。"]'),
('6c295b5f-2c6d-4d61-95dd-ffa616c60a1c','澄清軒','黄裳','宋','宋诗','song-poetry','','[]','開軒何處野塘清，靜見蒲魚作隊行。',64,'全唐诗/poet.song.54000.json','["開軒何處野塘清，靜見蒲魚作隊行。", "亦似養源知物理，始能遊刃到民情。", "雖非渺渺鑑湖闊，豈少亭亭秋月明。", "多謝松庭無外事，不教風浪此中生。"]'),
('77190be1-7267-44aa-a5e4-5cd1cbd604c2','拂雲軒','黄裳','宋','宋诗','song-poetry','','[]','却塵兼却暑，非市亦非郊。',48,'全唐诗/poet.song.54000.json','["却塵兼却暑，非市亦非郊。", "龍孕雪中種，鳳翻雲外梢。", "蕭蕭天籟作，淡淡月華交。", "切玉歲寒味，供餐無外餚。"]'),
('3b5098f7-445d-43eb-982c-8053b0d2dab2','雪','黄裳','宋','宋诗','song-poetry','','[]','雲上江天意已濃，化機先下隔年功。',64,'全唐诗/poet.song.54000.json','["雲上江天意已濃，化機先下隔年功。", "明吞夜後梅花月，狂弄春前柳絮風。", "清悟胸襟吟更逸，寒驚毛骨醉還空。", "漁簑歸去豈其樂，相賀惟聞田舍翁。"]'),
('be2f4c76-6059-4fb7-acdf-8242bacc6037','梅花','黄裳','宋','宋诗','song-poetry','','[]','素呈天巧未教青，雲釀寒時一望明。',64,'全唐诗/poet.song.54000.json','["素呈天巧未教青，雲釀寒時一望明。", "且得少陽通好信，不消孤笛送新聲。", "絳綃捧蕊誰粧就，金粟含鬚自綴成。", "最是百花難比處，只承風信已知名。"]'),
('d8a676c3-16cb-4033-a167-6fe1a5c871f9','泛湖','黄裳','宋','宋诗','song-poetry','','[]','放船初向白公樓，渺渺天光簇簇洲。',64,'全唐诗/poet.song.54000.json','["放船初向白公樓，渺渺天光簇簇洲。", "綠竹岸深疑士隠，紫烟波遠恐仙遊。", "賓朋欲散且看月，風俗雖忙猶買舟。", "最好四山環繞處，一家中占五湖秋。"]'),
('53ca13c6-dd3f-44da-a15e-a6dc2d7758a1','偶成示道溫','黄裳','宋','宋诗','song-poetry','','[]','何當歸臥水雲鄉，不必功名似子房。',64,'全唐诗/poet.song.54000.json','["何當歸臥水雲鄉，不必功名似子房。", "一黍精華空色大，百年行數古今長。", "誰知擾擾還三得，獨向冥冥遣兩忘。", "少室山頭星月近，紫微垣下起天香。"]'),
('dc7cea3d-b055-4fda-933f-0895af94b7f9','歸燕','黄裳','宋','宋诗','song-poetry','','[]','掃迹各安在，托身誰與爲。',48,'全唐诗/poet.song.54000.json','["掃迹各安在，托身誰與爲。", "安危應擇主，去就尚知時。", "春暖語尤巧，海遙歸較遲。", "畫堂人有德，可放繡簾垂。"]'),
('9a323974-1eb4-40ae-b88f-36a17e5e748f','寄及之','黄裳','宋','宋诗','song-poetry','','[]','南飛長是夢相尋，海角何妨寄好音。',64,'全唐诗/poet.song.54000.json','["南飛長是夢相尋，海角何妨寄好音。", "有客交遊多革面，無君談笑少開襟。", "家山荔子邀誰賞，澤國荷花憶共吟。", "秋後西來無爽約，遙郊當候馬駸駸。"]'),
('22734a4b-20a9-4437-879f-a16cfbdaac58','初秋偶作','黄裳','宋','宋诗','song-poetry','','[]','火行金候兩猶爭，擾擾蚊蠅自未平。',64,'全唐诗/poet.song.54000.json','["火行金候兩猶爭，擾擾蚊蠅自未平。", "雲漏雨聲蒸地爽，日含山色暮天明。", "直須紈扇恩情斷，始向籬花意態生。", "萬里璧寒無一點，月明中看雁初橫。"]'),
('d4e0e739-e7f9-4f04-82cb-fb251707ba72','除夜呈張公實','黄裳','宋','宋诗','song-poetry','','[]','兩年相見此宵中，萬里家山與子同。',64,'全唐诗/poet.song.54000.json','["兩年相見此宵中，萬里家山與子同。", "百歲未垂雙鬢白，六骰先獻一盆紅。", "莫嗟雪臘回頭盡，且約金巵到手空。", "過隙浮生聊自慰，明朝行樂屬春風。"]'),
('b94a6f65-b1f8-49ef-9940-11f5cc015f54','客暑因書昔日山居之樂','黄裳','宋','宋诗','song-poetry','','[]','憶昔幽居最道情，水邊林下寄勞生。',64,'全唐诗/poet.song.54000.json','["憶昔幽居最道情，水邊林下寄勞生。", "靜眠片石無閒夢，深入寒雲有笑聲。", "壯了一心塵事滿，別來三歲客身輕。", "功成便遂歸歟興，待與青山歃一盟。"]'),
('c4607ac4-afda-4cac-b8e2-106d4e3810dd','秋暑喜雨','黄裳','宋','宋诗','song-poetry','','[]','不害爲霖未可收，煩襟相憚暑相投。',64,'全唐诗/poet.song.54000.json','["不害爲霖未可收，煩襟相憚暑相投。", "水簾檻外霏霏晝，銀漢雲中點點秋。", "別館休論欹客枕，釣潭尤憶看漁舟。", "催成天色純如璧，白酒黄花欲上樓。"]'),
('5541e3bf-a50d-4a90-a636-bc05751c4a10','試院中秋夜月','黄裳','宋','宋诗','song-poetry','','[]','秋色中分夜，金行旺氣中。',48,'全唐诗/poet.song.54000.json','["秋色中分夜，金行旺氣中。", "邇遐人望別，內外桂華同。", "澄澈曾經雨，娉婷欲御風。", "三人歡已斷，猶鎖武成宮。"]'),
('33fe7c2a-051f-4292-9171-f7e29bc286a6','貢院上元','黄裳','宋','宋诗','song-poetry','','[]','精舍喧譁外，華燈想望中。',48,'全唐诗/poet.song.54000.json','["精舍喧譁外，華燈想望中。", "管弦何處客，簾幕去年風。", "好斁隨塵起，悲歡覆手空。", "蟾光無內外，自與此心同。"]'),
('2bcff40f-ecb7-4959-89e8-0dfee11ba0dc','還鄉有感','黄裳','宋','宋诗','song-poetry','','[]','別來身在利名邊，三十春風兩少年。',64,'全唐诗/poet.song.54000.json','["別來身在利名邊，三十春風兩少年。", "問勞只聞新子弟，悲歡還見舊山川。", "客塵况味今無念，雨露情懷夙有緣。", "不向洞霄歸未得，此官猶是地行仙。"]'),
('9a176c7d-ef59-4eb2-86b9-180ef94df59f','和章樞密西齋','黄裳','宋','宋诗','song-poetry','','[]','公餘誰解憩勞生，不動天機性自靈。',64,'全唐诗/poet.song.54000.json','["公餘誰解憩勞生，不動天機性自靈。", "道骨對山尤更好，夢魂聞雨易爲醒。", "謾拋芽雪歸仙鼎，只把筌蹄看聖經。", "還顧一源無去住，雙梧惟有翠盈庭。"]'),
('536032c9-0379-4f44-a472-fd15e804b64b','次陳子真見別  其一','黄裳','宋','宋诗','song-poetry','','[]','懶散先生恐是仙，幾時來上鑑湖船。',64,'全唐诗/poet.song.54000.json','["懶散先生恐是仙，幾時來上鑑湖船。", "水雲共賞更誰可，氣概相投還自然。", "憂樂未當隨外物，窮通何必問他年。", "解顔一笑樽前話，各向閒中見性天。"]'),
('321cb217-33a0-4112-af6f-63af7c391e24','次陳子真見別  其二','黄裳','宋','宋诗','song-poetry','','[]','行軒猶遠五雲溪，烟雨霜風去魯遲。',32,'全唐诗/poet.song.54000.json','["行軒猶遠五雲溪，烟雨霜風去魯遲。", "浄眼看山應是好，北來須乞送行詩。"]'),
('a36cea1b-35a0-48bf-9ef0-2ac3751dc392','觀潮  其一','黄裳','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','吳國人從越國回，兩舠旗鼓急相催。',64,'全唐诗/poet.song.54000.json','["吳國人從越國回，兩舠旗鼓急相催。", "悠悠二氣已交感，隠隠一聲還到來。", "銀漢風波生沆瀣，玉龍雷雨出蓬萊。", "周天安用蓮花漏，自有潮軒與月臺。"]'),
('04697927-8333-442e-a232-66911d35ce4d','觀潮  其二','黄裳','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','杳冥中信自輪回，十二時行不可催。',64,'全唐诗/poet.song.54000.json','["杳冥中信自輪回，十二時行不可催。", "纔迫海門三級起，忽臨沙渚二龍開。", "水頭花雨凌空落，日脚雲旗動地來。", "果是尾閭虛不得，却還江上一徘徊。"]'),
('15f99c1d-b01a-41fc-9548-57ea08c5ba92','觀潮  其三','黄裳','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','密窺神化自陰陽，雲御雷車不可當。',32,'全唐诗/poet.song.54000.json','["密窺神化自陰陽，雲御雷車不可當。", "吹倒玉山風信惡，蛟龍回首也須忙。"]'),
('ff033422-c27c-4fe3-94c5-d0521b244948','觀潮  其四','黄裳','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','十州基址難淪沒，二浙源流且遡洄。',32,'全唐诗/poet.song.54000.json','["十州基址難淪沒，二浙源流且遡洄。", "秋信最宜吳地看，雪峰飛向越溪來。"]'),
('c59c01a5-f64f-4b33-90c6-e0c26ad55702','次陳殿院遊洞霄','黄裳','宋','宋诗','song-poetry','','[]','杖屨相尋爲愛山，來朝山盡到林巒。',64,'全唐诗/poet.song.54000.json','["杖屨相尋爲愛山，來朝山盡到林巒。", "真源立己今猶古，清氣臨人暑亦寒。", "巖溜飛來春雨瀉，洞霄歸去海鵬翻。", "紫霄名位緣何事，了取無中一粒丹。"]'),
('c2b3e678-36eb-4dae-9e23-8abed60bd3aa','秋日苦雨','黄裳','宋','宋诗','song-poetry','','[]','漫漫雲無隙，紛紛稻有芽。',48,'全唐诗/poet.song.54000.json','["漫漫雲無隙，紛紛稻有芽。", "久懷暘谷日，空想暮天霞。", "睡美夜聲碎，坐寒風脚斜。", "秋光猶未盡，相望有黄花。"]'),
('11175699-4e9f-4f01-bf75-5abb6f76eac4','聽隠士琴','黄裳','宋','宋诗','song-poetry','','[]','心手相忘到混成，又非湘瑟與秦箏。',64,'全唐诗/poet.song.54000.json','["心手相忘到混成，又非湘瑟與秦箏。", "秋來獨坐水邊石，古往誰知弦上聲。", "易度寸心閒有味，難諧羣耳淡無情。", "夕陽回首山猶好，更起松風一段清。"]'),
('78a15b52-7e65-49d6-93b4-4b399a2ade23','送翟司業赴南康  其一','黄裳','宋','宋诗','song-poetry','','[]','烏臺章疏風霜勁，璧水詩書日月閒。',64,'全唐诗/poet.song.54000.json','["烏臺章疏風霜勁，璧水詩書日月閒。", "萬事自來如義命，一麾誰去得湖山。", "嘗聞訟少公庭下，但見閒多宴坐間。", "明月幾時隨太守，香爐峰下看禪還。"]'),
('a9778744-cb6a-43ac-b6ef-df742ddd7e73','送翟司業赴南康  其二','黄裳','宋','宋诗','song-poetry','','[]','國子先生行最淳，紅顔猶足照青春。',64,'全唐诗/poet.song.54000.json','["國子先生行最淳，紅顔猶足照青春。", "神仙廬下分符遠，父老鄉中衣錦新。", "畫舸欲飛初得雨，煩襟如洗乍離塵。", "從來官職清于水，好爲江山作主人。"]'),
('bea6539e-2a2a-4066-82c1-4f5013199e0c','酬友人見寄','黄裳','宋','宋诗','song-poetry','','[]','纔得新詩寫我憂，荆溪何日與君遊。',64,'全唐诗/poet.song.54000.json','["纔得新詩寫我憂，荆溪何日與君遊。", "久爲江國三年客，長憶仙公一洞秋。", "共有幽懷堪把手，誰無忙事且回頭。", "忽乘清興拏舟去，準擬香牋作唱酬。"]'),
('593e17f9-111e-402d-88a0-178cac01384f','寄題溪堂','黄裳','宋','宋诗','song-poetry','','[]','華堂深在翠微間，瀲灧波光照客顔。',64,'全唐诗/poet.song.54000.json','["華堂深在翠微間，瀲灧波光照客顔。", "歸隠輸君塵外樂，留題偷我日邊閒。", "心忘機後鷗相識，日落山時鶴自還。", "小艇得魚無事了，歌聲移向荻花灣。"]'),
('5767b529-6034-4fa7-a25e-ba83aab6f2f2','送柴伯通歸衢梁','黄裳','宋','宋诗','song-poetry','','[]','晚入荷華一葉香，羨君歸興滿仙鄉。',64,'全唐诗/poet.song.54000.json','["晚入荷華一葉香，羨君歸興滿仙鄉。", "他年上國來須早，今夜中秋別太忙。", "雖厭風波同客路，已憐松栢共秋霜。", "東來傳舍無多地，勤寄新詩莫我忘。"]'),
('84a1bd17-e5e5-43ed-a84a-48e6b0cdd25f','寄清退君章大夫','黄裳','宋','宋诗','song-poetry','','[]','故人閒適地行仙，林下邀誰共暮年。',64,'全唐诗/poet.song.54000.json','["故人閒適地行仙，林下邀誰共暮年。", "把酒應思天際客，登樓俄上水南船。", "懶看小吏呈朝報，靜聽高僧說世緣。", "華髮未輸頭上白，更期携手劍溪邊。"]'),
('5848f7de-3b04-4fe2-a0f2-ce3845b6a680','春日喜晴','黄裳','宋','宋诗','song-poetry','','[]','天意分明人意開，便聞歌管上春臺。',64,'全唐诗/poet.song.54000.json','["天意分明人意開，便聞歌管上春臺。", "綠堤風暖投衫袖，紅檻花光落酒盃。", "雲結陰容俄散去，蝶驚晴影旋飛來。", "芳菲猶在無多日，倚取韶光作醉媒。"]'),
('34d88c27-fa21-4154-be08-a2a8f79ebec2','寄王之道','黄裳','宋','宋诗','song-poetry','','[]','蘭陵爲別又多時，花月妖中想見幾。',64,'全唐诗/poet.song.54000.json','["蘭陵爲別又多時，花月妖中想見幾。", "鄉國可憐猶間隔，客途何故更分飛。", "身邊無事樂雖樂，堂上有親歸未歸。", "欲寄新文將遠信，尚須勤苦到精微。"]'),
('cce58bf4-35e8-41a3-85fd-5942fc19b862','長樂宴遣貢士','黄裳','宋','宋诗','song-poetry','','[]','賢能書扣九天門，安用區區更問津。',64,'全唐诗/poet.song.54000.json','["賢能書扣九天門，安用區區更問津。", "周室笙歌聲調古，孔庭詩禮指歸新。", "吟窺清璧還爲侶，笑謝寒齋已作賓。", "烝我時髦尤利市，使君元是奪標人。"]'),
('a82178de-c240-4206-9742-ed1d652493d0','遊開平書貽佛智長老','黄裳','宋','宋诗','song-poetry','','[]','訪我京華歲已深，化龍潭畔却相尋。',64,'全唐诗/poet.song.54000.json','["訪我京華歲已深，化龍潭畔却相尋。", "是空是色休排色，非佛非心且洗心。", "南望自生江上月，西歸誰了水中金。", "洞霄人去寧無夢，多在蓮池與竹林。"]'),
('fdde00c5-eb05-4a0a-91e9-bc6523fbb084','寄袁思與','黄裳','宋','宋诗','song-poetry','','[]','京華爲別各蹉跎，猶幸相逢笑與歌。',64,'全唐诗/poet.song.54000.json','["京華爲別各蹉跎，猶幸相逢笑與歌。", "風雅長言先進少，遊從高義故人多。", "雖知塵境先忘累，尤念玄宮未處和。", "行欲超然無一事，便當求我向烟蘿。"]'),
('ab7a9f6d-3e09-4552-acde-f3a26964dd12','與南京留守','黄裳','宋','宋诗','song-poetry','','[]','澤國旌麾十幾秋，一封曾去辱青眸。',64,'全唐诗/poet.song.54000.json','["澤國旌麾十幾秋，一封曾去辱青眸。", "吹噓寸草風猶在，倚傍長松夢未休。", "借取謾勞閩士論，召還聊寄宋王州。", "宿源洞裏南湖上，似得雙溪有樂不。"]'),
('67d99f5d-4406-44da-b880-84c1f41288cf','中和堂見雙蓮呈張內翰','黄裳','宋','宋诗','song-poetry','','[]','兩萼雙房並一枝，誰家姝子上西池。',64,'全唐诗/poet.song.54000.json','["兩萼雙房並一枝，誰家姝子上西池。", "鵲橋牛女共遊夜，湘浦皇英相會時。", "曉鑑鬭粧肩笑倚，秋林同賞步慵移。", "行看閣老重歸去，花獨來迎此可知。"]'),
('cc5f0539-3a91-4f94-baf9-3f4f60e3d4a2','次大野雙源水閣','黄裳','宋','宋诗','song-poetry','','[]','長爲雙源夢舊遊，西風吹動白蘋秋。',64,'全唐诗/poet.song.54000.json','["長爲雙源夢舊遊，西風吹動白蘋秋。", "得君昨日數聯景，寫我此懷無限愁。", "但看清虛堪寄足，豈須衰老始抽頭。", "小漁船上好相訪，烟雨中乘丁字流。"]'),
('44e2a2f0-9cbd-4491-8613-3e859921ba82','送陳子真  其一','黄裳','宋','宋诗','song-poetry','','[]','木笏青衫便染塵，久思風骨始知真。',64,'全唐诗/poet.song.54000.json','["木笏青衫便染塵，久思風骨始知真。", "有無悟道何妨仕，俯仰趨時只爲貧。", "靜向畫圖看五驥，急來華省侍雙親。", "茶園送客詩猶在，空恨芳罇失故人。"]'),
('860058b1-6219-47b3-bd7e-7836788e6ca7','送陳子真  其二','黄裳','宋','宋诗','song-poetry','','[]','拙翁甘與外臺廉，只此勞生想自占。',64,'全唐诗/poet.song.54000.json','["拙翁甘與外臺廉，只此勞生想自占。", "人我是非雙累重，古今榮辱一塵纖。", "便遊澤國尋鱸市，忽落仙帆傍酒帘。", "案上簿書看得未，養真當有智隨恬。"]'),
('9dcb8b20-69a2-4a2c-b347-8b6d9794d382','感舊書呈彭城太守','黄裳','宋','宋诗','song-poetry','','[]','屈指朋從共愴神，不知原上幾回春。',64,'全唐诗/poet.song.54000.json','["屈指朋從共愴神，不知原上幾回春。", "靜緣老去忘餘事，樂自閒來得故人。", "雲日雖牽琳館夢，旌麾聊慰雪窗身。", "老彭樓下人安在，千古都歸一笑嚬。"]'),
('0c44bb55-b0c5-43b8-9ccd-b568e02a561b','觀菊','黄裳','宋','宋诗','song-poetry','','[]','盈盈金色带秋光，淡淡仙粧只着黄。',64,'全唐诗/poet.song.54000.json','["盈盈金色带秋光，淡淡仙粧只着黄。", "嘗共故人休獨樂，笑同今日更誰忙。", "方嗟老取年華近，尚喜花留日數長。", "爲掇繁英還爲撚，莫辜纖素在君傍。"]'),
('a271f141-75d1-4296-802c-67b4a6221eea','贈葛侍郎','黄裳','宋','宋诗','song-poetry','','[]','三品顯官知分退，數株靈草對春栽。',64,'全唐诗/poet.song.54000.json','["三品顯官知分退，數株靈草對春栽。", "已馳吏政青編上，却御仙風紫府來。", "琴寫幽懷心火息，酒陶和氣面花開。", "應憐仕路多華髮，不把松雲爲己催。"]'),
('6adcc670-3f89-4b62-8c8b-27177327a259','自警','黄裳','宋','宋诗','song-poetry','','[]','一日少一日，一年無一年。',48,'全唐诗/poet.song.54000.json','["一日少一日，一年無一年。", "頓門何處入，秘旨有誰傳。", "憂樂波生水，光陰箭去弦。", "幾時能得了，坐臥莫忘禪。"]'),
('dac8b416-ac95-4cc7-b59c-7a7aa6ab59cc','贈張山人','黄裳','宋','宋诗','song-poetry','','[]','極數幽人百尺松，歲寒枝節引清風。',64,'全唐诗/poet.song.54000.json','["極數幽人百尺松，歲寒枝節引清風。", "世途險易拋身外，人事榮枯落掌中。", "藥有靈根秋轉活，面多和氣老猶紅。", "行人借問生前事，何事天津久未通。"]'),
('fc1aa2eb-971d-44d0-a356-29ddfec5284a','贈傳神師','黄裳','宋','宋诗','song-poetry','','[]','闕下遊多日，溪邊過幾春。',48,'全唐诗/poet.song.54000.json','["闕下遊多日，溪邊過幾春。", "數圖人欲活，一筆自如神。", "不寫俗中態，漫留雲外身。", "丹青如模我，道貌似山人。"]'),
('a6d38a00-c1e5-4e6b-90d2-089e1d3fa89e','對菊閒飲','黄裳','宋','宋诗','song-poetry','','[]','良辰惟有菊前盃，十五蟾光已看回。',64,'全唐诗/poet.song.54000.json','["良辰惟有菊前盃，十五蟾光已看回。", "白蟻醱醅凉後熟，黄金蓓蕾夜來開。", "休悲往古事何在，且樂去年時復來。", "好是夕陽須管醉，花叢中放玉山頹。"]'),
('0bbaccbb-23a7-46a2-9aaf-1be3cd9d1f61','題南華洞','黄裳','宋','宋诗','song-poetry','','[]','數卷真經學兩忘，何須疑蝶更疑莊。',64,'全唐诗/poet.song.54000.json','["數卷真經學兩忘，何須疑蝶更疑莊。", "水雲生計不知老，詩酒光陰無限長。", "何處猿聲殘客夢，有時風信漏天香。", "鍾山不愧移文士，信步尋幽到草堂。"]'),
('95f3b419-00ab-4424-b613-c9f00fde9b0f','江下山居','黄裳','宋','宋诗','song-poetry','','["\u897f\u6e56"]','不卜西湖卜此山，江天方作洞天寒。',64,'全唐诗/poet.song.54000.json','["不卜西湖卜此山，江天方作洞天寒。", "海門有信蓬萊近，丹室無塵宇宙寬。", "一箭昔人曾却浪，五雲何日便驂鸞。", "小橋流水通幽徑，休向朋賓說內觀。"]'),
('fb15b0dc-42d2-40be-a04f-d4203049a29b','信步','黄裳','宋','宋诗','song-poetry','','[]','閒適無他事，優遊有此身。',60,'全唐诗/poet.song.54000.json','["閒適無他事，優遊有此身。", "禽魚窺物性，草木露天真。", "靜味祇獨覺，幽香還自陳。", "行雲難問信，流水莫知因。", "漁父偶相值，笑談猶及秦。"]'),
('ad8f53b0-3503-4f60-b686-5d077d1f61dc','寄梅承事','黄裳','宋','宋诗','song-poetry','','[]','滄浪風縐鴨頭波，中有高人養太和。',64,'全唐诗/poet.song.54000.json','["滄浪風縐鴨頭波，中有高人養太和。", "怪石換金清興遠，華堂收佛善緣多。", "花街山院青春醉，玉管雲牋白雪歌。", "未信閒名羈絆得，試教衫色綠如何。"]'),
('3937cb71-ba9d-4631-8b23-3dd98027dc0c','東山三題 觀蓮亭','黄裳','宋','宋诗','song-poetry','','[]','青泥藏化育，紅粉看芬芳。',48,'全唐诗/poet.song.54000.json','["青泥藏化育，紅粉看芬芳。", "照水有餘態，乘風無限香。", "晚來花獨盛，暑後雨聲凉。", "不著故不染，走盤珠自忙。"]'),
('c6d55b1b-0cab-49a6-bf48-5a751e587e51','東山三題 現月亭','黄裳','宋','宋诗','song-poetry','','[]','一月滅私照，萬水生餘光。',48,'全唐诗/poet.song.54000.json','["一月滅私照，萬水生餘光。", "成道果有性，應物元無方。", "對景妄想斷，凭高清夜長。", "超然養源士，豈徒愛瀟湘。"]'),
('271b7e1e-d5e0-4aee-967b-22bd356e447a','東山三題 悟桃軒','黄裳','宋','宋诗','song-poetry','','[]','中無城市埃，下有桃溪源。',48,'全唐诗/poet.song.54000.json','["中無城市埃，下有桃溪源。", "灼灼發獨見，冥冥從混元。", "俄忽遂出世，喜躍聊開樽。", "且共衆人看，迷悟休復論。"]'),
('c2bc972a-6b1f-43eb-a86f-ed9bd85da668','簡叔文','黄裳','宋','宋诗','song-poetry','','[]','屈指當時宴笑同，已更三十五春風。',64,'全唐诗/poet.song.54000.json','["屈指當時宴笑同，已更三十五春風。", "十年忽忽成今古，萬事悠悠作色空。", "別後每懷青眼客，坐間俄揖白鬚翁。", "蘭亭咫尺歸歟好，當悟浮生似轉蓬。"]'),
('05ef7398-79dc-487b-859e-e91b19c71092','寄題范氏六桂堂','黄裳','宋','宋诗','song-poetry','','[]','榮到蟾宮父子同，滿堂天秀望仙峰。',64,'全唐诗/poet.song.54000.json','["榮到蟾宮父子同，滿堂天秀望仙峰。", "六枝已勝燕山桂，八子須攀潁水龍。", "風信動人香遠遠，月華垂地影重重。", "餘芳更有成林日，行見君家萬里封。"]'),
('d5e267c0-fd9d-417b-b723-7e0a8e52bb4e','聞雁','黄裳','宋','宋诗','song-poetry','','[]','露下多時雁未鳴，數聲雲外此宵征。',64,'全唐诗/poet.song.54000.json','["露下多時雁未鳴，數聲雲外此宵征。", "北人書到三秋盡，南國弓閒一字橫。", "孤館有誰驚好夢，平蘆何處起寒更。", "想應俎上終須免，宜向方塘寄此生。"]'),
('c33ea507-e220-40a5-b2dc-40c72ac913d7','大暑','黄裳','宋','宋诗','song-poetry','','[]','輕輕絲葛汗如蒸，空有雲雷未見靈。',64,'全唐诗/poet.song.54000.json','["輕輕絲葛汗如蒸，空有雲雷未見靈。", "安得此生長不老，豈能今日便忘形。", "謾摇紈扇終嫌倦，欲倒金罍却恐醒。", "赤脚踏冰疑未穩，且尋林下泛清泠。"]'),
('3650bc1c-f175-48cd-8b1c-0794318b1c06','山堂有作','黄裳','宋','宋诗','song-poetry','','[]','烟籠雲鎖幾千年，流俗尋山豈得先。',64,'全唐诗/poet.song.54000.json','["烟籠雲鎖幾千年，流俗尋山豈得先。", "一水中分吳越界，四峰前臥漢唐仙。", "閒遊東徑窺青海，偶往西源翫白蓮。", "却省內遊還有感，杖藜獨立夕陽天。"]'),
('a8657dc3-75e5-408b-8abd-f749bc194c3f','題愛竹軒','黄裳','宋','宋诗','song-poetry','','[]','北堂人去竹成陰，手澤須看碧玉林。',64,'全唐诗/poet.song.54000.json','["北堂人去竹成陰，手澤須看碧玉林。", "清賞昔嫌無一日，孝思今喜有千尋。", "滿窗金鎖日華永，遍地龍孫春意深。", "寄語嬋娟多結實，幾時當聽鳳凰吟。"]'),
('37046f55-5633-412e-ac1b-62cfb351015f','除夜','黄裳','宋','宋诗','song-poetry','','[]','守歲飲須頻，光陰又再春。',48,'全唐诗/poet.song.54000.json','["守歲飲須頻，光陰又再春。", "漏移中夜刻，身是去年人。", "天色收殘臘，人心息舊塵。", "東風新我意，相得向雞晨。"]'),
('6d5b945d-0a5e-4095-941c-853d131c2cfb','楊立之南歸','黄裳','宋','宋诗','song-poetry','','[]','五月雙艫偶共行，開懷尤喜暑風清。',64,'全唐诗/poet.song.54000.json','["五月雙艫偶共行，開懷尤喜暑風清。", "亨途事業心猶壯，細字詩書眼更明。", "家有青山應可樂，首無黄髮未須驚。", "相期一醉無他景，九十西風菊萬莖。"]'),
('1098203c-4c9e-4cb7-9061-2276ddd952b4','南樓有作呈仲矩舍人','黄裳','宋','宋诗','song-poetry','','[]','莫言風物是窮邊，塞北江南此果然。',64,'全唐诗/poet.song.54000.json','["莫言風物是窮邊，塞北江南此果然。", "蒼璧下粘芳草地，垂楊中臥碧塘天。", "人吟夜月波中笛，客醉秋荷雨後筵。", "來候朔音棲處好，夢常捫斗過幽燕。"]'),
('5ca5ff82-9da9-4a8a-80f7-65c400a9a7b3','秋夜','黄裳','宋','宋诗','song-poetry','','[]','百蟲將入蟄，一氣已歸根。',48,'全唐诗/poet.song.54000.json','["百蟲將入蟄，一氣已歸根。", "今古在還去，光陰朝又昏。", "莫隨塵衮衮，須悟性存存。", "誰得逍遙趣，南鵬是北鯤。"]'),
('ddef2085-becb-4f9c-84eb-c0872a42c0c8','送李季益龍圖','黄裳','宋','宋诗','song-poetry','','[]','浮遊塵世未還元，偶會琳宮兩地仙。',64,'全唐诗/poet.song.54000.json','["浮遊塵世未還元，偶會琳宮兩地仙。", "行止義明嘗得己，修持仁靜可忘年。", "笑談客去吳無侶，惠愛人來楚有緣。", "公外詩筒當見寄，爲乘佳興益新編。"]'),
('c20636ce-4122-4728-958c-0496d1844f40','清勝亭','黄裳','宋','宋诗','song-poetry','','[]','靈源來處亂雲深，回抱華亭愜我吟。',64,'全唐诗/poet.song.54000.json','["靈源來處亂雲深，回抱華亭愜我吟。", "窺影冷光天上面，入懷清氣水中心。", "橋頭月到人携榼，蘋末風來客解襟。", "秣馬臺前聊遣興，寸陰何惜與登臨。"]'),
('32689025-5ea9-4a62-a1ee-ef9b603e911f','歲暮偶成','黄裳','宋','宋诗','song-poetry','','[]','新舊光陰各自催，分年須折送年梅。',64,'全唐诗/poet.song.54000.json','["新舊光陰各自催，分年須折送年梅。", "歡聲動地驅儺鼓，厚意迎春獻壽杯。", "誰似江山難得老，人憐桃李又重開。", "朱顔未遂花前計，却恨東風抵死來。"]'),
('faf0abae-c3ed-49d1-9ecf-79fa00ed6b15','贈致政葛侍郎','黄裳','宋','宋诗','song-poetry','','[]','金带慵腰便退居，高閒吟思滿江湖。',64,'全唐诗/poet.song.54000.json','["金带慵腰便退居，高閒吟思滿江湖。", "一頭黄髮真元老，兩郡朱幡更大夫。", "世事榮枯閒似夢，道經舒卷靜如愚。", "延平遺愛今猶在，一片棠陰入畫圖。"]'),
('674b6cac-3add-4b38-abc1-0df53c0357c1','九日遊堯山','黄裳','宋','宋诗','song-poetry','','[]','誰見東巡駐六龍，秋山留與醉吟翁。',64,'全唐诗/poet.song.54000.json','["誰見東巡駐六龍，秋山留與醉吟翁。", "人非物是紛華外，古往今來想望中。", "雲日萬年興素節，士民千里鬧晴空。", "黄花盈首猶教摻，一笑從他落帽風。"]'),
('78e9d80d-c66b-47fb-ae48-6f3d21610198','贈張太保','黄裳','宋','宋诗','song-poetry','','[]','赫赫家聲將帥官，仕途寧肯放君閒。',64,'全唐诗/poet.song.54000.json','["赫赫家聲將帥官，仕途寧肯放君閒。", "不妨林下權尋藥，未可雲中便買山。", "五兩輕綸猶系命，滿樽清醑且開顔。", "天涯之子誰爲樂，何幸相逢一笑間。"]'),
('da3d0a38-73e8-4f2a-a4a9-bb960901e169','除夜代送倪簽判','黄裳','宋','宋诗','song-poetry','','[]','北風吹雪抹潮頭，待過東南第一州。',64,'全唐诗/poet.song.54000.json','["北風吹雪抹潮頭，待過東南第一州。", "去客情生來客夢，隔年燈照隔江愁。", "玉皇謫吏行當復，金闕除書即便收。", "言簡氣清終有用，臥龍山下自難留。"]'),
('3a0bf784-e389-4e49-a142-67fd779673d5','觀遊山記感舊寄霍子侔','黄裳','宋','宋诗','song-poetry','','[]','故園別後有餘念，舊記重看無限情。',64,'全唐诗/poet.song.54000.json','["故園別後有餘念，舊記重看無限情。", "山倚日中支暑氣，水從雲外落秋聲。", "向前世務心猶壯，憶昔溪居眼自明。", "携手逸民今在否，盃茶誰與話平生。"]'),
('43d70243-6c04-43a2-ab6d-e2be9cf8a825','再寄及之  其一','黄裳','宋','宋诗','song-poetry','','[]','眼淩霄漢氣橫秋，未壯吾年似白頭。',64,'全唐诗/poet.song.54000.json','["眼淩霄漢氣橫秋，未壯吾年似白頭。", "病態問人皆笑老，壯圖何處始知休。", "還因往事悲今事，難得新遊比舊遊。", "霅水越溪風信好，尺書多幸屢相投。"]'),
('13d2a1f1-e4da-479c-ab00-b406268dad95','再寄及之  其二','黄裳','宋','宋诗','song-poetry','','[]','別後新寒有勁風，不親談笑轉乖慵。',64,'全唐诗/poet.song.54000.json','["別後新寒有勁風，不親談笑轉乖慵。", "一行塞雁來多日，萬里鄉書得幾封。", "閒憶蘭陵還自笑，願遊苕水更相從。", "與君疏闊誰堪愛，閱古堂前樹樹松。"]'),
('8ccdf15e-26a7-42f2-bbf1-7c30cbf3a426','會友人飲','黄裳','宋','宋诗','song-poetry','','[]','曾共螢窗得夜光，別來聲問在周行。',64,'全唐诗/poet.song.54000.json','["曾共螢窗得夜光，別來聲問在周行。", "未摇丹管酬詩史，且遣青娥丐樂章。", "巧笑莫嫌留客數，幽懷須信到官忙。", "樽前邂逅知多少，更對春風舞一場。"]'),
('20b14740-7e5f-4e48-8f02-5c165f82bd04','送方子元赴固始','黄裳','宋','宋诗','song-poetry','','[]','九卿遺俗各尋宗，君自南來喜更濃。',64,'全唐诗/poet.song.54000.json','["九卿遺俗各尋宗，君自南來喜更濃。", "無類已聞詩禮教，有行還守子男封。", "胸中道在何嫌酒，弦上聲清只愛松。", "行聽老農無一累，曉炊如玉稻新舂。"]'),
('1daf21b1-8ccf-48ef-b4b8-77ae3da2cda3','送林君錫宣德','黄裳','宋','宋诗','song-poetry','','[]','最喜君來寫我憂，羣情忙處獨抽頭。',64,'全唐诗/poet.song.54000.json','["最喜君來寫我憂，羣情忙處獨抽頭。", "功名機會須時可，詩酒光陰屬自由。", "醉度九秋江上舫，食遊雙筯海邊州。", "兩年官滿休瞻望，且與磨鉛了校讎。"]'),
('017ff289-c8e9-4076-b439-db65c1c2d97e','送仲時南歸','黄裳','宋','宋诗','song-poetry','','[]','壯志九年人事足，奇書千卷客囊空。',64,'全唐诗/poet.song.54000.json','["壯志九年人事足，奇書千卷客囊空。", "窮通自在身謀外，取舍誰堪士論中。", "休歎鹽車千里驥，且誇天漢一帆風。", "忙拖雙履雲邊興，更與何人作醉翁。"]'),
('50194ae9-8f47-4941-bed3-a27e3bc2f2ba','與子侔始會于常學後爲禮部同官感舊','黄裳','宋','宋诗','song-poetry','','[]','始觀文彩慕聲名，三十餘年夢可驚。',64,'全唐诗/poet.song.54000.json','["始觀文彩慕聲名，三十餘年夢可驚。", "真幻自從窺至理，是非誰復較浮榮。", "別來方策迷情斷，老去園林逸思生。", "敘舊幽軒時一笑，更宜茶鼎作蠅聲。"]'),
('86a092e6-2ca9-41dc-a9e2-f83f7b0e1cc3','靈壁遊張學士園','黄裳','宋','宋诗','song-poetry','','[]','休說行行且與吟，道山官職舊園林。',64,'全唐诗/poet.song.54000.json','["休說行行且與吟，道山官職舊園林。", "石疑六醜默難問，竹類七賢閒可尋。", "翠引賓朋三徑遠，寒生涯澗一池深。", "隋河堤上人空老，誰爲蘭皋惜寸陰。"]'),
('40733380-85a5-419f-85df-82c78132ddd5','謝人示詩集','黄裳','宋','宋诗','song-poetry','','[]','騷雅先生得古風，恨無吟侶忽相逢。',64,'全唐诗/poet.song.54000.json','["騷雅先生得古風，恨無吟侶忽相逢。", "欲陪大巧搜春景，已賈長毫插筆鋒。", "花下比聲歌帝力，醉中聯句頌花容。", "斐然小子多詩癖，時遣青衣寄一封。"]'),
('ab77a9f6-a24c-4fa7-a442-97f784914f24','寄陳充道','黄裳','宋','宋诗','song-poetry','','[]','性纔圓了便相逢，對面還如一鏡中。',64,'全唐诗/poet.song.54000.json','["性纔圓了便相逢，對面還如一鏡中。", "共取醉時聊遣興，兩忘言處却歸空。", "紛紛綠髮何妨白，擾擾黄塵謾自紅。", "松竹滿林先我去，笑談誰起坐間風。"]'),
('a06c6ef7-8987-4066-ba47-5cccf4e6c65e','頤堂','黄裳','宋','宋诗','song-poetry','','[]','晚年塵事少，閒境道情多。',48,'全唐诗/poet.song.54000.json','["晚年塵事少，閒境道情多。", "汗簡知千古，靈龜見一毫。", "更尋何處樂，休訟此生勞。", "名利雖然好，誰瞻數仞高。"]'),
('e6b8fde0-23bb-44db-94f1-6014db2cc65e','送鄭少府延平教授','黄裳','宋','宋诗','song-poetry','','[]','上舍聲華太學生，青衫從我薛齊城。',64,'全唐诗/poet.song.54000.json','["上舍聲華太學生，青衫從我薛齊城。", "神仙官職去期遠，詩禮門庭歸思清。", "山展旌旗秋可樂，劍驅風雨夜休驚。", "故鄉夢想今猶在，此景何年慰此情。"]'),
('7e830bf0-3c65-458a-b36f-2eabb560968e','長樂閒賦  其一','黄裳','宋','宋诗','song-poetry','','[]','行盡溪山到海邊，合沙門外見平田。',64,'全唐诗/poet.song.54000.json','["行盡溪山到海邊，合沙門外見平田。", "潭潭清世元侯宅，杳杳真人小洞天。", "萬戶管弦春賣酒，三山鐘鼓曉參禪。", "旌旄纔上南臺路，方記詩篇落在先。"]'),
('f5299bab-038f-4d77-b8ff-c29c0582e05d','長樂閒賦  其二','黄裳','宋','宋诗','song-poetry','','[]','二百餘人領此州，去思誰更有碑樓。',64,'全唐诗/poet.song.54000.json','["二百餘人領此州，去思誰更有碑樓。", "浮名浮利果何在，潮去潮來空自流。", "照萬事時惟是道，賞三山處最宜秋。", "使君籍上尋同姓，只許旌旄獨自遊。"]'),
('5183ea03-0ef4-42f1-949e-862b244ce194','長樂閒賦  其三','黄裳','宋','宋诗','song-poetry','','[]','越王峰下小棠深，秋入三山未暇尋。',32,'全唐诗/poet.song.54000.json','["越王峰下小棠深，秋入三山未暇尋。", "兩造盈庭真與僞，紫玄堂上本無心。"]'),
('3862fd0a-af30-406c-a171-010f56fe03d9','長樂閒賦  其四','黄裳','宋','宋诗','song-poetry','','[]','七樓遙直釣龍臺，榕曳橫枝庇兩階。',32,'全唐诗/poet.song.54000.json','["七樓遙直釣龍臺，榕曳橫枝庇兩階。", "好是四州南下水，却隨潮信入城來。"]'),
('39cdd97f-eb19-49f9-9d7b-bcabe9a79484','長樂閒賦  其五','黄裳','宋','宋诗','song-poetry','','[]','五十年前夢此遊，已云持節豈能休。',64,'全唐诗/poet.song.54000.json','["五十年前夢此遊，已云持節豈能休。", "悠悠封域連東海，浩浩朝宗接上州。", "五季侯王時事古，九還仙子洞天秋。", "閒行嫌被朱衣覺，密往西堂獨倚樓。"]'),
('4f53fbf9-f640-4727-a8fe-5a182579bd86','長樂閒賦  其六','黄裳','宋','宋诗','song-poetry','','[]','地傃東南一角垂，百川夢處勢隨堤。',32,'全唐诗/poet.song.54000.json','["地傃東南一角垂，百川夢處勢隨堤。", "滿帆風力人航海，七日遊吳尚說遲。"]'),
('bd7950d8-5008-4884-9ed5-edfcbab9ac7f','長樂閒賦  其七','黄裳','宋','宋诗','song-poetry','','[]','旁統七州連帥府，中分三壤屬僧家。',32,'全唐诗/poet.song.54000.json','["旁統七州連帥府，中分三壤屬僧家。", "荔枝獨作閩山秀，宜與龍團一處誇。"]'),
('1137af61-bf19-45a6-a7b6-de927bf842cb','長樂閒賦  其八','黄裳','宋','宋诗','song-poetry','','[]','歲華猶暖山藏翠，客起還留海獻鮮。',32,'全唐诗/poet.song.54000.json','["歲華猶暖山藏翠，客起還留海獻鮮。", "風雅可憐元太守，一生魂夢已茫然。"]'),
('70246e23-a15a-45ff-bbc6-106dae76ab00','長樂閒賦  其九','黄裳','宋','宋诗','song-poetry','','[]','方壺圓嶠飛來處，北越南番望斷時。',32,'全唐诗/poet.song.54000.json','["方壺圓嶠飛來處，北越南番望斷時。", "莫道長安天樣遠，一輪初上已先知。"]'),
('2a2c30bc-efb2-473f-8adc-ff23607d059a','長樂閒賦  其一○','黄裳','宋','宋诗','song-poetry','','[]','周回禪剎望嚴城，雲弄遙岑一寸青。',32,'全唐诗/poet.song.54000.json','["周回禪剎望嚴城，雲弄遙岑一寸青。", "眼在簿書心在道，何妨尋我到山亭。"]'),
('4e0bd2da-9b95-420e-99c2-ba1b50ee193d','秋日有感','黄裳','宋','宋诗','song-poetry','','[]','清生明爽靜生悲，羣動相將却入機。',64,'全唐诗/poet.song.54000.json','["清生明爽靜生悲，羣動相將却入機。", "物向本根成既老，雁知時節去還歸。", "山人邀飲酒初熟，漁叟獻鮮鱸正肥。", "莫管世情都掃盡，閒來林下看秋輝。"]'),
('1f4fcb9c-b6e2-4b6e-a7fa-c9e368b9e677','和寄麻城饒令','黄裳','宋','宋诗','song-poetry','','[]','應向公餘飽看山，弦歌安用智閒閒。',64,'全唐诗/poet.song.54000.json','["應向公餘飽看山，弦歌安用智閒閒。", "有爲百里人同樂，無累三神我獨閒。", "雖隔春風長在想，尚期嘉什屢蒙頒。", "近來與物低昂少，多是聰明落靜關。"]'),
('50abc374-8bbc-4281-a12e-fac73e7dd09a','白蓮閣','黄裳','宋','宋诗','song-poetry','','[]','白蓮池上閣崢嶸，萬朵西風滿社清。',64,'全唐诗/poet.song.54000.json','["白蓮池上閣崢嶸，萬朵西風滿社清。", "已寓漣漪呈皓質，何妨污潦得浮生。", "羅抨翠蓋秋陽盛，玉琢香腮曉鑑明。", "空色從來無辨處，此詩非獨爲花成。"]'),
('3ce26319-3dce-4305-a7a4-a4c2f28e40f5','寄題明舍','黄裳','宋','宋诗','song-poetry','','[]','明舍義方立，深宮文藝成。',48,'全唐诗/poet.song.54000.json','["明舍義方立，深宮文藝成。", "詩書盈篋重，金玉滿堂輕。", "天漢一枝峻，秋風雙桂榮。", "羨君能自樂，在處有蓬瀛。"]'),
('05b18667-0aa8-47a7-b2bc-5baddeb905aa','藤杖','黄裳','宋','宋诗','song-poetry','','[]','一枝能獨立，三徑漫相隨。',48,'全唐诗/poet.song.54000.json','["一枝能獨立，三徑漫相隨。", "閒逐人行止，先知路險夷。", "倚憑吟望久，將飲醉歸遲。", "携到遙林下，尤宜倒接䍦。"]'),
('9f70b009-42ce-4e59-9b44-991f7a81b4ec','寄蕭思遠','黄裳','宋','宋诗','song-poetry','','[]','自能騰踏到天衢，少壯爲龍卷未舒。',64,'全唐诗/poet.song.54000.json','["自能騰踏到天衢，少壯爲龍卷未舒。", "案上不留生熟事，篋中偏有古今書。", "高吟應愜新移命，幽夢還尋舊隠居。", "須道守官誰似我，長來湖上得清虛。"]'),
('5d0dbeaa-1835-4b67-af69-8f5d5ad3811d','寄湖江二十四叔','黄裳','宋','宋诗','song-poetry','','[]','小宗纔廢各西東，懷想湖江夢寐中。',64,'全唐诗/poet.song.54000.json','["小宗纔廢各西東，懷想湖江夢寐中。", "受祖生涯君獨異，起家身計我誰同。", "客遊何事千山遠，族燕還悲一位空。", "期約明年來侍側，青衫滿滿桂花風。"]'),
('245ee066-c249-4254-9c3c-892accbe180e','表海亭','黄裳','宋','宋诗','song-poetry','','[]','大老悠悠不嗣音，高風難向望中尋。',64,'全唐诗/poet.song.54000.json','["大老悠悠不嗣音，高風難向望中尋。", "三千賓客空離合，十二山河自古今。", "北戶人歸雲洞遠，東方春入牡丹深。", "兩辭遣興無他好，只有閒來醉與吟。"]'),
('b63d6dc2-5e4a-4cc1-8806-917e24d788a4','社日遊雲門山','黄裳','宋','宋诗','song-poetry','','[]','不須扶我自登山，脚力能勝十八盤。',64,'全唐诗/poet.song.54000.json','["不須扶我自登山，脚力能勝十八盤。", "一字雁低頭上過，兩城人細掌中看。", "雖知北戶緣尤在，却笑南柯夢未闌。", "忽見歸雲應是信，滿襟先得洞天寒。"]'),
('842b0cc5-fa37-4486-a287-c50f29f113b2','次泠風閣之韵  其一','黄裳','宋','宋诗','song-poetry','','[]','九龍峰下閣橫秋，世上纖塵不可留。',64,'全唐诗/poet.song.54000.json','["九龍峰下閣橫秋，世上纖塵不可留。", "清伴夜蟾留醉客，細吹時雨走歸舟。", "天南從此載鵬往，山北與誰乘鶴遊。", "已是逍遙何所待，上人高臥見蓬丘。"]'),
('c54dd6a6-d772-4015-88b1-5d61affbd4de','次泠風閣之韵  其二','黄裳','宋','宋诗','song-poetry','','[]','能御泠風入九秋，豈愁光景去難留。',64,'全唐诗/poet.song.54000.json','["能御泠風入九秋，豈愁光景去難留。", "翠摇竹影落猿嶠，清遞笛聲來鷺洲。", "兩腋獨乘盧椀興，滿襟誰作楚臺遊。", "須知大塊生微意，豈俟雲邊虎嘯丘。"]'),
('723f1bfb-82cb-4feb-aa2c-a600a95cd848','寄題澄虛閣','黄裳','宋','宋诗','song-poetry','','[]','欄檻天都近，池塘水鑑平。',48,'全唐诗/poet.song.54000.json','["欄檻天都近，池塘水鑑平。", "微風晴後寂，孤月夜來清。", "大象莫能破，纖塵何處生。", "湘靈誰爲感，一曲謾分明。"]'),
('9581d386-e356-4263-8d9e-3dab7cc76f3d','贈致政王朝奉','黄裳','宋','宋诗','song-poetry','','[]','得老歸來已幾年，水雲深處洞中天。',64,'全唐诗/poet.song.54000.json','["得老歸來已幾年，水雲深處洞中天。", "有身且睡三竿日，無物應看一指禪。", "松竹亭臺閒信步，鄉閭樽俎謾隨緣。", "此生離合誰能定，只見龍潭尚宛然。"]'),
('d7f6d8af-94f4-436e-b4cc-1149daba9e6a','次張秘校昔日同遊僧舍','黄裳','宋','宋诗','song-poetry','','[]','過去光陰有勝遊，翠微深處更乘秋。',64,'全唐诗/poet.song.54000.json','["過去光陰有勝遊，翠微深處更乘秋。", "偶尋得石坐云坐，莫問作官休未休。", "世揉道情塵擾擾，雲藏詩壁歲悠悠。", "山僧看了須重看，且碧雙眸便轉頭。"]'),
('5cbfb4e8-843b-4752-8f9b-574861d70216','和李學士試院感秋二首  其一','黄裳','宋','宋诗','song-poetry','','[]','遽往偶相聚，下簾人事稀。',48,'全唐诗/poet.song.54000.json','["遽往偶相聚，下簾人事稀。", "感秋那聽雨，聞杵屢催衣。", "得喪多士夢，行藏羣雁飛。", "黄花期野老，須插滿頭歸。"]'),
('2474b750-60e2-48de-bb79-27f8b979316a','和李學士試院感秋二首  其二','黄裳','宋','宋诗','song-poetry','','[]','荒庭初得雨，幽點失凋梧。',48,'全唐诗/poet.song.54000.json','["荒庭初得雨，幽點失凋梧。", "滯思舒千卷，高吟想五湖。", "蛩聲生翠幄，酒力借微軀。", "襲蹈貽文病，猶難望漢儒。"]'),
('40771df5-cf15-4d25-9a5e-7d5b0dbd0f8f','送劉教授','黄裳','宋','宋诗','song-poetry','','[]','升沈相識十三秋，新故如麻一轉頭。',64,'全唐诗/poet.song.54000.json','["升沈相識十三秋，新故如麻一轉頭。", "久款遊從來北闕，遽聞風教入東州。", "自驅矛盾趨中說，誰擁鸞旂翫半流。", "十日菊花猶可醉，多情應且擊扁舟。"]'),
('20b565b3-949b-4430-9bc9-8d63cd2cb68a','平嵐亭','黄裳','宋','宋诗','song-poetry','','[]','平嵐亭寄半天身，閒向欄干獨倚頻。',64,'全唐诗/poet.song.54000.json','["平嵐亭寄半天身，閒向欄干獨倚頻。", "往事有懷誰共笑，歸雲無意自相親。", "神仙窟宅幽明境，花木園林上下春。", "斗絕一臺疑是此，不須低首看紅塵。"]'),
('f822a04c-aad4-4a3c-92dc-5322f0fa116d','湖上','黄裳','宋','宋诗','song-poetry','','[]','一家風景洞天清，不愧東南第一名。',64,'全唐诗/poet.song.54000.json','["一家風景洞天清，不愧東南第一名。", "春入桃源花未落，秋歸湘浦月初生。", "便捐世事劬劬到，且置籃輿緩緩行。", "隨分堪觀無可辨，水光山色競相迎。"]'),
('2bbcc895-7d9b-4c7e-91b9-1ce0af7718bb','會江晦叔遊湖山','黄裳','宋','宋诗','song-poetry','','[]','相隨山水裏徘徊，興未闌時慎勿催。',80,'全唐诗/poet.song.54000.json','["相隨山水裏徘徊，興未闌時慎勿催。", "草草行厨隨步去，匆匆漁艇趁船來。", "每逢佳景還含思，偶造幽軒更把盃。", "况是同歸無世味，何須旁立有蓮腮。", "荻灣桃塢猶留客，不覺銀瓶又耻罍。"]'),
('0a529c2e-c454-4ad3-adb6-6ea3f651c475','送昇師行','黄裳','宋','宋诗','song-poetry','','[]','得道無餘事，遊方有幾年。',60,'全唐诗/poet.song.54000.json','["得道無餘事，遊方有幾年。", "如何超幻境，誰與付真筌。", "初祖昔曾訣，趙州今已仙。", "進修方且學，拂蕩未須傳。", "歸去南山好，休休更說禪。"]'),
('d928d2c5-6332-4ce9-9a81-7441ab330f1b','留題西禪寺','黄裳','宋','宋诗','song-poetry','','[]','誰是怡山不滅仙，定光來應此方緣。',64,'全唐诗/poet.song.54000.json','["誰是怡山不滅仙，定光來應此方緣。", "龍驤鳳翥三宗字，獅吼雷鳴六祖禪。", "魚佩獨垂聊徇世，藕絲相感爲開天。", "自從日月歸真後，衣法何人已得傳。"]'),
('10b7b051-9a77-40e6-80bc-cfa177367382','題鄉老堂','黄裳','宋','宋诗','song-poetry','','[]','未到中年便掛冠，一鄉三老北溪寒。',64,'全唐诗/poet.song.54000.json','["未到中年便掛冠，一鄉三老北溪寒。", "廢興有命知尤早，去住無心遇更難。", "輕物想能閒似夢，愛山應是好如官。", "莫言林下何曾見，待向圖中畫與看。"]'),
('47cc738e-0428-463b-98ca-11601c16bf85','次趙彥思東湖見寄','黄裳','宋','宋诗','song-poetry','','[]','爲愛江湖夢也尋，有泉來處亂雲深。',64,'全唐诗/poet.song.54000.json','["爲愛江湖夢也尋，有泉來處亂雲深。", "鑿開澄澈是天界，激起潺湲非世音。", "鴻雁渚幽山兩足，芙蓉堂冷水中心。", "花時月夜扁舟興，相約公餘一醉吟。"]'),
('368b5e96-2b31-47a0-b980-e07e25ddad9b','和范宏甫','黄裳','宋','宋诗','song-poetry','','[]','不於場屋便橫行，安用詩書寄此生。',64,'全唐诗/poet.song.54000.json','["不於場屋便橫行，安用詩書寄此生。", "萬里一飛雖有志，十年三戰未成名。", "風霜已是知秋栢，雷雨何妨借海鯨。", "自愧壯圖猶未效，幾時樽酒與君評。"]'),
('e60f6875-d431-463b-8880-93a6bca0e751','喜張公實至','黄裳','宋','宋诗','song-poetry','','[]','纔踰閩嶺轉悠悠，所屬相逢夢未休。',64,'全唐诗/poet.song.54000.json','["纔踰閩嶺轉悠悠，所屬相逢夢未休。", "逸興起君桑梓國，多情尋我帝王州。", "且看文物新朝事，更話溪山舊酒樓。", "會合此生能幾度，一樽長瀉菊花秋。"]'),
('7dbabe0e-b7a8-471b-ae04-2d5569efc38f','方祖仁都門阻雨','黄裳','宋','宋诗','song-poetry','','[]','未蒙官放此身休，空恨茶園失舊遊。',64,'全唐诗/poet.song.54000.json','["未蒙官放此身休，空恨茶園失舊遊。", "將謂天邊鴻共發，豈知門外雨相留。", "一襟凉過人歸室，萬朵香殘菊送秋。", "兄弟急難君有義，白衣東下更何尤。"]'),
('a0f8a4b4-1aff-40c9-9a66-2b113a8a5b98','桐廬會景亭二首  其一','黄裳','宋','宋诗','song-poetry','','[]','物華才思兩無窮，來倚欄干萬累空。',64,'全唐诗/poet.song.54000.json','["物華才思兩無窮，來倚欄干萬累空。", "今古坐間山遠近，悲歡潮後客西東。", "樵樓上下夕陽外，漁網高低烟雨中。", "想見飛昇人只在，留題當識紫玄翁。"]'),
('2aae88ce-e3b9-465e-9bd5-7d1cf44c1f61','桐廬會景亭二首  其二','黄裳','宋','宋诗','song-poetry','','[]','舟楫會通處，陰陽明晦時。',48,'全唐诗/poet.song.54000.json','["舟楫會通處，陰陽明晦時。", "四并歸善政，萬象入新詩。", "地勝得仙久，水遙歸鷺遲。", "爲看滕閣記，將賦此尤宜。"]'),
('5062574e-56d6-44f1-8dd2-d077d848487b','送王道觀錄事','黄裳','宋','宋诗','song-poetry','','[]','一府觀風郡督郵，試看鷹隼在高秋。',64,'全唐诗/poet.song.54000.json','["一府觀風郡督郵，試看鷹隼在高秋。", "黄花對酌新離別，白雪難思舊唱酬。", "塵緒案頭來擾擾，銀河天上去悠悠。", "碧羅琢硯初離水，勤寫瑰奇度阻脩。"]'),
('f5ac36ce-c333-404f-ae0e-980d14762adf','貽劉先生','黄裳','宋','宋诗','song-poetry','','[]','勢利交遊聚與分，會真堂上合離羣。',64,'全唐诗/poet.song.54000.json','["勢利交遊聚與分，會真堂上合離羣。", "形骸外索難爲侶，風義中尋偶得君。", "水鑑秋來宜泛月，桃源花後且穿雲。", "此生已是龍山客，高論相過我欲聞。"]'),
('341da378-e203-4f03-ac8a-4ffd7843c931','題望遠樓','黄裳','宋','宋诗','song-poetry','','[]','雕欄身有限，芳草意無窮。',48,'全唐诗/poet.song.54000.json','["雕欄身有限，芳草意無窮。", "望盡天垂地，吟餘色入空。", "鋒鋩千里岫，羽翼半天風。", "萬象回頭了，駢明亦夢中。"]'),
('00e72cab-1b2f-4075-ba69-750d538e1c17','寄陳邵老  其一','黄裳','宋','宋诗','song-poetry','','[]','南來安不裂新題，萬里悠悠十載睽。',64,'全唐诗/poet.song.54000.json','["南來安不裂新題，萬里悠悠十載睽。", "一別每懷君海角，兩除應笑我朝齏。", "是非莫訝時方轉，榮辱須驚物未齊。", "故舊九仙山下客，想曾携手泛三溪。"]'),
('d1a2276e-1dd6-4f9d-9896-9fff74ff491a','寄陳邵老  其二','黄裳','宋','宋诗','song-poetry','','[]','幾度爲書却便休，疏慵于我更如讎。',64,'全唐诗/poet.song.54000.json','["幾度爲書却便休，疏慵于我更如讎。", "兩忘有道何須問，相責無情我合羞。", "屢感客塵新事變，難尋陵谷舊時遊。", "爲親歸去親猶健，只此浮生已解憂。"]'),
('6fdf1a1e-6038-4111-9c57-1211cfc1b37f','次邦彥節推見寄  其一','黄裳','宋','宋诗','song-poetry','','[]','十年譏笑爲誰妨，洒落思君酒甕旁。',64,'全唐诗/poet.song.54000.json','["十年譏笑爲誰妨，洒落思君酒甕旁。", "曉殿雖爭多士捷，夜窗還對短檠光。", "靜憐春草開三徑，冷怪朝齏引五漿。", "且喜相逢頭尚黑，江湖休更起懷鄉。"]'),
('a45eb8f1-35a7-4069-89ad-96a1fa04dcfe','次邦彥節推見寄  其二','黄裳','宋','宋诗','song-poetry','','[]','淮上相逢得勝遊，水邊鄉落水邊洲。',64,'全唐诗/poet.song.54000.json','["淮上相逢得勝遊，水邊鄉落水邊洲。", "每憐酒旆能留客，長恐秋風便解舟。", "十載窮通重把手，兩朝今古一迴頭。", "金明且看春波綠，共我忘機子與鷗。"]'),
('f4332999-78eb-4376-a93b-b9efcb7a5fdb','寄簡能','黄裳','宋','宋诗','song-poetry','','[]','形迹分飛有道同，五年聲問不須通。',64,'全唐诗/poet.song.54000.json','["形迹分飛有道同，五年聲問不須通。", "侍親官上應尤樂，得子年來想更聰。", "相對忽因山入夢，自窺還愛璧涵空。", "公餘誰伴溪南話，七椀浮雲兩腋風。"]'),
('849afbdc-7819-4c5e-a8da-67200b67619c','榴花洞','黄裳','宋','宋诗','song-poetry','','[]','蓮社是非外，洞天空色中。',48,'全唐诗/poet.song.54000.json','["蓮社是非外，洞天空色中。", "一枝樵客夢，兩腋石門風。", "鹿徑蹤何在，榴花信可通。", "此緣當邂逅，來接紫玄翁。"]'),
('153378ea-b895-473e-93f1-264c6c543e58','訪曾君施不值','黄裳','宋','宋诗','song-poetry','','[]','有懷高論已經年，不落中間與兩邊。',64,'全唐诗/poet.song.54000.json','["有懷高論已經年，不落中間與兩邊。", "世路幾人機寂寂，春風何處騎翩翩。", "四聲險韵應尋句，一炷清香想看禪。", "我更欲勞三吐哺，周公今付伯禽賢。"]'),
('9d8421f9-406c-4e80-b953-d02564695382','送李奉議','黄裳','宋','宋诗','song-poetry','','[]','更去鄉關作子男，得賢當美大夫監。',64,'全唐诗/poet.song.54000.json','["更去鄉關作子男，得賢當美大夫監。", "暑中雨過乘清洛，公外雲開看綠巖。", "遂失故人須舉酒，纔聞佳境便收帆。", "春暉已報君無愧，一表遺文敕兩緘。"]'),
('915768b9-4e81-4420-8d07-325822d89017','貽沖和子','黄裳','宋','宋诗','song-poetry','','[]','想見高風夢已飛，無心中有道心微。',64,'全唐诗/poet.song.54000.json','["想見高風夢已飛，無心中有道心微。", "此生獨斷來修養，何處相逢得指歸。", "融結幾人知火候，斡旋惟子識天機。", "松庵欲對禪床坐，莫問朝曦與夕暉。"]'),
('b3ac4510-9238-4255-9ffd-276e6955ffd6','陰陽','黄裳','宋','宋诗','song-poetry','','[]','陰陽無意本由人，禍福皆緣幻與真。',64,'全唐诗/poet.song.54000.json','["陰陽無意本由人，禍福皆緣幻與真。", "悟即離倫兼度世，迷須傾國更亡身。", "智愚莫曉氣隨數，老少合驚秋復春。", "有物混成如了得，却教真幻兩通神。"]'),
('3a190c57-ee55-4482-9d77-707996226741','遊洞霄簡陳伯修','黄裳','宋','宋诗','song-poetry','','[]','異香來自洞中春，王屋華陽密作鄰。',64,'全唐诗/poet.song.54000.json','["異香來自洞中春，王屋華陽密作鄰。", "宛轉白雲離紫府，參差青鎖斷紅塵。", "若無天柱難留許，惟有桃花解笑秦。", "我得此官應是分，欲從何處更尋真。"]'),
('395934fc-0e99-4b33-94b1-f1eed29f9e39','考試軍器所和敦禮兵部見示之什','黄裳','宋','宋诗','song-poetry','','[]','夢中宣使至，天上敕書開。',288,'全唐诗/poet.song.54000.json','["夢中宣使至，天上敕書開。", "去騎遵西野，回眸失北槐。", "利名何日了，儒法幾回來。", "丹管誅邪說，重帷截亂埃。", "簿書稀見影，典策冗成堆。", "仰望門雖峻，旁求網已恢。", "幽題胸膽破，雄敵劍鋒摧。", "狂欲勞彈鋏，輕投慎報瑰。", "侯中誰破的，營下各銜枚。", "含蓄飛香翰，搜尋遶翠苔。", "自非衡鑑手，誰是棟梁材。", "累外灰心火，閒中臥鼻雷。", "相投歸邂逅，共樂入調詼。", "寥廓喪爾界，勤勞忘彼嵬。", "家音催轉曆，廳議款銜盃。", "殊品酬三刖，遊辭薦一咍。", "無形嗤字號，有秩喜罇罍。", "壁角蚊初動，天南暑已回。", "不慚居屋漏，却厭面牆隈。", "凉滿亭亭扇，香餘餠餠灰。", "幾時當命駕，此興可登臺。", "清浪風歸袖，紅鱗酒入腮。", "莫隨人俯仰，且共月徘徊。", "既事當如約，分襟便可催。"]'),
('643cfd26-a272-4846-9884-4e80242dc94e','偕王道觀雪中聯句  其一','黄裳','宋','宋诗','song-poetry','','[]','瑞意纔含蓄，輕花即翦裁。',24,'全唐诗/poet.song.54000.json','["瑞意纔含蓄，輕花即翦裁。", "清寒穿箔去，豐兆破烟來。"]'),
('c2c041ea-0537-4764-a9bc-ef91b16db4b3','偕王道觀雪中聯句  其二','黄裳','宋','宋诗','song-poetry','','[]','密霰俄傳信，癡雲預作媒。',24,'全唐诗/poet.song.54000.json','["密霰俄傳信，癡雲預作媒。", "瑶池方瀲灧，玉鳳更毰毸。"]'),
('1d71c3bb-3dea-4040-b4a0-72ff796ed3b1','偕王道觀雪中聯句  其三','黄裳','宋','宋诗','song-poetry','','[]','思見憐初洒，憂消喜漸堆。',24,'全唐诗/poet.song.54000.json','["思見憐初洒，憂消喜漸堆。", "惜明聊自擬，驚密偶同欵。"]'),
('ba4a9518-a448-4f3e-a64b-cba5299a7a5f','偕王道觀雪中聯句  其四','黄裳','宋','宋诗','song-poetry','','[]','片片榆飄莢，纍纍蚌剖胎。',24,'全唐诗/poet.song.54000.json','["片片榆飄莢，纍纍蚌剖胎。", "遽將天曉報，頻把歲華催。"]'),
('ba959b2d-2cda-40c3-b26c-d06fce630f91','偕王道觀雪中聯句  其五','黄裳','宋','宋诗','song-poetry','','[]','有景榮千巘，無私瑞九垓。',24,'全唐诗/poet.song.54000.json','["有景榮千巘，無私瑞九垓。", "水精排瓦礫，天庫委瓊瑰。"]'),
('a9a993f3-7ae4-4c54-93ee-8cd65059db23','偕王道觀雪中聯句  其六','黄裳','宋','宋诗','song-poetry','','[]','就下深趨坎，憑高杪寄桅。',24,'全唐诗/poet.song.54000.json','["就下深趨坎，憑高杪寄桅。", "四垂纔密密，一望已皚皚。"]'),
('d70e3eb4-0494-42d6-a88b-6f31d4171ba4','偕王道觀雪中聯句  其七','黄裳','宋','宋诗','song-poetry','','[]','瀑布鬭直瀉，仙葩誰碎挼。',24,'全唐诗/poet.song.54000.json','["瀑布鬭直瀉，仙葩誰碎挼。", "風前鵝毳落，秋後海潮回。"]'),
('9cfc1c32-0d0f-4d20-afe4-b34a3626210e','偕王道觀雪中聯句  其八','黄裳','宋','宋诗','song-poetry','','[]','礱轉揚輕礦，篩旋迸細粞。',24,'全唐诗/poet.song.54000.json','["礱轉揚輕礦，篩旋迸細粞。", "紋波翻太液，縞練遶蓬萊。"]'),
('3a419c8b-7c85-431d-8edd-fdd4343de715','偕王道觀雪中聯句  其九','黄裳','宋','宋诗','song-poetry','','[]','泛泛冰壺動，漫漫寶鑑開。',24,'全唐诗/poet.song.54000.json','["泛泛冰壺動，漫漫寶鑑開。", "柳條新弄絮，律管乍飛灰。"]'),
('c6420ed8-af48-488f-97ae-8d4e4ef0d665','偕王道觀雪中聯句  其一○','黄裳','宋','宋诗','song-poetry','','[]','照耀行人氅，光華釣叟臺。',24,'全唐诗/poet.song.54000.json','["照耀行人氅，光華釣叟臺。", "書帷爭白日，秋色改黄槐。"]'),
('18d84e69-dea5-43ad-894a-d4a715e2a7e7','偕王道觀雪中聯句  其一一','黄裳','宋','宋诗','song-poetry','','[]','比潔須延月，聞香不掩梅。',24,'全唐诗/poet.song.54000.json','["比潔須延月，聞香不掩梅。", "載塗人艮趾，入領我咸脢。"]'),
('4fe8acd1-db40-4837-a47c-f41dd8621be5','偕王道觀雪中聯句  其一二','黄裳','宋','宋诗','song-poetry','','[]','封鎖烟嘗衛，飛揚露可陪。',24,'全唐诗/poet.song.54000.json','["封鎖烟嘗衛，飛揚露可陪。", "厚將平地塹，高欲峻堂陔。"]'),
('af5f2b4b-b8d6-4cdb-85a6-6e5b58fbce49','偕王道觀雪中聯句  其一三','黄裳','宋','宋诗','song-poetry','','[]','特應三冬令，寧傷萬物胚。',24,'全唐诗/poet.song.54000.json','["特應三冬令，寧傷萬物胚。", "秦蛇伸瓦隴，卞璞暴山峐。"]'),
('a05214c9-8e7e-4be8-ad1b-a675eed98c98','偕王道觀雪中聯句  其一四','黄裳','宋','宋诗','song-poetry','','[]','始恐佛氏講，天花何徘徊。',24,'全唐诗/poet.song.54000.json','["始恐佛氏講，天花何徘徊。", "終疑宓妃至，仙肌何奇侅。"]'),
('1751ca88-d803-41fd-8609-4df061954459','偕王道觀雪中聯句  其一五','黄裳','宋','宋诗','song-poetry','','[]','砌鋪砧上練，池泛甕中醅。',48,'全唐诗/poet.song.54000.json','["砌鋪砧上練，池泛甕中醅。", "豐滿莫見睍，優閒休及隤。", "遺圓還得璧，臨翠忽亡苔。", "弄巧俄顛漩，爭狂忽遡洄。"]'),
('d623a8ff-4506-4f8f-b8a8-4c6da2077a86','偕王道觀雪中聯句  其一六','黄裳','宋','宋诗','song-poetry','','[]','空中逢汗漫，望外見崔嵬。',48,'全唐诗/poet.song.54000.json','["空中逢汗漫，望外見崔嵬。", "艷態非因飾，虛根豈可栽。", "先崇逢壠斷，後化得牆隈。", "歡賀紛耕叟，欣拏亂戲孩。"]'),
('aa3374e6-c087-475e-9e2a-2ffe01d527ad','偕王道觀雪中聯句  其一七','黄裳','宋','宋诗','song-poetry','','[]','應迷天上鶴，猶壓地中雷。',48,'全唐诗/poet.song.54000.json','["應迷天上鶴，猶壓地中雷。", "商色皎且盛，郢歌清更哀。", "簷澌懸劍戟，庭塊列杓魁。", "對老凌華髮，迎春濯舊埃。"]'),
('b320a694-ba1d-4f0b-9607-5e1da24d63a7','偕王道觀雪中聯句  其一八','黄裳','宋','宋诗','song-poetry','','[]','盛疑星漢瀉，高恐玉山頹。',48,'全唐诗/poet.song.54000.json','["盛疑星漢瀉，高恐玉山頹。", "江水聊添漲，春根却忌培。", "漁汀埋舸纜，獵野陷盧鋂。", "覆蓋污爲潔，消磨厲作災。"]'),
('b013f163-e2ca-4206-b5bb-18ceb7d81d3d','偕王道觀雪中聯句  其一九','黄裳','宋','宋诗','song-poetry','','[]','棲寒禽惴慄，步滑馬虺尵。',48,'全唐诗/poet.song.54000.json','["棲寒禽惴慄，步滑馬虺尵。", "富國寒銀溢，籠鵬素網恢。", "漫郊頻去牧，□穴愴歸𧳟。", "戶濕知風送，軒鳴想竹摧。"]'),
('52536948-deee-4286-98a3-05965fa4c890','偕王道觀雪中聯句  其二○','黄裳','宋','宋诗','song-poetry','','[]','密勻甌漬液，丹映檻凝衃。',24,'全唐诗/poet.song.54000.json','["密勻甌漬液，丹映檻凝衃。", "照歲何妨積，侵階慎勿推。"]'),
('bc3180b6-4c8f-429d-b8cd-d3af655cd8bc','偕王道觀雪中聯句  其二一','黄裳','宋','宋诗','song-poetry','','[]','書窗輝竹簡，詩筆凍松煤。',24,'全唐诗/poet.song.54000.json','["書窗輝竹簡，詩筆凍松煤。", "煎煮供茶鼎，收藏厠酒罍。"]'),
('cd9f86c8-f480-49dc-907c-5b255dcffd60','偕王道觀雪中聯句  其二二','黄裳','宋','宋诗','song-poetry','','[]','擬氈安可卷，欲器不禁鎚。',24,'全唐诗/poet.song.54000.json','["擬氈安可卷，欲器不禁鎚。", "俯拾甘頳手，昂窺任撲腮。"]'),
('3d17a865-f765-4c2c-a6f8-6bcbb2d6f837','偕王道觀雪中聯句  其二三','黄裳','宋','宋诗','song-poetry','','[]','誤雞忙下杙，趣雉不須䍙。',24,'全唐诗/poet.song.54000.json','["誤雞忙下杙，趣雉不須䍙。", "翫久清成興，吞多冷失咍。"]'),
('74677548-1d5d-44a3-ae4c-46428f59ce52','偕王道觀雪中聯句  其二四','黄裳','宋','宋诗','song-poetry','','[]','脂膚堪奬與，墨面可譏詼。',24,'全唐诗/poet.song.54000.json','["脂膚堪奬與，墨面可譏詼。", "鹽散徒云爾，心虛可比哉。"]'),
('66a65bfc-7e63-47cd-a5fb-0c639e25df67','偕王道觀雪中聯句  其二五','黄裳','宋','宋诗','song-poetry','','[]','助清還啜茗，勝冷屢銜盃。',60,'全唐诗/poet.song.54000.json','["助清還啜茗，勝冷屢銜盃。", "辨味憑茶陸，登高愜賦枚。", "袁門清夢未，梁苑勝遊纔。", "船去須尋戴，詩成蓋獻裴。", "光餘應可借，□大固難猜。"]'),
('5edb4374-1992-49ab-8bbc-6b3ef8578c7f','徐州遊崇寧','黄裳','宋','宋诗','song-poetry','','[]','得官來自洞中天，閒向桑間戲問禪。',64,'全唐诗/poet.song.54000.json','["得官來自洞中天，閒向桑間戲問禪。", "已爲命機根玉籙，曾將心印祖金仙。", "懶看小吏呈朝報，喜聽高人說世緣。", "一物也無參底事，紛紛誰可付真筌。"]'),
('58827cba-c14b-4de7-b9aa-353fcba4ffc8','道中有作呈崔風子','黄裳','宋','宋诗','song-poetry','','[]','有分尋真莫道難，蓬萊詩句請君看。',64,'全唐诗/poet.song.54000.json','["有分尋真莫道難，蓬萊詩句請君看。", "雙輪轉出三清路，二氣燒成九轉丹。", "烟靄樓臺金虎遶，雪霜宮殿玉龍盤。", "解顔爲向潜山近，天柱峰頭月夜寒。"]'),
('9d77f232-6a73-45fb-9635-fe3642516dae','舟次嚴子陵瀨  其一','黄裳','宋','宋诗','song-poetry','','[]','纁車曾此賁山林，深谷爲陵古到今。',32,'全唐诗/poet.song.54000.json','["纁車曾此賁山林，深谷爲陵古到今。", "節行清如臺下水，何人能洗利名心。"]'),
('3919033a-a92a-47b9-a929-51067a1b0e5f','舟次嚴子陵瀨  其二','黄裳','宋','宋诗','song-poetry','','[]','故人康世自英雄，富貴明知轉首空。',32,'全唐诗/poet.song.54000.json','["故人康世自英雄，富貴明知轉首空。", "不似羊裘歸去好，素癡猶解笑三公。"]'),
('f49fb851-d959-43bd-bac2-48860e6f6622','舟次嚴子陵瀨  其三','黄裳','宋','宋诗','song-poetry','','[]','交遊分在紅塵外，主客緣從紫極中。',32,'全唐诗/poet.song.54000.json','["交遊分在紅塵外，主客緣從紫極中。", "各有志存休見迫，經邦須訪渭川翁。"]'),
('8251d40e-2664-4a76-9393-9033391c4112','舟次嚴子陵瀨  其四','黄裳','宋','宋诗','song-poetry','','[]','風節無人能用舍，塵凡何處問行藏。',32,'全唐诗/poet.song.54000.json','["風節無人能用舍，塵凡何處問行藏。", "虹蜺已卷胸中氣，只作天文一點光。"]'),
('6f4855e3-88cd-4f47-8b0a-ff8c465b3c51','舟次嚴子陵瀨  其五','黄裳','宋','宋诗','song-poetry','','[]','已外世情來獨立，何勞物色去相尋。',32,'全唐诗/poet.song.54000.json','["已外世情來獨立，何勞物色去相尋。", "太官食好還多累，一線金鱗豈有心。"]'),
('d0fcd86a-a1cd-4155-96cb-83a3cff31bf7','和張樞密西齋','黄裳','宋','宋诗','song-poetry','','[]','雙梧尤愜雨中聽，莫恨庭前古月明。',32,'全唐诗/poet.song.54000.json','["雙梧尤愜雨中聽，莫恨庭前古月明。", "簌簌西風吹又急，却疑欹枕得秋聲。"]'),
('21097e17-3e80-418d-a0a6-a15fce8ea2b0','和人聞角  其一','黄裳','宋','宋诗','song-poetry','','[]','胡笳羌笛此聲同，一曲梅花萬感濃。',32,'全唐诗/poet.song.54000.json','["胡笳羌笛此聲同，一曲梅花萬感濃。", "吹轉滿城蝴蝶夢，利名心動五更鐘。"]'),
('b5c5e6ed-001a-431a-96dc-90b291607c40','和人聞角  其二','黄裳','宋','宋诗','song-poetry','','[]','一聲寒角四更終，吹下雲間細細風。',32,'全唐诗/poet.song.54000.json','["一聲寒角四更終，吹下雲間細細風。", "孤館幾多人展轉，半窗明月與誰同。"]'),
('1f92a25d-7c95-406e-ad10-5b2419dfc0a9','秋日有感  其一','黄裳','宋','宋诗','song-poetry','','[]','秋來猶寄一涯天，葉葉秋聲似去年。',32,'全唐诗/poet.song.54000.json','["秋來猶寄一涯天，葉葉秋聲似去年。", "可惜良辰長在客，不堪孤館更聞蟬。"]'),
('92895377-63b4-44ba-9d9f-8576514ab05f','秋日有感  其二','黄裳','宋','宋诗','song-poetry','','[]','幾時能致買山錢，便好山中醉暮天。',32,'全唐诗/poet.song.54000.json','["幾時能致買山錢，便好山中醉暮天。", "有物秋來長引夢，鱸魚新到曲江邊。"]'),
('69b6ea4b-6359-4659-8912-267e7d89c661','延平閣閒望  其一','黄裳','宋','宋诗','song-poetry','','[]','歌管東西誰共樂，水雲高下自相通。',32,'全唐诗/poet.song.54000.json','["歌管東西誰共樂，水雲高下自相通。", "吟看忽到難吟處，望斷天南色入空。"]'),
('f943c18c-466e-4d0c-b19f-3305a030b4ea','延平閣閒望  其二','黄裳','宋','宋诗','song-poetry','','[]','南北山形兩鬭龍，畫橋橫鎖水西東。',32,'全唐诗/poet.song.54000.json','["南北山形兩鬭龍，畫橋橫鎖水西東。", "百花巖上人長在，誰識神仙指顧中。"]'),
('24b9bb36-cf2e-413a-9871-90d3fdfa1cc0','延平閣閒望  其三','黄裳','宋','宋诗','song-poetry','','[]','兩邊樓館倚晴空，閣出中間與畫同。',32,'全唐诗/poet.song.54000.json','["兩邊樓館倚晴空，閣出中間與畫同。", "劍未歸時潭得月，舟從來處客乘風。"]'),
('a772c934-4a65-4a73-bd18-75517a980f89','延平閣閒望  其四','黄裳','宋','宋诗','song-poetry','','[]','翠微虛白兩圓融，爽氣令人欲御風。',32,'全唐诗/poet.song.54000.json','["翠微虛白兩圓融，爽氣令人欲御風。", "曉傍雕欄初見日，水天都入混茫中。"]'),
('63574b56-1db4-41bd-910a-3057c9bf676a','延平閣閒望  其五','黄裳','宋','宋诗','song-poetry','','[]','客維舟處莫匆匆，拂袖人來蓼已紅。',32,'全唐诗/poet.song.54000.json','["客維舟處莫匆匆，拂袖人來蓼已紅。", "江上忽含烟雨意，數峰還在有無中。"]'),
('ae95fdad-b1f5-4537-8b1f-2523f3debe65','延平閣閒望  其六','黄裳','宋','宋诗','song-poetry','','[]','倚闌誰問紫玄翁，湘浦幽懷莫我同。',32,'全唐诗/poet.song.54000.json','["倚闌誰問紫玄翁，湘浦幽懷莫我同。", "邂逅秦漁人不識，扁舟常在水西東。"]'),
('544a9ddd-6828-47b5-9fa3-bb7905c13dea','延平閣閒望  其七','黄裳','宋','宋诗','song-poetry','','[]','不顧溪山已幾年，再營華構慰人瞻。',32,'全唐诗/poet.song.54000.json','["不顧溪山已幾年，再營華構慰人瞻。", "欲尋好景歸詩思，更候朝曦與夜蟾。"]'),
('66dd961a-ff83-477b-81ee-2b1d6dc92bf9','延平閣閒望  其八','黄裳','宋','宋诗','song-poetry','','[]','英靈祠下晉朝賢，終伴精芒合水邊。',32,'全唐诗/poet.song.54000.json','["英靈祠下晉朝賢，終伴精芒合水邊。", "看取黄龍沙斗起，滿城歌吹入豐年。"]'),
('f802037a-6e32-49fa-860a-3a6ae58db3d0','延平閣閒望  其九','黄裳','宋','宋诗','song-poetry','','[]','演峰遙見客懷開，天末舟從海上回。',32,'全唐诗/poet.song.54000.json','["演峰遙見客懷開，天末舟從海上回。", "三岸讙呼無別事，一潭風雨劍歸來。"]'),
('66681e1c-9025-4282-996b-4a2215e78369','延平閣閒望  其一○','黄裳','宋','宋诗','song-poetry','','[]','雲中山出三秋靜，水上風來六月寒。',32,'全唐诗/poet.song.54000.json','["雲中山出三秋靜，水上風來六月寒。", "寶氣有時藏不得，夜深尤好倚闌干。"]'),
('d93b3723-7556-4dd7-b4d5-29ae46b3abf2','梅花  其一','黄裳','宋','宋诗','song-poetry','','[]','芳意已將春漏洩，真香何慮雪埋藏。',32,'全唐诗/poet.song.54000.json','["芳意已將春漏洩，真香何慮雪埋藏。", "百花頭上爭先好，未用忙誇落後粧。"]'),
('24cc3c1f-dbe0-4702-835c-092625a851df','梅花  其二','黄裳','宋','宋诗','song-poetry','','[]','逢春莫問枝南北，對雪休分臘後先。',32,'全唐诗/poet.song.54000.json','["逢春莫問枝南北，對雪休分臘後先。", "豈獨惜花長欲醉，相宜尤是雪寒天。"]'),
('baeb75be-7414-4f39-a0ca-3ab7c14054ce','梅花  其三','黄裳','宋','宋诗','song-poetry','','[]','花傍水邊窺縹緲，月來花上失蟬娟。',32,'全唐诗/poet.song.54000.json','["花傍水邊窺縹緲，月來花上失蟬娟。", "長教風脚微如線，時把真香爲我傳。"]'),
('ea4f681f-98e4-400b-930c-cf721bf22118','梅花  其四','黄裳','宋','宋诗','song-poetry','','[]','密移神化本無情，天篆橫空木末榮。',32,'全唐诗/poet.song.54000.json','["密移神化本無情，天篆橫空木末榮。", "凝住雪花都不下，槎牙枝上放輕盈。"]'),
('dd553b2b-264f-41b1-8c00-1c73430e98bb','梅花  其五','黄裳','宋','宋诗','song-poetry','','[]','蜂蝶謾尋花後葉，功名猶寄鼎中羹。',32,'全唐诗/poet.song.54000.json','["蜂蝶謾尋花後葉，功名猶寄鼎中羹。", "開樽好席瑶林下，香墮金巵得素瓊。"]'),
('9ab6c374-fea3-432a-82d8-e48446b0522d','梅花  其六','黄裳','宋','宋诗','song-poetry','','[]','一種清香誰可比，九春和氣爾爭先。',32,'全唐诗/poet.song.54000.json','["一種清香誰可比，九春和氣爾爭先。", "曉來爛熳驚人眼，只謂寒林是雪天。"]'),
('867d3aad-4c17-4e87-9b72-8d85656a8340','梅花  其七','黄裳','宋','宋诗','song-poetry','','[]','醱醅新酒人間熟，蓓蕾寒梅嶺上開。',32,'全唐诗/poet.song.54000.json','["醱醅新酒人間熟，蓓蕾寒梅嶺上開。", "親自折歸罇畔去，幾回尋向雪中來。"]'),
('11f267ea-7346-4134-bdbe-9b74493a1c4f','梅花  其八','黄裳','宋','宋诗','song-poetry','','[]','自從花發吟何苦，未見春來惜更深。',32,'全唐诗/poet.song.54000.json','["自從花發吟何苦，未見春來惜更深。", "天與異香分辨雪，不教埋沒亂山陰。"]'),
('f8ed9c5b-d629-41f2-a314-7ec2e89715de','次禹弼同遊滕王園池之韵  其一','黄裳','宋','宋诗','song-poetry','','[]','當時歌舞競韶華，銀燭燒殘始上車。',32,'全唐诗/poet.song.54000.json','["當時歌舞競韶華，銀燭燒殘始上車。", "堂上舊歡何處覓，春風無計問桃花。"]'),
('376070e3-0e93-4485-ae64-756888794d06','次禹弼同遊滕王園池之韵  其二','黄裳','宋','宋诗','song-poetry','','[]','徘徊池上昔人非，不爲勞生竟自迷。',32,'全唐诗/poet.song.54000.json','["徘徊池上昔人非，不爲勞生竟自迷。", "花下百年緣分滿，月明誰聽杜鵑啼。"]'),
('74eadfb8-4806-4324-9448-0217dc27edc9','次禹弼同遊滕王園池之韵  其三','黄裳','宋','宋诗','song-poetry','','[]','標的强宗兩鬢華，不令身後到牛車。',32,'全唐诗/poet.song.54000.json','["標的强宗兩鬢華，不令身後到牛車。", "武陵溪上人何在，流水聲中看落花。"]'),
('f2ff16c4-6b87-4a73-9c94-242de3298e2c','次禹弼同遊滕王園池之韵  其四','黄裳','宋','宋诗','song-poetry','','[]','洪都山水北宮西，不似元嬰未解迷。',32,'全唐诗/poet.song.54000.json','["洪都山水北宮西，不似元嬰未解迷。", "客去尋春人已往，驚猿空有曉來啼。"]'),
('c8ea44c3-66d8-47b4-a091-45f86ce69353','遊山','黄裳','宋','宋诗','song-poetry','','[]','靜意逢山樂自知，更遺名跡恐人疑。',32,'全唐诗/poet.song.54000.json','["靜意逢山樂自知，更遺名跡恐人疑。", "寒林野水相窺處，步未移時已得詩。"]'),
('81df7b64-f5b6-49cb-9754-9219a547ca55','牡丹  其一','黄裳','宋','宋诗','song-poetry','','[]','衮衮羣芳已失真，超然奇秀始離倫。',32,'全唐诗/poet.song.54000.json','["衮衮羣芳已失真，超然奇秀始離倫。", "夜遊說與雕欄客，費盡天機老却春。"]'),
